} from 'recharts';

const Dashboard: React.FC<{ onNavigateToClient: (id: string) => void }> = ({ onNavigateToClient }) => {
  const clients = db.getClients();
  const appointments = db.getAppointments();
  const invoices = db.getInvoices();

  const totalRevenue = invoices.reduce((acc, inv) => acc + inv.amount, 0);
  const pendingAppointments = appointments.filter(a => a.status === 'pending').length;

  const data = [
    { name: 'Jan', total: 400 },
    { name: 'Fév', total: 300 },
    { name: 'Mar', total: 500 },
    { name: 'Avr', total: totalRevenue },
  ];

  return (
    <div className="space-y-8 animate-in fade-in duration-500">
      <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-6">
        <StatCard icon={<Users className="text-blue-600" />} label="Clients Totaux" value={clients.length} color="bg-blue-50" />
        <StatCard icon={<CalendarIcon className="text-purple-600" />} label="RDV en attente" value={pendingAppointments} color="bg-purple-50" />
        <StatCard icon={<Euro className="text-emerald-600" />} label="C.A. Global" value={`${totalRevenue.toFixed(2)}€`} color="bg-emerald-50" />
        <StatCard icon={<TrendingUp className="text-orange-600" />} label="Performance" value="+12%" color="bg-orange-50" />
      </div>

      <div className="grid grid-cols-1 lg:grid-cols-3 gap-8">
        <div className="lg:col-span-2 bg-white p-6 rounded-2xl shadow-sm border border-slate-100">
          <h3 className="text-lg font-bold mb-6 text-slate-800">Évolution du Chiffre d'Affaires</h3>
          <div className="h-64">
            <ResponsiveContainer width="100%" height="100%">
              <BarChart data={data}>
                <CartesianGrid strokeDasharray="3 3" vertical={false} stroke="#f1f5f9" />
                <XAxis dataKey="name" axisLine={false} tickLine={false} tick={{fill: '#64748b', fontSize: 12}} dy={10} />
                <YAxis axisLine={false} tickLine={false} tick={{fill: '#64748b', fontSize: 12}} />
                <Tooltip 
                  cursor={{fill: '#f8fafc'}}
                  contentStyle={{ borderRadius: '12px', border: 'none', boxShadow: '0 10px 15px -3px rgb(0 0 0 / 0.1)' }}
                />
                <Bar dataKey="total" fill="#6366f1" radius={[4, 4, 0, 0]} barSize={40} />
              </BarChart>
            </ResponsiveContainer>
          </div>
        </div>

        <div className="bg-white p-6 rounded-2xl shadow-sm border border-slate-100 flex flex-col">
          <h3 className="text-lg font-bold mb-4 text-slate-800">Derniers Clients</h3>
          <div className="flex-1 space-y-4 overflow-y-auto">
            {clients.slice(-5).reverse().map(client => (
              <div 
                key={client.id}
                onClick={() => onNavigateToClient(client.id)}
                className="flex items-center justify-between p-3 hover:bg-slate-50 rounded-xl cursor-pointer transition-colors group"
              >
