                  <div className="w-10 h-10 rounded-full bg-indigo-100 flex items-center justify-center text-indigo-600 font-bold uppercase overflow-hidden">
                    {client.photoProfile ? (
                      <img src={client.photoProfile} className="w-full h-full object-cover" alt="" />
                    ) : (
                      client.name.charAt(0)
