const StatCard = ({ icon, label, value, color }: { icon: React.ReactNode, label: string, value: string | number, color: string }) => (
  <div className="bg-white p-6 rounded-2xl shadow-sm border border-slate-100 flex items-center gap-4">
    <div className={`p-4 rounded-xl ${color}`}>
      {icon}
    </div>
    <div>
      <p className="text-sm font-medium text-slate-500">{label}</p>
      <p className="text-2xl font-bold text-slate-900">{value}</p>
    </div>
  </div>
);

export default Dashboard;

import React, { useState, useEffect } from 'react';
import { db } from '../services/database';
import { Client } from '../types';
import { Search, Plus, User, Phone, Mail, MapPin, Calendar, Sparkles, Trash2, Edit3, Camera } from 'lucide-react';
import { getPetInsight } from '../services/gemini';

const ClientList: React.FC<{ initialClientId?: string | null }> = ({ initialClientId }) => {
  const [clients, setClients] = useState<Client[]>([]);
  const [search, setSearch] = useState('');
  const [selectedClient, setSelectedClient] = useState<Client | null>(null);
  const [isEditing, setIsEditing] = useState(false);
  const [aiInsight, setAiInsight] = useState<string | null>(null);
  const [loadingAi, setLoadingAi] = useState(false);

  const config = db.getConfig();

  useEffect(() => {
    const loaded = db.getClients();
    setClients(loaded);
    if (initialClientId) {
      const found = loaded.find(c => c.id === initialClientId);
      if (found) setSelectedClient(found);
    }
  }, [initialClientId]);

  const filteredClients = clients.filter(c => 
    c.name.toLowerCase().includes(search.toLowerCase()) || 
    c.ownerName.toLowerCase().includes(search.toLowerCase())
  );

  const handleSave = (e: React.FormEvent<HTMLFormElement>) => {
    e.preventDefault();
    const formData = new FormData(e.currentTarget);
    const updated: Client = {
      id: selectedClient?.id || crypto.randomUUID(),
      name: formData.get('name') as string,
      species: formData.get('species') as string,
      breed: formData.get('breed') as string,
      coatType: formData.get('coatType') as string,
      birthDate: formData.get('birthDate') as string,
      ownerName: formData.get('ownerName') as string,
      phone: formData.get('phone') as string,
      email: formData.get('email') as string,
      address: formData.get('address') as string,
      notes: formData.get('notes') as string,
      particularities: Array.from(formData.getAll('particularities')) as string[],
      createdAt: selectedClient?.createdAt || new Date().toISOString(),
      photoProfile: selectedClient?.photoProfile || `https://picsum.photos/seed/${Math.random()}/300/300`
    };

    db.saveClient(updated);
    setClients(db.getClients());
    setSelectedClient(updated);
    setIsEditing(false);
  };

  const loadAiAdvice = async (client: Client) => {
    setLoadingAi(true);
    const insight = await getPetInsight(client);
    setAiInsight(insight);
    setLoadingAi(false);
  };

  return (
