        </div>

        <div className="flex-1 overflow-y-auto space-y-2 pr-2">
          {filteredClients.map(client => (
            <button
              key={client.id}
              onClick={() => { setSelectedClient(client); setIsEditing(false); setAiInsight(null); }}
