import { Client, Appointment, Invoice, Configuration } from '../types';
import { INITIAL_CONFIG } from '../constants';

const KEYS = {
  CLIENTS: 'groom_clients',
  APPOINTMENTS: 'groom_appointments',
  INVOICES: 'groom_invoices',
  CONFIG: 'groom_config'
};

export const db = {
  // Config
  getConfig: (): Configuration => {
    const data = localStorage.getItem(KEYS.CONFIG);
    return data ? JSON.parse(data) : INITIAL_CONFIG;
  },
  saveConfig: (config: Configuration) => localStorage.setItem(KEYS.CONFIG, JSON.stringify(config)),

  updateConfigItems: (category: keyof Configuration, items: string[]) => {
    const config = db.getConfig();
    // Special handling for breeds if needed, but for now we treat arrays
    if (Array.isArray(config[category])) {
      (config[category] as string[]) = items;
      db.saveConfig(config);
    }
  },

  // Clients
  getClients: (): Client[] => {
    const data = localStorage.getItem(KEYS.CLIENTS);
    return data ? JSON.parse(data) : [];
  },
  saveClient: (client: Client) => {
    const clients = db.getClients();
    const index = clients.findIndex(c => c.id === client.id);
    if (index >= 0) clients[index] = client;
    else clients.push(client);
    localStorage.setItem(KEYS.CLIENTS, JSON.stringify(clients));
  },
  deleteClient: (id: string) => {
    const clients = db.getClients().filter(c => c.id !== id);
    localStorage.setItem(KEYS.CLIENTS, JSON.stringify(clients));
  },

  // Appointments
  getAppointments: (): Appointment[] => {
    const data = localStorage.getItem(KEYS.APPOINTMENTS);
    return data ? JSON.parse(data) : [];
  },
  saveAppointment: (appt: Appointment) => {
    const appts = db.getAppointments();
    const index = appts.findIndex(a => a.id === appt.id);
    if (index >= 0) appts[index] = appt;
    else appts.push(appt);
    localStorage.setItem(KEYS.APPOINTMENTS, JSON.stringify(appts));
  },
  deleteAppointment: (id: string) => {
    const appts = db.getAppointments().filter(a => a.id !== id);
    localStorage.setItem(KEYS.APPOINTMENTS, JSON.stringify(appts));
  },

  // Invoices
  getInvoices: (): Invoice[] => {
    const data = localStorage.getItem(KEYS.INVOICES);
    return data ? JSON.parse(data) : [];
  },
  saveInvoice: (invoice: Invoice) => {
    const invoices = db.getInvoices();
    invoices.push(invoice);
    localStorage.setItem(KEYS.INVOICES, JSON.stringify(invoices));
  }
};

import React, { useState, useEffect } from 'react';
import { db } from '../services/database';
import { Appointment, Client } from '../types';
import { Calendar as CalendarIcon, Clock, ChevronLeft, ChevronRight, FileText, CheckCircle2, Trash2, Plus } from 'lucide-react';

const Planning: React.FC = () => {
  const [view, setView] = useState<'day' | 'month'>('day');
  const [currentDate, setCurrentDate] = useState(new Date());
  const [appointments, setAppointments] = useState<Appointment[]>([]);
  const [clients, setClients] = useState<Client[]>([]);
  const [isModalOpen, setIsModalOpen] = useState(false);
  const [selectedAppt, setSelectedAppt] = useState<Appointment | null>(null);

  const config = db.getConfig();

  const refreshData = () => {
    setAppointments(db.getAppointments());
    setClients(db.getClients());
  };

  useEffect(() => {
    refreshData();
  }, []);

  const formatDate = (date: Date) => date.toISOString().split('T')[0];
  const dateStr = formatDate(currentDate);

  const dailyAppts = appointments
    .filter(a => a.date === dateStr)
    .sort((a, b) => a.time.localeCompare(b.time));

  const handleSaveAppt = (e: React.FormEvent<HTMLFormElement>) => {
    e.preventDefault();
    const formData = new FormData(e.currentTarget);
    const clientSelect = formData.get('client') as string;
    const [petName, ownerName] = clientSelect.split(' - ');
    const client = clients.find(c => c.name === petName && c.ownerName === ownerName);

    const newAppt: Appointment = {
      id: selectedAppt?.id || crypto.randomUUID(),
      date: formData.get('date') as string,
      time: formData.get('time') as string,
      clientId: client?.id || '',
      clientName: ownerName,
      petName: petName,
      service: formData.get('service') as string,
      notes: formData.get('notes') as string,
      duration: parseInt(formData.get('duration') as string),
      status: selectedAppt?.status || 'pending'
    };

    db.saveAppointment(newAppt);
    refreshData();
    setIsModalOpen(false);
    setSelectedAppt(null);
  };

  const handleInvoice = (appt: Appointment) => {
    const amountStr = prompt(`Montant pour le soin "${appt.service}" de ${appt.petName} (€) ?`, "50");
    if (amountStr === null) return; // User cancelled

    const amount = parseFloat(amountStr);
    if (isNaN(amount)) {
      alert("Veuillez saisir un montant valide.");
      return;
    }

    const invoiceNumber = `FAC-${Date.now().toString().slice(-6)}`;

    // Create Invoice
    db.saveInvoice({
      id: crypto.randomUUID(),
      number: invoiceNumber,
      date: formatDate(new Date()),
      clientId: appt.clientId,
      petName: appt.petName,
      ownerName: appt.clientName,
      amount: amount,
      paymentMethod: 'Espèces', // Default
      appointmentId: appt.id
    });

    // Update Appointment Status
    const updated = { ...appt, status: 'invoiced' as const };
    db.saveAppointment(updated);

    // Refresh local state to update UI
    refreshData();
    alert(`Facture ${invoiceNumber} de ${amount}€ enregistrée !`);
  };

  return (
    <div className="space-y-8 h-[calc(100vh-140px)] flex flex-col">
      <div className="flex flex-col sm:flex-row items-center justify-between gap-4 no-print">
        <div className="flex items-center gap-4">
          <div className="flex bg-white rounded-xl p-1 shadow-sm border border-slate-100">
            <button 
              onClick={() => setView('day')}
              className={`px-4 py-2 rounded-lg text-sm font-bold transition-all ${view === 'day' ? 'bg-indigo-600 text-white shadow-md' : 'text-slate-600 hover:bg-slate-50'}`}
            >
              Jour
            </button>
            <button 
              onClick={() => setView('month')}
              className={`px-4 py-2 rounded-lg text-sm font-bold transition-all ${view === 'month' ? 'bg-indigo-600 text-white shadow-md' : 'text-slate-600 hover:bg-slate-50'}`}
            >
              Mois
            </button>
          </div>
          <div className="flex items-center gap-2">
            <button onClick={() => setCurrentDate(new Date(currentDate.setDate(currentDate.getDate() - 1)))} className="p-2 hover:bg-slate-100 rounded-lg"><ChevronLeft size={20}/></button>
            <span className="text-lg font-bold text-slate-800 min-w-[150px] text-center">
              {currentDate.toLocaleDateString('fr-FR', { weekday: 'long', day: 'numeric', month: 'long' })}
            </span>
            <button onClick={() => setCurrentDate(new Date(currentDate.setDate(currentDate.getDate() + 1)))} className="p-2 hover:bg-slate-100 rounded-lg"><ChevronRight size={20}/></button>
          </div>
        </div>
        <button 
          onClick={() => { setSelectedAppt(null); setIsModalOpen(true); }}
          className="flex items-center gap-2 px-6 py-3 bg-indigo-600 text-white rounded-xl font-bold hover:bg-indigo-700 transition-all shadow-lg shadow-indigo-100"
        >
          <Plus size={20} />
          Prendre RDV
        </button>
      </div>

      <div className="flex-1 bg-white rounded-2xl shadow-sm border border-slate-100 overflow-y-auto">
        <div className="p-4 md:p-8">
          {dailyAppts.length > 0 ? (
            <div className="space-y-4">
              {dailyAppts.map(appt => (
                <div key={appt.id} className="group flex flex-col sm:flex-row items-start sm:items-center gap-4 sm:gap-6 p-4 md:p-6 rounded-2xl border border-slate-100 hover:border-indigo-100 hover:bg-slate-50/50 transition-all">
                  <div className="w-full sm:w-20 text-left sm:text-center border-b sm:border-b-0 sm:border-r pb-2 sm:pb-0 sm:pr-6 border-slate-100">
                    <p className="text-xl font-black text-slate-800 tracking-tight">{appt.time}</p>
                    <p className="text-[10px] font-bold text-slate-400 uppercase">{appt.duration}min</p>
                  </div>
                  <div className="flex-1">
                    <div className="flex flex-wrap items-center gap-3">
                      <h4 className="text-lg font-bold text-slate-800">{appt.petName}</h4>
                      <span className="px-2 py-0.5 bg-indigo-50 text-indigo-600 text-[10px] font-bold uppercase rounded-md">{appt.service}</span>
                      {appt.status === 'invoiced' && <span className="flex items-center gap-1 text-emerald-600 font-bold text-[10px] uppercase bg-emerald-50 px-2 py-0.5 rounded-md"><CheckCircle2 size={12}/> Payé</span>}
                    </div>
                    <p className="text-sm text-slate-500 font-medium">Propriétaire: {appt.clientName}</p>
                    {appt.notes && <p className="text-xs text-slate-400 mt-2 italic">"{appt.notes}"</p>}
                  </div>
                  <div className="flex items-center gap-2 sm:opacity-0 group-hover:opacity-100 transition-opacity no-print w-full sm:w-auto justify-end">
                    {appt.status !== 'invoiced' && (
                      <button 
                        onClick={() => handleInvoice(appt)}
                        className="flex items-center gap-2 px-4 py-2 bg-emerald-600 text-white rounded-xl text-sm font-bold hover:bg-emerald-700 shadow-md shadow-emerald-100"
                      >
                        <FileText size={16} /> Facturer
                      </button>
                    )}
                    <button 
                       onClick={() => {
                        if(confirm("Supprimer ce rendez-vous ?")) {
                          db.deleteAppointment(appt.id);
                          refreshData();
                        }
                      }}
                      className="p-2 text-slate-400 hover:text-red-500 transition-colors"
                    >
                      <Trash2 size={20} />
                    </button>
                  </div>
                </div>
              ))}
            </div>
          ) : (
            <div className="h-full flex flex-col items-center justify-center text-slate-400 space-y-4 py-20">
              <Clock size={64} className="opacity-10" />
              <p className="font-medium">Aucun rendez-vous pour cette journée.</p>
            </div>
          )}
        </div>
      </div>

      {/* Appt Modal */}
      {isModalOpen && (
        <div className="fixed inset-0 bg-slate-900/40 backdrop-blur-sm z-50 flex items-center justify-center p-4">
          <div className="bg-white rounded-3xl w-full max-w-xl shadow-2xl overflow-hidden animate-in zoom-in-95 duration-200">
            <div className="p-8 border-b border-slate-100 flex justify-between items-center">
              <h3 className="text-xl font-bold text-slate-800">Nouveau Rendez-vous</h3>
              <button onClick={() => setIsModalOpen(false)} className="text-slate-400 hover:text-slate-600 text-xl">✕</button>
            </div>
            <form onSubmit={handleSaveAppt} className="p-8 space-y-6">
              <div className="grid grid-cols-2 gap-4">
                <InputField label="Date" name="date" type="date" defaultValue={dateStr} required />
                <InputField label="Heure" name="time" type="time" defaultValue="09:00" required />
              </div>

              <SelectField 
                label="Client" 
                name="client" 
                options={clients.map(c => `${c.name} - ${c.ownerName}`)} 
                required 
              />

              <div className="grid grid-cols-2 gap-4">
                <SelectField label="Soin" name="service" options={config.services} required />
                <InputField label="Durée (min)" name="duration" type="number" defaultValue="60" step="15" />
              </div>

              <TextAreaField label="Remarques particulières" name="notes" rows={3} />

              <div className="pt-4 flex gap-3">
                <button type="submit" className="flex-1 py-3 bg-indigo-600 text-white rounded-xl font-bold hover:bg-indigo-700 shadow-lg shadow-indigo-100 transition-all">
                  Enregistrer le rendez-vous
                </button>
                <button type="button" onClick={() => setIsModalOpen(false)} className="px-6 py-3 bg-slate-100 text-slate-600 rounded-xl font-bold hover:bg-slate-200">
                  Annuler
                </button>
              </div>
            </form>
          </div>
        </div>
      )}
    </div>
  );
};

