const EditableConfigSection = ({ title, items, onUpdate }: { title: string, items: string[], onUpdate: (items: string[]) => void }) => {
  const [newItem, setNewItem] = useState('');

  const handleAdd = (e: React.FormEvent) => {
    e.preventDefault();
    if (!newItem.trim()) return;
    if (items.includes(newItem.trim())) {
      alert("Cet élément existe déjà.");
      return;
    }
    onUpdate([...items, newItem.trim()]);
    setNewItem('');
  };

  const handleDelete = (itemToDelete: string) => {
    if (confirm(`Supprimer "${itemToDelete}" ?`)) {
      onUpdate(items.filter(i => i !== itemToDelete));
    }
  };

  return (
    <div className="bg-white p-6 rounded-2xl border border-slate-100 shadow-sm flex flex-col h-full">
      <h3 className="text-lg font-bold mb-6 text-slate-800 flex items-center justify-between">
        {title}
        <span className="text-xs font-normal text-slate-400 bg-slate-50 px-2 py-1 rounded-md">{items.length} éléments</span>
      </h3>

      <div className="flex-1 space-y-3 mb-6">
        {items.map(item => (
          <div key={item} className="flex items-center justify-between group p-3 bg-slate-50 hover:bg-indigo-50/50 border border-slate-100 hover:border-indigo-100 rounded-xl transition-all">
            <span className="text-sm font-medium text-slate-700">{item}</span>
            <button 
              onClick={() => handleDelete(item)}
              className="p-1.5 text-slate-400 hover:text-red-500 opacity-0 group-hover:opacity-100 transition-all"
            >
              <Trash2 size={16} />
            </button>
          </div>
        ))}
        {items.length === 0 && <p className="text-center py-4 text-xs text-slate-400 italic">Aucun élément</p>}
      </div>

      <form onSubmit={handleAdd} className="mt-auto">
        <div className="relative">
          <input 
            type="text" 
            value={newItem}
            onChange={(e) => setNewItem(e.target.value)}
            placeholder={`Ajouter ${title.toLowerCase()}...`}
            className="w-full pl-4 pr-12 py-3 bg-white border border-slate-200 rounded-xl focus:ring-2 focus:ring-indigo-500 outline-none transition-all text-sm"
          />
          <button 
            type="submit"
            className="absolute right-2 top-1/2 -translate-y-1/2 p-2 bg-indigo-600 text-white rounded-lg hover:bg-indigo-700 transition-colors"
          >
            <Plus size={18} />
          </button>
        </div>
      </form>
    </div>
  );
};

