};

const EditableBreedsSection = ({ speciesList, breedsMap, onUpdateBreeds }: { speciesList: string[], breedsMap: Record<string, string[]>, onUpdateBreeds: (species: string, breeds: string[]) => void }) => {
  const [selectedSpecies, setSelectedSpecies] = useState(speciesList[0] || '');
  const [newBreed, setNewBreed] = useState('');

  const currentBreeds = breedsMap[selectedSpecies] || [];

  const handleAdd = (e: React.FormEvent) => {
    e.preventDefault();
    if (!selectedSpecies || !newBreed.trim()) return;
    if (currentBreeds.includes(newBreed.trim())) {
      alert("Cette race existe déjà pour cette espèce.");
      return;
    }
    onUpdateBreeds(selectedSpecies, [...currentBreeds, newBreed.trim()]);
    setNewBreed('');
  };

  const handleDelete = (breedToDelete: string) => {
    if (confirm(`Supprimer la race "${breedToDelete}" pour l'espèce "${selectedSpecies}" ?`)) {
      onUpdateBreeds(selectedSpecies, currentBreeds.filter(b => b !== breedToDelete));
    }
  };

  return (
    <div className="bg-white p-8 rounded-3xl border border-slate-100 shadow-sm">
      <div className="flex flex-col md:flex-row md:items-center justify-between gap-6 mb-8">
        <div>
          <h3 className="text-xl font-bold text-slate-800 flex items-center gap-2">
            <Tags className="text-indigo-600" size={24} />
            Gestion des Races par Espèce
          </h3>
          <p className="text-sm text-slate-500 mt-1">Configurez les races disponibles pour chaque animal dans la fiche client.</p>
        </div>

        <div className="flex items-center gap-3 bg-slate-100 p-1.5 rounded-2xl">
          {speciesList.map(sp => (
            <button
              key={sp}
              onClick={() => setSelectedSpecies(sp)}
              className={`px-4 py-2 rounded-xl text-sm font-bold transition-all ${selectedSpecies === sp ? 'bg-white text-indigo-600 shadow-sm' : 'text-slate-500 hover:bg-white/50'}`}
            >
              {sp}
            </button>
          ))}
          {speciesList.length === 0 && <span className="text-xs text-slate-400 px-4">Ajoutez d'abord une espèce</span>}
        </div>
      </div>

      <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 xl:grid-cols-4 gap-4">
        {currentBreeds.map(breed => (
          <div key={breed} className="flex items-center justify-between p-4 bg-slate-50 border border-slate-100 rounded-2xl group hover:border-indigo-100 hover:bg-indigo-50/30 transition-all">
            <span className="text-sm font-bold text-slate-700">{breed}</span>
            <button 
              onClick={() => handleDelete(breed)}
              className="p-2 text-slate-300 hover:text-red-500 opacity-0 group-hover:opacity-100 transition-all"
            >
              <Trash2 size={16} />
            </button>
          </div>
        ))}

        <form onSubmit={handleAdd} className="relative">
          <input 
            type="text" 
            value={newBreed}
            disabled={!selectedSpecies}
            onChange={(e) => setNewBreed(e.target.value)}
            placeholder={`Ajouter une race pour ${selectedSpecies}...`}
            className="w-full pl-4 pr-12 py-4 bg-white border-2 border-dashed border-slate-200 rounded-2xl focus:border-indigo-500 focus:border-solid outline-none transition-all text-sm"
          />
          <button 
            type="submit"
            disabled={!selectedSpecies}
            className="absolute right-2 top-1/2 -translate-y-1/2 p-2.5 bg-indigo-600 text-white rounded-xl hover:bg-indigo-700 disabled:opacity-30 transition-colors"
          >
            <Plus size={20} />
          </button>
        </form>
      </div>

      {!selectedSpecies && speciesList.length > 0 && (
         <div className="text-center py-12 text-slate-400 flex flex-col items-center gap-2">
           <ChevronRight className="rotate-90" />
           <p className="font-medium">Veuillez sélectionner une espèce en haut</p>
         </div>
      )}
    </div>
  );
};

export default App;

import { GoogleGenAI } from "@google/genai";
import { Client } from "../types";

export const getPetInsight = async (client: Client): Promise<string> => {
  try {
    // Initialize GoogleGenAI with the API key from environment variables.
    const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
    const prompt = `
      Agis comme un expert toiletteur. Voici les informations d'un client :
      Espèce: ${client.species}
      Race: ${client.breed}
      Particularités: ${client.particularities.join(", ")}
      Notes précédentes: ${client.notes}

      Donne-moi en 3 phrases maximum des conseils spécifiques pour son prochain toilettage (tempérament, soin du poil, précautions).
    `;

    // Generate content using the specified model and prompt.
    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: prompt,
    });

    // Access the generated text directly from the response object.
    return response.text || "Pas d'insight disponible pour le moment.";
  } catch (error) {
    console.error("Gemini Error:", error);
    return "Impossible de générer des conseils IA.";
  }
};

