          </div>
          <div className="flex items-center gap-2">
            <button onClick={() => setCurrentDate(new Date(currentDate.setDate(currentDate.getDate() - 1)))} className="p-2 hover:bg-slate-100 rounded-lg"><ChevronLeft size={20}/></button>
            <span className="text-lg font-bold text-slate-800 min-w-[150px] text-center">
              {currentDate.toLocaleDateString('fr-FR', { weekday: 'long', day: 'numeric', month: 'long' })}
            </span>
            <button onClick={() => setCurrentDate(new Date(currentDate.setDate(currentDate.getDate() + 1)))} className="p-2 hover:bg-slate-100 rounded-lg"><ChevronRight size={20}/></button>
          </div>
        </div>
        <button 
          onClick={() => { setSelectedAppt(null); setIsModalOpen(true); }}
          className="flex items-center gap-2 px-6 py-3 bg-indigo-600 text-white rounded-xl font-bold hover:bg-indigo-700 transition-all shadow-lg shadow-indigo-100"
        >
          <Plus size={20} />
          Prendre RDV
        </button>
      </div>

      <div className="flex-1 bg-white rounded-2xl shadow-sm border border-slate-100 overflow-y-auto">
        <div className="p-4 md:p-8">
          {dailyAppts.length > 0 ? (
            <div className="space-y-4">
              {dailyAppts.map(appt => (
                <div key={appt.id} className="group flex flex-col sm:flex-row items-start sm:items-center gap-4 sm:gap-6 p-4 md:p-6 rounded-2xl border border-slate-100 hover:border-indigo-100 hover:bg-slate-50/50 transition-all">
                  <div className="w-full sm:w-20 text-left sm:text-center border-b sm:border-b-0 sm:border-r pb-2 sm:pb-0 sm:pr-6 border-slate-100">
                    <p className="text-xl font-black text-slate-800 tracking-tight">{appt.time}</p>
                    <p className="text-[10px] font-bold text-slate-400 uppercase">{appt.duration}min</p>
                  </div>
                  <div className="flex-1">
                    <div className="flex flex-wrap items-center gap-3">
                      <h4 className="text-lg font-bold text-slate-800">{appt.petName}</h4>
                      <span className="px-2 py-0.5 bg-indigo-50 text-indigo-600 text-[10px] font-bold uppercase rounded-md">{appt.service}</span>
                      {appt.status === 'invoiced' && <span className="flex items-center gap-1 text-emerald-600 font-bold text-[10px] uppercase bg-emerald-50 px-2 py-0.5 rounded-md"><CheckCircle2 size={12}/> Payé</span>}
                    </div>
                    <p className="text-sm text-slate-500 font-medium">Propriétaire: {appt.clientName}</p>
                    {appt.notes && <p className="text-xs text-slate-400 mt-2 italic">"{appt.notes}"</p>}
                  </div>
                  <div className="flex items-center gap-2 transition-opacity no-print w-full sm:w-auto justify-end">
                    {appt.status !== 'invoiced' && (
                      <button 
                        onClick={() => openInvoiceModal(appt)}
                        className="flex items-center gap-2 px-4 py-2 bg-emerald-600 text-white rounded-xl text-sm font-bold hover:bg-emerald-700 shadow-md shadow-emerald-100 transition-all transform active:scale-95"
                      >
                        <FileText size={16} /> Facturer
                      </button>
                    )}
                    <button 
                       onClick={() => {
                        if(confirm("Supprimer ce rendez-vous ?")) {
                          db.deleteAppointment(appt.id);
                          refreshData();
                        }
                      }}
                      className="p-2 text-slate-400 hover:text-red-500 transition-colors"
                    >
                      <Trash2 size={20} />
                    </button>
                  </div>
                </div>
              ))}
            </div>
          ) : (
            <div className="h-full flex flex-col items-center justify-center text-slate-400 space-y-4 py-20">
              <Clock size={64} className="opacity-10" />
              <p className="font-medium">Aucun rendez-vous pour cette journée.</p>
            </div>
          )}
        </div>
      </div>

      {/* Modal Facturation */}
      {isInvoiceModalOpen && selectedAppt && (
        <div className="fixed inset-0 bg-slate-900/60 backdrop-blur-sm z-[60] flex items-center justify-center p-4">
          <div className="bg-white rounded-[2rem] w-full max-w-xl shadow-2xl overflow-hidden animate-in zoom-in-95 duration-200">
            <div className="bg-indigo-600 p-8 text-white relative">
              <div className="flex justify-between items-start mb-4">
                <div className="p-3 bg-white/20 rounded-2xl">
                  <Euro size={32} />
                </div>
                <button onClick={() => setIsInvoiceModalOpen(false)} className="text-white/60 hover:text-white text-xl">✕</button>
              </div>
              <h3 className="text-2xl font-bold">Facturation</h3>
              <p className="text-indigo-100 mt-1 opacity-80">{selectedAppt.petName} - {selectedAppt.service}</p>
            </div>

            <div className="p-8 space-y-6 max-h-[70vh] overflow-y-auto">
              <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
                <div className="space-y-2">
                  <label className="text-xs font-bold text-slate-400 uppercase tracking-wider">Montant (€)</label>
                  <input 
                    autoFocus
                    type="number" 
                    value={invoiceAmount}
                    onChange={(e) => setInvoiceAmount(e.target.value)}
                    className="w-full text-3xl font-black text-slate-800 bg-slate-50 border-none rounded-2xl p-4 focus:ring-4 focus:ring-indigo-500/10 transition-all"
                  />
                </div>

                <div className="space-y-2">
                  <label className="text-xs font-bold text-slate-400 uppercase tracking-wider">Mode de règlement</label>
                  <div className="grid grid-cols-2 gap-2">
                    {['Carte', 'Espèces', 'Chèque', 'Virement'].map((method) => (
                      <button
                        key={method}
                        onClick={() => setPaymentMethod(method as any)}
                        className={`flex items-center gap-2 px-3 py-3 rounded-xl border-2 transition-all font-bold text-xs ${
                          paymentMethod === method 
                          ? 'border-indigo-600 bg-indigo-50 text-indigo-700' 
                          : 'border-slate-100 bg-white text-slate-500 hover:border-slate-200'
                        }`}
                      >
                        {method}
                      </button>
                    ))}
                  </div>
                </div>
              </div>

              <div className="space-y-2">
                <label className="text-xs font-bold text-slate-400 uppercase tracking-wider flex items-center gap-2">
                  <MessageSquare size={14} />
                  Commentaires sur la prestation (Historique)
                </label>
                <textarea 
                  value={invoiceNotes}
                  onChange={(e) => setInvoiceNotes(e.target.value)}
                  placeholder="Détails techniques, comportement, produits utilisés..."
                  rows={4}
                  className="w-full p-4 bg-slate-50 border-none rounded-2xl focus:ring-4 focus:ring-indigo-500/10 transition-all text-sm resize-none"
                />
              </div>

              <div className="pt-4 flex flex-col gap-3">
                <button 
                  onClick={handleConfirmInvoice}
                  className="w-full py-5 bg-indigo-600 text-white rounded-2xl font-black text-lg hover:bg-indigo-700 shadow-xl shadow-indigo-200 transition-all transform active:scale-95"
                >
                  Valider et Enregistrer
                </button>
              </div>
            </div>
          </div>
        </div>
      )}

      {/* Modal Nouveau RDV */}
      {isModalOpen && (
        <div className="fixed inset-0 bg-slate-900/40 backdrop-blur-sm z-50 flex items-center justify-center p-4">
          <div className="bg-white rounded-3xl w-full max-w-xl shadow-2xl overflow-hidden animate-in zoom-in-95 duration-200">
            <div className="p-8 border-b border-slate-100 flex justify-between items-center">
              <h3 className="text-xl font-bold text-slate-800">Nouveau Rendez-vous</h3>
              <button onClick={() => setIsModalOpen(false)} className="text-slate-400 hover:text-slate-600 text-xl">✕</button>
            </div>
            <form onSubmit={handleSaveAppt} className="p-8 space-y-6">
              <div className="grid grid-cols-2 gap-4">
                <InputField label="Date" name="date" type="date" defaultValue={dateStr} required />
                <InputField label="Heure" name="time" type="time" defaultValue="09:00" required />
              </div>

              <SelectField 
                label="Client" 
                name="client" 
                options={clients.map(c => `${c.name} - ${c.ownerName}`)} 
                required 
              />

              <div className="grid grid-cols-2 gap-4">
                <SelectField label="Soin" name="service" options={config.services} required />
                <InputField label="Durée (min)" name="duration" type="number" defaultValue="60" step="15" />
              </div>

              <TextAreaField label="Remarques particulières" name="notes" rows={3} />

              <div className="pt-4 flex gap-3">
                <button type="submit" className="flex-1 py-3 bg-indigo-600 text-white rounded-xl font-bold hover:bg-indigo-700 shadow-lg shadow-indigo-100 transition-all">
                  Enregistrer
                </button>
                <button type="button" onClick={() => setIsModalOpen(false)} className="px-6 py-3 bg-slate-100 text-slate-600 rounded-xl font-bold hover:bg-slate-200">
                  Annuler
                </button>
              </div>
            </form>
          </div>
        </div>
      )}
    </div>
  );
};

const InputField = ({ label, ...props }: any) => (
  <div className="space-y-1.5">
    <label className="text-xs font-bold text-slate-500 uppercase">{label}</label>
    <input {...props} className="w-full px-4 py-2 bg-slate-50 border border-slate-200 rounded-xl focus:ring-2 focus:ring-indigo-500 outline-none transition-all text-sm" />
  </div>
);

const SelectField = ({ label, options, ...props }: any) => (
  <div className="space-y-1.5">
    <label className="text-xs font-bold text-slate-500 uppercase">{label}</label>
    <select {...props} className="w-full px-4 py-2 bg-slate-50 border border-slate-200 rounded-xl focus:ring-2 focus:ring-indigo-500 outline-none transition-all text-sm appearance-none cursor-pointer">
      <option value="">-- Choisir --</option>
      {options.map((o: string) => <option key={o} value={o}>{o}</option>)}
    </select>
  </div>
);

const TextAreaField = ({ label, ...props }: any) => (
  <div className="space-y-1.5">
    <label className="text-xs font-bold text-slate-500 uppercase">{label}</label>
    <textarea {...props} className="w-full px-4 py-2 bg-slate-50 border border-slate-200 rounded-xl focus:ring-2 focus:ring-indigo-500 outline-none transition-all text-sm resize-none" />
  </div>
);

export default Planning;

import { Search, Plus, User, Phone, Mail, MapPin, Calendar, Sparkles, Trash2, Edit3, Camera, History, FileText, ChevronRight } from 'lucide-react';
import { getPetInsight } from '../services/gemini';
import React, { useState, useEffect } from 'react';
import { db } from '../services/database';
import { Client, Invoice } from '../types';

const ClientList: React.FC<{ initialClientId?: string | null }> = ({ initialClientId }) => {
  const [clients, setClients] = useState<Client[]>([]);
  const [search, setSearch] = useState('');
  const [selectedClient, setSelectedClient] = useState<Client | null>(null);
  const [isEditing, setIsEditing] = useState(false);
  const [aiInsight, setAiInsight] = useState<string | null>(null);
  const [loadingAi, setLoadingAi] = useState(false);
  const [clientInvoices, setClientInvoices] = useState<Invoice[]>([]);

  // Local state for the species currently selected in the form
  const [formSpecies, setFormSpecies] = useState<string>('');

  const config = db.getConfig();

  useEffect(() => {
    const loaded = db.getClients();
    setClients(loaded);
    if (initialClientId) {
      const found = loaded.find(c => c.id === initialClientId);
      if (found) {
        setSelectedClient(found);
        setFormSpecies(found.species);
        loadHistory(found.id);
      }
    }
  }, [initialClientId]);

  const loadHistory = (clientId: string) => {
    const allInvoices = db.getInvoices();
    const filtered = allInvoices.filter(inv => inv.clientId === clientId).reverse();
    setClientInvoices(filtered);
  };

  const filteredClients = clients.filter(c => 
    c.name.toLowerCase().includes(search.toLowerCase()) || 
    c.ownerName.toLowerCase().includes(search.toLowerCase())
  );

  const handleSave = (e: React.FormEvent<HTMLFormElement>) => {
    e.preventDefault();
    const formData = new FormData(e.currentTarget);
    const updated: Client = {
      id: selectedClient?.id || crypto.randomUUID(),
      name: formData.get('name') as string,
      species: formData.get('species') as string,
      breed: formData.get('breed') as string,
      coatType: formData.get('coatType') as string,
      birthDate: formData.get('birthDate') as string,
      ownerName: formData.get('ownerName') as string,
      phone: formData.get('phone') as string,
      email: formData.get('email') as string,
      address: formData.get('address') as string,
      notes: formData.get('notes') as string,
      particularities: Array.from(formData.getAll('particularities')) as string[],
      createdAt: selectedClient?.createdAt || new Date().toISOString(),
      photoProfile: selectedClient?.photoProfile || `https://picsum.photos/seed/${Math.random()}/300/300`
    };

    db.saveClient(updated);
    setClients(db.getClients());
    setSelectedClient(updated);
    setIsEditing(false);
  };

  const loadAiAdvice = async (client: Client) => {
    setLoadingAi(true);
    const insight = await getPetInsight(client);
    setAiInsight(insight);
    setLoadingAi(false);
  };

  const handleSpeciesChange = (e: React.ChangeEvent<HTMLSelectElement>) => {
    setFormSpecies(e.target.value);
  };

  return (
    <div className="flex flex-col lg:flex-row gap-8 h-[calc(100vh-140px)]">
      {/* List */}
      <div className="w-full lg:w-96 flex flex-col gap-4 bg-white p-4 rounded-2xl shadow-sm border border-slate-100 overflow-hidden">
        <div className="flex gap-2">
          <div className="relative flex-1">
            <Search className="absolute left-3 top-1/2 -translate-y-1/2 text-slate-400" size={18} />
            <input 
              type="text" 
              placeholder="Rechercher..." 
              className="w-full pl-10 pr-4 py-2 bg-slate-50 border-none rounded-xl focus:ring-2 focus:ring-indigo-500 text-sm"
              value={search}
              onChange={e => setSearch(e.target.value)}
            />
          </div>
          <button 
            onClick={() => { 
              setSelectedClient(null); 
              setIsEditing(true); 
              setAiInsight(null);
              setFormSpecies('');
              setClientInvoices([]);
            }}
            className="p-2 bg-indigo-600 text-white rounded-xl hover:bg-indigo-700 transition-colors shadow-md shadow-indigo-200"
          >
            <Plus size={20} />
          </button>
        </div>

        <div className="flex-1 overflow-y-auto space-y-2 pr-2">
          {filteredClients.map(client => (
            <button
              key={client.id}
              onClick={() => { 
                setSelectedClient(client); 
                setIsEditing(false); 
                setAiInsight(null);
                setFormSpecies(client.species);
                loadHistory(client.id);
              }}
              className={`w-full text-left p-4 rounded-xl transition-all ${
                selectedClient?.id === client.id 
                ? 'bg-indigo-50 border-l-4 border-indigo-600 ring-1 ring-indigo-100' 
                : 'hover:bg-slate-50 border-l-4 border-transparent'
              }`}
            >
              <div className="flex justify-between items-start">
                <div>
                  <h4 className="font-bold text-slate-800">{client.name}</h4>
                  <p className="text-xs text-slate-500 font-medium">{client.ownerName}</p>
                </div>
                <span className="text-[10px] px-2 py-1 bg-slate-100 rounded-full font-bold uppercase text-slate-600">
                  {client.species}
                </span>
              </div>
            </button>
          ))}
        </div>
      </div>

      {/* Details/Form */}
      <div className="flex-1 bg-white rounded-2xl shadow-sm border border-slate-100 overflow-y-auto overflow-x-hidden">
        {isEditing ? (
          <form onSubmit={handleSave} className="p-8 space-y-8 animate-in slide-in-from-right duration-300">
            <h2 className="text-2xl font-bold text-slate-800">{selectedClient ? 'Modifier le client' : 'Nouveau client'}</h2>

            <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
              <div className="space-y-4">
                <h3 className="text-sm font-bold text-indigo-600 uppercase tracking-wider">Informations Animal</h3>
                <InputField label="Nom de l'animal" name="name" defaultValue={selectedClient?.name} required />
                <div className="grid grid-cols-2 gap-4">
                  <SelectField label="Espèce" name="species" options={config.species} defaultValue={selectedClient?.species} onChange={handleSpeciesChange} required />
                  <SelectField label="Race" name="breed" options={config.breeds[formSpecies] || []} defaultValue={selectedClient?.breed} required />
                </div>
                <SelectField label="Type de poil" name="coatType" options={config.coatTypes} defaultValue={selectedClient?.coatType} />
                <InputField label="Date de naissance" name="birthDate" type="date" defaultValue={selectedClient?.birthDate} />
              </div>

              <div className="space-y-4">
                <h3 className="text-sm font-bold text-indigo-600 uppercase tracking-wider">Informations Propriétaire</h3>
                <InputField label="Nom complet" name="ownerName" defaultValue={selectedClient?.ownerName} required />
                <InputField label="Téléphone" name="phone" defaultValue={selectedClient?.phone} required />
                <InputField label="Email" name="email" type="email" defaultValue={selectedClient?.email} />
                <TextAreaField label="Adresse" name="address" defaultValue={selectedClient?.address} />
              </div>
            </div>

            <div className="space-y-4">
              <h3 className="text-sm font-bold text-indigo-600 uppercase tracking-wider">Particularités & Notes Fixes</h3>
              <div className="flex flex-wrap gap-3">
                {config.particularities.map(p => (
                  <label key={p} className="flex items-center gap-2 px-3 py-2 bg-slate-50 rounded-lg cursor-pointer hover:bg-indigo-50 transition-colors">
                    <input type="checkbox" name="particularities" value={p} defaultChecked={selectedClient?.particularities.includes(p)} className="rounded text-indigo-600" />
                    <span className="text-sm text-slate-700">{p}</span>
                  </label>
                ))}
              </div>
              <TextAreaField label="Notes de base (tempérament général)" name="notes" defaultValue={selectedClient?.notes} rows={4} />
            </div>

            <div className="flex gap-4 pt-4 border-t">
              <button type="submit" className="px-8 py-3 bg-indigo-600 text-white rounded-xl font-bold hover:bg-indigo-700 transition-all shadow-lg shadow-indigo-100">
                Enregistrer
              </button>
              <button type="button" onClick={() => setIsEditing(false)} className="px-8 py-3 bg-slate-100 text-slate-700 rounded-xl font-bold hover:bg-slate-200">
                Annuler
              </button>
            </div>
          </form>
        ) : selectedClient ? (
          <div className="p-8 space-y-12 animate-in zoom-in-95 duration-200">
            <div className="flex items-start justify-between">
              <div className="flex items-center gap-6">
                <div className="w-24 h-24 rounded-3xl bg-indigo-50 flex items-center justify-center relative group overflow-hidden shadow-inner">
                  {selectedClient.photoProfile ? (
                    <img src={selectedClient.photoProfile} className="w-full h-full object-cover" alt="" />
                  ) : (
                    <PawIcon className="w-12 h-12 text-indigo-300" />
                  )}
                  <div className="absolute inset-0 bg-black/40 opacity-0 group-hover:opacity-100 flex items-center justify-center transition-opacity cursor-pointer">
                    <Camera size={24} className="text-white" />
                  </div>
                </div>
                <div>
                  <h2 className="text-3xl font-black text-slate-800 tracking-tight">{selectedClient.name}</h2>
                  <div className="flex items-center gap-3 mt-1">
                    <span className="px-3 py-1 bg-indigo-100 text-indigo-700 text-xs font-bold rounded-full">{selectedClient.species}</span>
                    <span className="text-slate-400 font-medium">•</span>
                    <span className="text-slate-500 text-sm font-semibold">{selectedClient.breed}</span>
                  </div>
                </div>
              </div>
              <div className="flex gap-2">
                <button onClick={() => setIsEditing(true)} className="p-2.5 bg-slate-100 text-slate-600 rounded-xl hover:bg-indigo-50 hover:text-indigo-600 transition-colors">
                  <Edit3 size={20} />
                </button>
                <button 
                  onClick={() => {
                    if(confirm("Supprimer définitivement ce client ?")) {
                      db.deleteClient(selectedClient.id);
                      setClients(db.getClients());
                      setSelectedClient(null);
                    }
                  }}
                  className="p-2.5 bg-slate-100 text-slate-600 rounded-xl hover:bg-red-50 hover:text-red-600 transition-colors"
                >
                  <Trash2 size={20} />
                </button>
              </div>
            </div>

            <div className="grid grid-cols-1 lg:grid-cols-2 gap-12">
              <div className="space-y-8">
                <div>
                  <h3 className="text-sm font-bold text-slate-400 uppercase tracking-widest border-b pb-2 mb-4">Propriétaire</h3>
                  <div className="space-y-4">
                    <InfoItem icon={<User size={18} />} label="Nom" value={selectedClient.ownerName} />
                    <InfoItem icon={<Phone size={18} />} label="Tel" value={selectedClient.phone} />
                    <InfoItem icon={<Mail size={18} />} label="Email" value={selectedClient.email || "Non renseigné"} />
                    <InfoItem icon={<MapPin size={18} />} label="Adresse" value={selectedClient.address || "Non renseignée"} />
                  </div>
                </div>

                <div>
                   <h3 className="text-sm font-bold text-slate-400 uppercase tracking-widest border-b pb-2 mb-4">Caractéristiques</h3>
                   <div className="space-y-6">
                      <div>
                        <p className="text-xs font-bold text-slate-400 mb-2 uppercase">Particularités</p>
                        <div className="flex flex-wrap gap-2">
                          {selectedClient.particularities.length > 0 ? selectedClient.particularities.map(p => (
                            <span key={p} className="px-3 py-1 bg-amber-50 text-amber-700 border border-amber-100 rounded-lg text-xs font-bold">{p}</span>
                          )) : <span className="text-sm text-slate-400 italic">Aucune</span>}
                        </div>
                      </div>
                      <div>
                        <p className="text-xs font-bold text-slate-400 mb-2 uppercase">Notes Générales</p>
                        <p className="text-slate-600 text-sm leading-relaxed bg-slate-50 p-4 rounded-xl border border-slate-100 italic">
                          {selectedClient.notes || "Pas de notes de base."}
                        </p>
                      </div>
                   </div>
                </div>
              </div>

              {/* Visit History Section */}
              <div className="space-y-6">
                <h3 className="text-sm font-bold text-indigo-600 uppercase tracking-widest border-b border-indigo-100 pb-2 flex items-center gap-2">
                  <History size={18} />
                  Historique des Visites
                </h3>
                <div className="space-y-4 overflow-y-auto max-h-[500px] pr-2">
                  {clientInvoices.length > 0 ? clientInvoices.map((inv, idx) => (
                    <div key={inv.id} className="relative pl-8 pb-4">
                      {idx !== clientInvoices.length - 1 && <div className="absolute left-[11px] top-6 bottom-0 w-0.5 bg-slate-100"></div>}
                      <div className="absolute left-0 top-1 w-6 h-6 rounded-full bg-indigo-50 border-2 border-indigo-600 flex items-center justify-center z-10">
                        <div className="w-2 h-2 rounded-full bg-indigo-600"></div>
                      </div>
                      <div className="bg-white p-4 rounded-2xl border border-slate-100 hover:border-indigo-100 transition-all shadow-sm">
                        <div className="flex justify-between items-start mb-2">
                          <div>
                            <p className="text-xs font-bold text-slate-400 uppercase">{new Date(inv.date).toLocaleDateString('fr-FR', { day: 'numeric', month: 'long', year: 'numeric' })}</p>
                            <p className="text-sm font-bold text-slate-800">{inv.number}</p>
                          </div>
                          <p className="text-sm font-black text-indigo-600">{inv.amount}€</p>
                        </div>
                        {inv.notes ? (
                          <div className="mt-3 p-3 bg-slate-50 rounded-xl border-l-4 border-indigo-400">
                            <p className="text-xs text-slate-600 leading-relaxed italic">"{inv.notes}"</p>
                          </div>
                        ) : (
