  const [selectedSpecies, setSelectedSpecies] = useState(speciesList[0] || '');
  const [newBreed, setNewBreed] = useState('');
  const currentBreeds = breedsMap[selectedSpecies] || [];
  const handleAdd = (e: React.FormEvent) => {
    e.preventDefault();
    if (!selectedSpecies || !newBreed.trim()) return;
    if (currentBreeds.includes(newBreed.trim())) { alert("Cette race existe déjà."); return; }
    onUpdateBreeds(selectedSpecies, [...currentBreeds, newBreed.trim()]);
    setNewBreed('');
  };
  const handleDelete = (breedToDelete: string) => {
    if (confirm(`Supprimer "${breedToDelete}" ?`)) onUpdateBreeds(selectedSpecies, currentBreeds.filter((b: string) => b !== breedToDelete));
  };
  return (
    <div className="bg-white p-8 rounded-3xl border border-slate-100 shadow-sm">
      <div className="flex flex-col md:flex-row md:items-center justify-between gap-6 mb-8">
        <div><h3 className="text-xl font-bold text-slate-800 flex items-center gap-2"><Tags className="text-indigo-600" size={24} /> Gestion des Races</h3></div>
        <div className="flex items-center gap-3 bg-slate-100 p-1.5 rounded-2xl">
          {speciesList.map((sp: string) => (
            <button key={sp} onClick={() => setSelectedSpecies(sp)} className={`px-4 py-2 rounded-xl text-sm font-bold transition-all ${selectedSpecies === sp ? 'bg-white text-indigo-600 shadow-sm' : 'text-slate-500'}`}>{sp}</button>
          ))}
        </div>
      </div>
      <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 xl:grid-cols-4 gap-4">
        {currentBreeds.map((breed: string) => (
          <div key={breed} className="flex items-center justify-between p-4 bg-slate-50 border border-slate-100 rounded-2xl group transition-all">
            <span className="text-sm font-bold text-slate-700">{breed}</span>
            <button onClick={() => handleDelete(breed)} className="p-2 text-slate-300 hover:text-red-500 opacity-0 group-hover:opacity-100 transition-all"><Trash2 size={16} /></button>
          </div>
        ))}
        <form onSubmit={handleAdd} className="relative">
          <input type="text" value={newBreed} disabled={!selectedSpecies} onChange={(e) => setNewBreed(e.target.value)} placeholder={`Ajouter une race...`} className="w-full pl-4 pr-12 py-4 bg-white border-2 border-dashed border-slate-200 rounded-2xl focus:border-indigo-500 outline-none text-sm" />
          <button type="submit" className="absolute right-2 top-1/2 -translate-y-1/2 p-2.5 bg-indigo-600 text-white rounded-xl"><Plus size={20} /></button>
        </form>
      </div>
    </div>
  );
};

export default App;

import React, { useState, useEffect } from 'react';
import { db } from '../services/database';
import { Appointment, Client, Invoice } from '../types';
import { Calendar as CalendarIcon, Clock, ChevronLeft, ChevronRight, FileText, CheckCircle2, Trash2, Plus, Euro, CreditCard, Banknote, MessageSquare, Printer } from 'lucide-react';

const generateId = () => {
  if (typeof crypto !== 'undefined' && crypto.randomUUID) return crypto.randomUUID();
  return Math.random().toString(36).substring(2, 15) + Math.random().toString(36).substring(2, 15);
};

interface PlanningProps {
  onPrintInvoice?: (invoice: Invoice) => void;
}

const Planning: React.FC<PlanningProps> = ({ onPrintInvoice }) => {
  const [view, setView] = useState<'day' | 'month'>('day');
  const [currentDate, setCurrentDate] = useState(new Date());
  const [appointments, setAppointments] = useState<Appointment[]>([]);
  const [clients, setClients] = useState<Client[]>([]);
  const [isModalOpen, setIsModalOpen] = useState(false);
  const [isInvoiceModalOpen, setIsInvoiceModalOpen] = useState(false);
  const [selectedAppt, setSelectedAppt] = useState<Appointment | null>(null);
  const [invoiceAmount, setInvoiceAmount] = useState('50');
  const [invoiceNotes, setInvoiceNotes] = useState('');
  const [paymentMethod, setPaymentMethod] = useState<Invoice['paymentMethod']>('Carte');

  const config = db.getConfig();

  const refreshData = () => {
    setAppointments(db.getAppointments());
    setClients(db.getClients());
  };

  useEffect(() => {
    refreshData();
  }, []);

  const formatDate = (date: Date) => date.toISOString().split('T')[0];
  const dateStr = formatDate(currentDate);

  const dailyAppts = appointments
    .filter(a => a.date === dateStr)
    .sort((a, b) => a.time.localeCompare(b.time));

  const handleSaveAppt = (e: React.FormEvent<HTMLFormElement>) => {
    e.preventDefault();
    const formData = new FormData(e.currentTarget);
    const clientSelect = formData.get('client') as string;

    if (!clientSelect) {
      alert("Veuillez sélectionner un client.");
      return;
    }

    const [petName, ownerName] = clientSelect.split(' - ');
    const client = clients.find(c => c.name === petName && c.ownerName === ownerName);

    const newAppt: Appointment = {
      id: selectedAppt?.id || generateId(),
      date: formData.get('date') as string,
      time: formData.get('time') as string,
      clientId: client?.id || '',
      clientName: ownerName,
      petName: petName,
      service: formData.get('service') as string,
      notes: formData.get('notes') as string,
      duration: parseInt(formData.get('duration') as string),
      status: selectedAppt?.status || 'pending'
    };

    db.saveAppointment(newAppt);
    refreshData();
    setIsModalOpen(false);
    setSelectedAppt(null);
  };

  const openInvoiceModal = (appt: Appointment) => {
    setSelectedAppt(appt);
    setInvoiceNotes(''); // Reset notes
    setIsInvoiceModalOpen(true);
  };

  const handleConfirmInvoice = () => {
    if (!selectedAppt) return;

    const amount = parseFloat(invoiceAmount);
    if (isNaN(amount)) {
      alert("Veuillez saisir un montant valide.");
      return;
    }

    const invoiceNumber = `FAC-${Date.now().toString().slice(-6)}`;

    const newInvoice: Invoice = {
      id: generateId(),
      number: invoiceNumber,
      date: formatDate(new Date()),
      clientId: selectedAppt.clientId,
      petName: selectedAppt.petName,
      ownerName: selectedAppt.clientName,
      amount: amount,
      paymentMethod: paymentMethod,
      appointmentId: selectedAppt.id,
      notes: invoiceNotes
    };

    db.saveInvoice(newInvoice);

    const updated = { ...selectedAppt, status: 'invoiced' as const };
    db.saveAppointment(updated);

    refreshData();
    setIsInvoiceModalOpen(false);
    setSelectedAppt(null);

    if(confirm(`Facture ${invoiceNumber} enregistrée ! Voulez-vous générer le PDF maintenant ?`)) {
      onPrintInvoice?.(newInvoice);
    }
  };

  return (
    <div className="space-y-8 h-[calc(100vh-140px)] flex flex-col">
      <div className="flex flex-col sm:flex-row items-center justify-between gap-4 no-print">
        <div className="flex items-center gap-4">
          <div className="flex bg-white rounded-xl p-1 shadow-sm border border-slate-100">
            <button onClick={() => setView('day')} className={`px-4 py-2 rounded-lg text-sm font-bold transition-all ${view === 'day' ? 'bg-indigo-600 text-white shadow-md' : 'text-slate-600 hover:bg-slate-50'}`}>Jour</button>
            <button onClick={() => setView('month')} className={`px-4 py-2 rounded-lg text-sm font-bold transition-all ${view === 'month' ? 'bg-indigo-600 text-white shadow-md' : 'text-slate-600 hover:bg-slate-50'}`}>Mois</button>
          </div>
          <div className="flex items-center gap-2">
            <button onClick={() => setCurrentDate(new Date(currentDate.setDate(currentDate.getDate() - 1)))} className="p-2 hover:bg-slate-100 rounded-lg"><ChevronLeft size={20}/></button>
            <span className="text-lg font-bold text-slate-800 min-w-[150px] text-center">{currentDate.toLocaleDateString('fr-FR', { weekday: 'long', day: 'numeric', month: 'long' })}</span>
            <button onClick={() => setCurrentDate(new Date(currentDate.setDate(currentDate.getDate() + 1)))} className="p-2 hover:bg-slate-100 rounded-lg"><ChevronRight size={20}/></button>
          </div>
        </div>
        <button onClick={() => { setSelectedAppt(null); setIsModalOpen(true); }} className="flex items-center gap-2 px-6 py-3 bg-indigo-600 text-white rounded-xl font-bold hover:bg-indigo-700 shadow-lg transition-all"><Plus size={20} />Prendre RDV</button>
      </div>

      <div className="flex-1 bg-white rounded-2xl shadow-sm border border-slate-100 overflow-y-auto">
        <div className="p-4 md:p-8">
          {dailyAppts.length > 0 ? (
            <div className="space-y-4">
              {dailyAppts.map(appt => (
                <div key={appt.id} className="group flex flex-col sm:flex-row items-start sm:items-center gap-4 sm:gap-6 p-4 md:p-6 rounded-2xl border border-slate-100 hover:border-indigo-100 hover:bg-slate-50/50 transition-all">
                  <div className="w-full sm:w-20 text-left sm:text-center border-b sm:border-b-0 sm:border-r pb-2 sm:pb-0 sm:pr-6 border-slate-100">
                    <p className="text-xl font-black text-slate-800 tracking-tight">{appt.time}</p>
                    <p className="text-[10px] font-bold text-slate-400 uppercase">{appt.duration}min</p>
                  </div>
                  <div className="flex-1">
                    <div className="flex flex-wrap items-center gap-3">
                      <h4 className="text-lg font-bold text-slate-800">{appt.petName}</h4>
                      <span className="px-2 py-0.5 bg-indigo-50 text-indigo-600 text-[10px] font-bold uppercase rounded-md">{appt.service}</span>
                      {appt.status === 'invoiced' && <span className="flex items-center gap-1 text-emerald-600 font-bold text-[10px] uppercase bg-emerald-50 px-2 py-0.5 rounded-md"><CheckCircle2 size={12}/> Payé</span>}
                    </div>
                    <p className="text-sm text-slate-500 font-medium">Propriétaire: {appt.clientName}</p>
                  </div>
                  <div className="flex items-center gap-2 transition-opacity no-print w-full sm:w-auto justify-end">
                    {appt.status !== 'invoiced' ? (
                      <button onClick={() => openInvoiceModal(appt)} className="flex items-center gap-2 px-4 py-2 bg-emerald-600 text-white rounded-xl text-sm font-bold hover:bg-emerald-700 shadow-md transition-all"><FileText size={16} /> Facturer</button>
                    ) : (
                      <button 
                        onClick={() => {
                          const inv = db.getInvoices().find(i => i.appointmentId === appt.id);
                          if(inv) onPrintInvoice?.(inv);
                        }} 
                        className="flex items-center gap-2 px-4 py-2 bg-slate-100 text-slate-600 rounded-xl text-sm font-bold hover:bg-indigo-50 hover:text-indigo-600 transition-all"
                      >
                        <Printer size={16} /> PDF
                      </button>
                    )}
                    <button onClick={() => { if(confirm("Supprimer ce rendez-vous ?")) { db.deleteAppointment(appt.id); refreshData(); } }} className="p-2 text-slate-400 hover:text-red-500"><Trash2 size={20} /></button>
                  </div>
                </div>
              ))}
            </div>
          ) : (
            <div className="h-full flex flex-col items-center justify-center text-slate-400 space-y-4 py-20">
              <Clock size={64} className="opacity-10" />
              <p className="font-medium">Aucun rendez-vous pour cette journée.</p>
            </div>
          )}
        </div>
      </div>

      {/* Modal Facturation */}
      {isInvoiceModalOpen && selectedAppt && (
        <div className="fixed inset-0 bg-slate-900/60 backdrop-blur-sm z-[60] flex items-center justify-center p-4">
          <div className="bg-white rounded-[2rem] w-full max-w-xl shadow-2xl overflow-hidden animate-in zoom-in-95 duration-200">
            <div className="bg-indigo-600 p-8 text-white relative">
              <div className="flex justify-between items-start mb-4">
                <div className="p-3 bg-white/20 rounded-2xl"><Euro size={32} /></div>
                <button onClick={() => setIsInvoiceModalOpen(false)} className="text-white/60 hover:text-white text-xl">✕</button>
              </div>
              <h3 className="text-2xl font-bold">Facturation</h3>
              <p className="text-indigo-100 mt-1 opacity-80">{selectedAppt.petName} - {selectedAppt.service}</p>
            </div>
            <div className="p-8 space-y-6 max-h-[70vh] overflow-y-auto">
              <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
                <div className="space-y-2">
                  <label className="text-xs font-bold text-slate-400 uppercase tracking-wider">Montant (€)</label>
                  <input autoFocus type="number" value={invoiceAmount} onChange={(e) => setInvoiceAmount(e.target.value)} className="w-full text-3xl font-black text-slate-800 bg-slate-50 border-none rounded-2xl p-4 focus:ring-4 focus:ring-indigo-500/10" />
                </div>
                <div className="space-y-2">
                  <label className="text-xs font-bold text-slate-400 uppercase tracking-wider">Mode de règlement</label>
                  <div className="grid grid-cols-2 gap-2">
                    {['Carte', 'Espèces', 'Chèque', 'Virement'].map((method) => (
                      <button key={method} onClick={() => setPaymentMethod(method as any)} className={`flex items-center gap-2 px-3 py-3 rounded-xl border-2 transition-all font-bold text-xs ${paymentMethod === method ? 'border-indigo-600 bg-indigo-50 text-indigo-700' : 'border-slate-100 bg-white text-slate-500'}`}>{method}</button>
                    ))}
                  </div>
                </div>
              </div>
              <div className="space-y-2">
                <label className="text-xs font-bold text-slate-400 uppercase tracking-wider flex items-center gap-2"><MessageSquare size={14} />Commentaires de prestation (PDF)</label>
                <textarea value={invoiceNotes} onChange={(e) => setInvoiceNotes(e.target.value)} placeholder="Détails techniques, comportement..." rows={4} className="w-full p-4 bg-slate-50 border-none rounded-2xl text-sm resize-none" />
              </div>
              <button onClick={handleConfirmInvoice} className="w-full py-5 bg-indigo-600 text-white rounded-2xl font-black text-lg hover:bg-indigo-700 shadow-xl transition-all active:scale-95">Valider et Terminer</button>
            </div>
          </div>
        </div>
      )}

      {/* Modal Nouveau RDV */}
      {isModalOpen && (
        <div className="fixed inset-0 bg-slate-900/40 backdrop-blur-sm z-50 flex items-center justify-center p-4">
          <div className="bg-white rounded-3xl w-full max-w-xl shadow-2xl overflow-hidden animate-in zoom-in-95 duration-200">
            <div className="p-8 border-b border-slate-100 flex justify-between items-center">
              <h3 className="text-xl font-bold text-slate-800">Nouveau Rendez-vous</h3>
              <button onClick={() => setIsModalOpen(false)} className="text-slate-400 hover:text-slate-600 text-xl">✕</button>
            </div>
            <form onSubmit={handleSaveAppt} className="p-8 space-y-6">
              <div className="grid grid-cols-2 gap-4">
                <InputField label="Date" name="date" type="date" defaultValue={dateStr} required />
                <InputField label="Heure" name="time" type="time" defaultValue="09:00" required />
              </div>

              <SelectField 
                label="Client" 
                name="client" 
                options={clients.map(c => `${c.name} - ${c.ownerName}`)} 
                required 
              />

              <div className="grid grid-cols-2 gap-4">
                <SelectField label="Soin" name="service" options={config.services} required />
                <InputField label="Durée (min)" name="duration" type="number" defaultValue="60" step="15" />
              </div>

              <TextAreaField label="Remarques particulières" name="notes" rows={3} />

              <div className="pt-4 flex gap-3">
                <button type="submit" className="flex-1 py-3 bg-indigo-600 text-white rounded-xl font-bold hover:bg-indigo-700 shadow-lg shadow-indigo-100 transition-all">
                  Enregistrer
                </button>
                <button type="button" onClick={() => setIsModalOpen(false)} className="px-6 py-3 bg-slate-100 text-slate-600 rounded-xl font-bold hover:bg-slate-200">
                  Annuler
                </button>
              </div>
            </form>
          </div>
        </div>
      )}
    </div>
  );
};

const InputField = ({ label, ...props }: any) => (
  <div className="space-y-1.5">
    <label className="text-xs font-bold text-slate-500 uppercase">{label}</label>
    <input {...props} className="w-full px-4 py-2 bg-slate-50 border border-slate-200 rounded-xl outline-none text-sm" />
  </div>
);

const SelectField = ({ label, options, ...props }: any) => (
  <div className="space-y-1.5">
    <label className="text-xs font-bold text-slate-500 uppercase">{label}</label>
    <select {...props} className="w-full px-4 py-2 bg-slate-50 border border-slate-200 rounded-xl outline-none text-sm appearance-none cursor-pointer">
      <option value="">-- Choisir --</option>
      {options.map((o: string) => <option key={o} value={o}>{o}</option>)}
