const EditableConfigSection = ({ title, items, onUpdate }: any) => {
  const [newItem, setNewItem] = useState('');
  const handleAdd = (e: React.FormEvent) => {
    e.preventDefault();
    if (!newItem.trim()) return;
    if (items.includes(newItem.trim())) { alert("Cet élément existe déjà."); return; }
    onUpdate([...items, newItem.trim()]);
    setNewItem('');
  };
  const handleDelete = (itemToDelete: string) => {
    if (window.confirm(`Supprimer "${itemToDelete}" ?`)) onUpdate(items.filter((i: string) => i !== itemToDelete));
  };
  return (
    <div className="bg-white p-5 rounded-2xl border border-slate-100 shadow-sm flex flex-col h-full min-h-[300px]">
      <h3 className="text-sm font-bold mb-4 text-slate-800 flex items-center justify-between uppercase tracking-wider">{title}</h3>
      <div className="flex-1 space-y-2 mb-4 overflow-y-auto max-h-[200px] pr-1">
        {items.map((item: string) => (
          <div key={item} className="flex items-center justify-between group p-2 bg-slate-50 border border-slate-100 rounded-lg">
            <span className="text-xs font-semibold text-slate-700">{item}</span>
            <button onClick={() => handleDelete(item)} className="p-1 text-slate-400 hover:text-red-500 opacity-0 group-hover:opacity-100 transition-all"><Trash2 size={14} /></button>
          </div>
        ))}
      </div>
      <form onSubmit={handleAdd} className="mt-auto">
        <div className="relative">
          <input type="text" value={newItem} onChange={(e) => setNewItem(e.target.value)} placeholder={`Ajouter...`} className="w-full pl-3 pr-10 py-2 bg-white border border-slate-200 rounded-lg focus:ring-2 focus:ring-indigo-500 outline-none transition-all text-xs" />
          <button type="submit" className="absolute right-1 top-1/2 -translate-y-1/2 p-1.5 bg-indigo-600 text-white rounded-md"><Plus size={14} /></button>
        </div>
      </form>
    </div>
  );
};

const EditableBreedsSection = ({ speciesList, breedsMap, onUpdateBreeds }: any) => {
  const [selectedSpecies, setSelectedSpecies] = useState(speciesList[0] || '');
  const [newBreed, setNewBreed] = useState('');
  const currentBreeds = breedsMap[selectedSpecies] || [];
  const handleAdd = (e: React.FormEvent) => {
    e.preventDefault();
    if (!selectedSpecies || !newBreed.trim()) return;
    if (currentBreeds.includes(newBreed.trim())) { alert("Cette race existe déjà."); return; }
    onUpdateBreeds(selectedSpecies, [...currentBreeds, newBreed.trim()]);
    setNewBreed('');
  };
  const handleDelete = (breedToDelete: string) => {
    if (window.confirm(`Supprimer "${breedToDelete}" ?`)) onUpdateBreeds(selectedSpecies, currentBreeds.filter((b: string) => b !== breedToDelete));
  };
  return (
    <div className="bg-white p-8 rounded-3xl border border-slate-100 shadow-sm">
      <div className="flex flex-col md:flex-row md:items-center justify-between gap-6 mb-8">
        <div><h3 className="text-xl font-bold text-slate-800 flex items-center gap-2"><Tags className="text-indigo-600" size={24} /> Gestion des Races</h3></div>
        <div className="flex items-center gap-3 bg-slate-100 p-1.5 rounded-2xl">
          {speciesList.map((sp: string) => (
            <button key={sp} onClick={() => setSelectedSpecies(sp)} className={`px-4 py-2 rounded-xl text-sm font-bold transition-all ${selectedSpecies === sp ? 'bg-white text-indigo-600 shadow-sm' : 'text-slate-500'}`}>{sp}</button>
          ))}
        </div>
      </div>
      <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 xl:grid-cols-4 gap-4">
        {currentBreeds.map((breed: string) => (
          <div key={breed} className="flex items-center justify-between p-4 bg-slate-50 border border-slate-100 rounded-2xl group transition-all">
            <span className="text-sm font-bold text-slate-700">{breed}</span>
            <button onClick={() => handleDelete(breed)} className="p-2 text-slate-300 hover:text-red-500 opacity-0 group-hover:opacity-100 transition-all"><Trash2 size={16} /></button>
          </div>
        ))}
        <form onSubmit={handleAdd} className="relative">
          <input type="text" value={newBreed} disabled={!selectedSpecies} onChange={(e) => setNewBreed(e.target.value)} placeholder={`Ajouter une race...`} className="w-full pl-4 pr-12 py-4 bg-white border-2 border-dashed border-slate-200 rounded-2xl focus:border-indigo-500 outline-none text-sm" />
          <button type="submit" className="absolute right-2 top-1/2 -translate-y-1/2 p-2.5 bg-indigo-600 text-white rounded-xl"><Plus size={20} /></button>
        </form>
      </div>
    </div>
  );
};

export default App;

import { Search, Plus, User, Phone, Mail, MapPin, Calendar, Sparkles, Trash2, Edit3, Camera, History, FileText, ChevronRight } from 'lucide-react';
import { getPetInsight } from '../services/gemini';
import React, { useState, useEffect } from 'react';
import { db } from '../services/database';
import { Client, Invoice } from '../types';

// Fallback ID generator for robustness
const generateId = () => {
  if (typeof crypto !== 'undefined' && crypto.randomUUID) return crypto.randomUUID();
  return Math.random().toString(36).substring(2, 15) + Date.now().toString(36);
};

const ClientList: React.FC<{ initialClientId?: string | null }> = ({ initialClientId }) => {
  const [clients, setClients] = useState<Client[]>([]);
  const [search, setSearch] = useState('');
  const [selectedClient, setSelectedClient] = useState<Client | null>(null);
  const [isEditing, setIsEditing] = useState(false);
  const [aiInsight, setAiInsight] = useState<string | null>(null);
  const [loadingAi, setLoadingAi] = useState(false);
  const [clientInvoices, setClientInvoices] = useState<Invoice[]>([]);

  const [formSpecies, setFormSpecies] = useState<string>('');

  const config = db.getConfig();

  useEffect(() => {
    const loaded = db.getClients();
    setClients(loaded);
    if (initialClientId) {
      const found = loaded.find(c => c.id === initialClientId);
      if (found) {
        setSelectedClient(found);
        setFormSpecies(found.species);
        loadHistory(found.id);
      }
    }
  }, [initialClientId]);

  const loadHistory = (clientId: string) => {
    const allInvoices = db.getInvoices();
    const filtered = allInvoices.filter(inv => inv.clientId === clientId).slice().reverse();
    setClientInvoices(filtered);
  };

  const filteredClients = clients.filter(c => 
    c.name.toLowerCase().includes(search.toLowerCase()) || 
    c.ownerName.toLowerCase().includes(search.toLowerCase())
  );

  const handleSave = (e: React.FormEvent<HTMLFormElement>) => {
    e.preventDefault();
    const formData = new FormData(e.currentTarget);
    const updated: Client = {
      id: selectedClient?.id || generateId(),
      name: formData.get('name') as string,
      species: formData.get('species') as string,
      breed: formData.get('breed') as string,
      coatType: formData.get('coatType') as string,
      birthDate: formData.get('birthDate') as string,
      ownerName: formData.get('ownerName') as string,
      phone: formData.get('phone') as string,
      email: formData.get('email') as string,
      address: formData.get('address') as string,
      notes: formData.get('notes') as string,
      particularities: Array.from(formData.getAll('particularities')) as string[],
      createdAt: selectedClient?.createdAt || new Date().toISOString(),
      photoProfile: selectedClient?.photoProfile || `https://picsum.photos/seed/${Math.random()}/300/300`
    };

    db.saveClient(updated);
    setClients(db.getClients());
    setSelectedClient(updated);
    setIsEditing(false);
  };

  const loadAiAdvice = async (client: Client) => {
    setLoadingAi(true);
    const insight = await getPetInsight(client);
    setAiInsight(insight);
    setLoadingAi(false);
  };

  const handleSpeciesChange = (e: React.ChangeEvent<HTMLSelectElement>) => {
    setFormSpecies(e.target.value);
  };

  return (
    <div className="flex flex-col lg:flex-row gap-8 h-[calc(100vh-140px)]">
      <div className="w-full lg:w-96 flex flex-col gap-4 bg-white p-4 rounded-2xl shadow-sm border border-slate-100 overflow-hidden">
        <div className="flex gap-2">
          <div className="relative flex-1">
            <Search className="absolute left-3 top-1/2 -translate-y-1/2 text-slate-400" size={18} />
            <input 
              type="text" 
              placeholder="Rechercher..." 
              className="w-full pl-10 pr-4 py-2 bg-slate-50 border-none rounded-xl focus:ring-2 focus:ring-indigo-500 text-sm"
              value={search}
              onChange={e => setSearch(e.target.value)}
            />
          </div>
          <button 
            onClick={() => { 
              setSelectedClient(null); 
              setIsEditing(true); 
              setAiInsight(null);
              setFormSpecies('');
              setClientInvoices([]);
            }}
            className="p-2 bg-indigo-600 text-white rounded-xl hover:bg-indigo-700 transition-colors shadow-md shadow-indigo-200"
          >
            <Plus size={20} />
          </button>
        </div>

        <div className="flex-1 overflow-y-auto space-y-2 pr-2">
          {filteredClients.map(client => (
            <button
              key={client.id}
              onClick={() => { 
                setSelectedClient(client); 
                setIsEditing(false); 
                setAiInsight(null);
                setFormSpecies(client.species);
                loadHistory(client.id);
              }}
              className={`w-full text-left p-4 rounded-xl transition-all ${
                selectedClient?.id === client.id 
                ? 'bg-indigo-50 border-l-4 border-indigo-600 ring-1 ring-indigo-100' 
                : 'hover:bg-slate-50 border-l-4 border-transparent'
              }`}
            >
              <div className="flex justify-between items-start">
                <div>
                  <h4 className="font-bold text-slate-800">{client.name}</h4>
                  <p className="text-xs text-slate-500 font-medium">{client.ownerName}</p>
                </div>
                <span className="text-[10px] px-2 py-1 bg-slate-100 rounded-full font-bold uppercase text-slate-600">
                  {client.species}
                </span>
              </div>
            </button>
          ))}
        </div>
      </div>

      <div className="flex-1 bg-white rounded-2xl shadow-sm border border-slate-100 overflow-y-auto overflow-x-hidden">
        {isEditing ? (
          <form onSubmit={handleSave} className="p-8 space-y-8 animate-in slide-in-from-right duration-300">
            <h2 className="text-2xl font-bold text-slate-800">{selectedClient ? 'Modifier le client' : 'Nouveau client'}</h2>

            <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
              <div className="space-y-4">
                <h3 className="text-sm font-bold text-indigo-600 uppercase tracking-wider">Informations Animal</h3>
                <InputField label="Nom de l'animal" name="name" defaultValue={selectedClient?.name} required />
                <div className="grid grid-cols-2 gap-4">
                  <SelectField label="Espèce" name="species" options={config.species} defaultValue={selectedClient?.species} onChange={handleSpeciesChange} required />
                  <SelectField label="Race" name="breed" options={config.breeds[formSpecies] || []} defaultValue={selectedClient?.breed} required />
                </div>
                <SelectField label="Type de poil" name="coatType" options={config.coatTypes} defaultValue={selectedClient?.coatType} />
                <InputField label="Date de naissance" name="birthDate" type="date" defaultValue={selectedClient?.birthDate} />
              </div>

              <div className="space-y-4">
                <h3 className="text-sm font-bold text-indigo-600 uppercase tracking-wider">Informations Propriétaire</h3>
                <InputField label="Nom complet" name="ownerName" defaultValue={selectedClient?.ownerName} required />
                <InputField label="Téléphone" name="phone" defaultValue={selectedClient?.phone} required />
                <InputField label="Email" name="email" type="email" defaultValue={selectedClient?.email} />
                <TextAreaField label="Adresse" name="address" defaultValue={selectedClient?.address} />
              </div>
            </div>

            <div className="space-y-4">
              <h3 className="text-sm font-bold text-indigo-600 uppercase tracking-wider">Particularités & Notes Fixes</h3>
              <div className="flex flex-wrap gap-3">
                {config.particularities.map(p => (
                  <label key={p} className="flex items-center gap-2 px-3 py-2 bg-slate-50 rounded-lg cursor-pointer hover:bg-indigo-50 transition-colors">
                    <input type="checkbox" name="particularities" value={p} defaultChecked={selectedClient?.particularities.includes(p)} className="rounded text-indigo-600" />
                    <span className="text-sm text-slate-700">{p}</span>
                  </label>
                ))}
              </div>
              <TextAreaField label="Notes de base (tempérament général)" name="notes" defaultValue={selectedClient?.notes} rows={4} />
            </div>

            <div className="flex gap-4 pt-4 border-t">
              <button type="submit" className="px-8 py-3 bg-indigo-600 text-white rounded-xl font-bold hover:bg-indigo-700 transition-all shadow-lg shadow-indigo-100">
                Enregistrer
              </button>
              <button type="button" onClick={() => setIsEditing(false)} className="px-8 py-3 bg-slate-100 text-slate-700 rounded-xl font-bold hover:bg-slate-200">
                Annuler
              </button>
            </div>
          </form>
        ) : selectedClient ? (
          <div className="p-8 space-y-12 animate-in zoom-in-95 duration-200">
            <div className="flex items-start justify-between">
              <div className="flex items-center gap-6">
                <div className="w-24 h-24 rounded-3xl bg-indigo-50 flex items-center justify-center relative group overflow-hidden shadow-inner">
                  {selectedClient.photoProfile ? (
                    <img src={selectedClient.photoProfile} className="w-full h-full object-cover" alt="" />
                  ) : (
                    <PawIcon className="w-12 h-12 text-indigo-300" />
                  )}
                  <div className="absolute inset-0 bg-black/40 opacity-0 group-hover:opacity-100 flex items-center justify-center transition-opacity cursor-pointer">
                    <Camera size={24} className="text-white" />
                  </div>
                </div>
                <div>
                  <h2 className="text-3xl font-black text-slate-800 tracking-tight">{selectedClient.name}</h2>
                  <div className="flex items-center gap-3 mt-1">
                    <span className="px-3 py-1 bg-indigo-100 text-indigo-700 text-xs font-bold rounded-full">{selectedClient.species}</span>
                    <span className="text-slate-400 font-medium">•</span>
                    <span className="text-slate-500 text-sm font-semibold">{selectedClient.breed}</span>
                  </div>
                </div>
              </div>
              <div className="flex gap-2">
                <button onClick={() => setIsEditing(true)} className="p-2.5 bg-slate-100 text-slate-600 rounded-xl hover:bg-indigo-50 hover:text-indigo-600 transition-colors">
                  <Edit3 size={20} />
                </button>
                <button 
                  onClick={() => {
                    if(window.confirm("Supprimer définitivement ce client ?")) {
                      db.deleteClient(selectedClient.id);
                      setClients(db.getClients());
                      setSelectedClient(null);
                    }
                  }}
                  className="p-2.5 bg-slate-100 text-slate-600 rounded-xl hover:bg-red-50 hover:text-red-600 transition-colors"
                >
                  <Trash2 size={20} />
                </button>
              </div>
            </div>

            <div className="grid grid-cols-1 lg:grid-cols-2 gap-12">
              <div className="space-y-8">
                <div>
                  <h3 className="text-sm font-bold text-slate-400 uppercase tracking-widest border-b pb-2 mb-4">Propriétaire</h3>
                  <div className="space-y-4">
                    <InfoItem icon={<User size={18} />} label="Nom" value={selectedClient.ownerName} />
                    <InfoItem icon={<Phone size={18} />} label="Tel" value={selectedClient.phone} />
                    <InfoItem icon={<Mail size={18} />} label="Email" value={selectedClient.email || "Non renseigné"} />
                    <InfoItem icon={<MapPin size={18} />} label="Adresse" value={selectedClient.address || "Non renseignée"} />
                  </div>
                </div>

                <div>
                   <h3 className="text-sm font-bold text-slate-400 uppercase tracking-widest border-b pb-2 mb-4">Caractéristiques</h3>
                   <div className="space-y-6">
                      <div>
                        <p className="text-xs font-bold text-slate-400 mb-2 uppercase">Particularités</p>
                        <div className="flex flex-wrap gap-2">
                          {selectedClient.particularities.length > 0 ? selectedClient.particularities.map(p => (
                            <span key={p} className="px-3 py-1 bg-amber-50 text-amber-700 border border-amber-100 rounded-lg text-xs font-bold">{p}</span>
                          )) : <span className="text-sm text-slate-400 italic">Aucune</span>}
                        </div>
                      </div>
                      <div>
                        <p className="text-xs font-bold text-slate-400 mb-2 uppercase">Notes Générales</p>
                        <p className="text-slate-600 text-sm leading-relaxed bg-slate-50 p-4 rounded-xl border border-slate-100 italic">
                          {selectedClient.notes || "Pas de notes de base."}
                        </p>
                      </div>
                   </div>
                </div>
              </div>

              <div className="space-y-6">
                <h3 className="text-sm font-bold text-indigo-600 uppercase tracking-widest border-b border-indigo-100 pb-2 flex items-center gap-2">
                  <History size={18} />
                  Historique des Visites
                </h3>
                <div className="space-y-4 overflow-y-auto max-h-[500px] pr-2">
                  {clientInvoices.length > 0 ? clientInvoices.map((inv, idx) => (
                    <div key={inv.id} className="relative pl-8 pb-4">
                      {idx !== clientInvoices.length - 1 && <div className="absolute left-[11px] top-6 bottom-0 w-0.5 bg-slate-100"></div>}
                      <div className="absolute left-0 top-1 w-6 h-6 rounded-full bg-indigo-50 border-2 border-indigo-600 flex items-center justify-center z-10">
                        <div className="w-2 h-2 rounded-full bg-indigo-600"></div>
                      </div>
                      <div className="bg-white p-4 rounded-2xl border border-slate-100 hover:border-indigo-100 transition-all shadow-sm">
                        <div className="flex justify-between items-start mb-2">
                          <div>
                            <p className="text-xs font-bold text-slate-400 uppercase">{new Date(inv.date).toLocaleDateString('fr-FR', { day: 'numeric', month: 'long', year: 'numeric' })}</p>
                            <p className="text-sm font-bold text-slate-800">{inv.number}</p>
                          </div>
                          <p className="text-sm font-black text-indigo-600">{inv.amount}€</p>
                        </div>
                        {inv.notes ? (
                          <div className="mt-3 p-3 bg-slate-50 rounded-xl border-l-4 border-indigo-400">
                            <p className="text-xs text-slate-600 leading-relaxed italic">"{inv.notes}"</p>
                          </div>
                        ) : (
                          <p className="text-xs text-slate-300 italic mt-2">Aucun commentaire enregistré.</p>
                        )}
                      </div>
                    </div>
                  )) : (
                    <div className="text-center py-12 text-slate-300">
                      <FileText size={48} className="mx-auto opacity-10 mb-2" />
                      <p className="text-sm italic">Aucune visite enregistrée.</p>
                    </div>
                  )}
                </div>
              </div>
            </div>

            <div className="bg-gradient-to-br from-indigo-600 to-violet-700 rounded-3xl p-8 text-white relative overflow-hidden shadow-xl shadow-indigo-200">
              <div className="absolute top-0 right-0 p-8 opacity-10 pointer-events-none">
                <Sparkles size={120} />
              </div>
              <div className="relative z-10 flex flex-col md:flex-row items-center gap-8">
                <div className="flex-1">
                  <h3 className="text-xl font-bold flex items-center gap-2 mb-2">
                    <Sparkles size={24} /> 
                    Smart Grooming Advice
                  </h3>
                  <p className="text-indigo-100 text-sm mb-4">Analyse par intelligence artificielle des besoins spécifiques de {selectedClient.name}.</p>

                  {aiInsight ? (
                    <div className="bg-white/10 backdrop-blur-md rounded-2xl p-6 border border-white/10 animate-in fade-in slide-in-from-bottom-2 duration-500">
                      <p className="text-lg font-medium leading-relaxed italic">"{aiInsight}"</p>
                    </div>
                  ) : (
                    <button 
                      onClick={() => loadAiAdvice(selectedClient)}
                      disabled={loadingAi}
                      className="px-6 py-3 bg-white text-indigo-600 rounded-xl font-bold hover:bg-indigo-50 transition-colors disabled:opacity-50"
                    >
                      {loadingAi ? 'Analyse en cours...' : 'Générer des conseils IA'}
                    </button>
                  )}
                </div>
              </div>
            </div>
          </div>
        ) : (
          <div className="h-full flex flex-col items-center justify-center text-slate-400 space-y-4">
            <User size={80} className="opacity-20" />
            <p className="font-medium">Sélectionnez un client pour voir les détails et son historique</p>
          </div>
        )}
      </div>
    </div>
  );
};

