import React, { useState, useEffect } from 'react';
import Layout from './components/Layout';
import Dashboard from './views/Dashboard';
import ClientList from './views/ClientList';
import Planning from './views/Planning';
import InvoicePDF from './components/InvoicePDF';
import { db } from './services/database';
import { Plus, Trash2, X, ChevronRight, Tags, Printer, FileText, Download, Upload, AlertTriangle, CheckCircle } from 'lucide-react';
import { Configuration, Invoice, Client } from './types';

const App: React.FC = () => {
  const [activeTab, setActiveTab] = useState('dashboard');
  const [selectedClientId, setSelectedClientId] = useState<string | null>(null);
  const [config, setConfig] = useState<Configuration>(db.getConfig());
  const [printingInvoice, setPrintingInvoice] = useState<{inv: Invoice, cli?: Client} | null>(null);

  const navigateToClient = (id: string) => {
    setSelectedClientId(id);
    setActiveTab('clients');
  };

  const updateConfig = (category: keyof Configuration, newItems: string[]) => {
    db.updateConfigItems(category, newItems);
    setConfig(db.getConfig());
  };

  const updateBreeds = (species: string, breeds: string[]) => {
    db.updateBreeds(species, breeds);
    setConfig(db.getConfig());
  };

  const handlePrint = (invoice: Invoice) => {
    const clients = db.getClients();
    const client = clients.find(c => c.id === invoice.clientId);
    setPrintingInvoice({ inv: invoice, cli: client });
  };

  const handleImportFile = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) {
      console.log("Aucun fichier sélectionné");
      return;
    }

    console.log("Lecture du fichier :", file.name);
    const reader = new FileReader();

    reader.onload = (event) => {
      try {
        const content = event.target?.result as string;
        if (!content) throw new Error("Le fichier est vide.");

        const json = JSON.parse(content);
        console.log("Données parsées avec succès", Object.keys(json));

        const hasData = json && (json.clients || json.appointments || json.invoices || json.config);

        if (!hasData) {
          alert("ERREUR : Le fichier ne contient pas les données attendues par l'application.");
          return;
        }

        if (window.confirm("CONFIRMATION REQUISE :\n\nL'importation va supprimer TOUTES vos données actuelles pour les remplacer par celles du fichier.\n\nSouhaitez-vous continuer ?")) {
          db.importFullData(json);
          alert("Importation réussie !\nL'application va maintenant redémarrer pour appliquer les changements.");
          window.location.reload();
        }
      } catch (err) {
        console.error("Erreur durant l'import :", err);
        alert("ERREUR D'IMPORTATION :\nLe fichier est corrompu ou n'est pas au format JSON valide.");
      }
    };

    reader.onerror = (err) => {
      console.error("Erreur FileReader :", err);
      alert("Erreur technique lors de la lecture physique du fichier.");
    };

    reader.readAsText(file);
    // On réinitialise l'input pour permettre de sélectionner le même fichier à nouveau si besoin
    e.target.value = '';
  };

  const renderContent = () => {
    switch (activeTab) {
      case 'dashboard': return <Dashboard onNavigateToClient={navigateToClient} />;
      case 'clients': return <ClientList initialClientId={selectedClientId} />;
      case 'planning': return <Planning onPrintInvoice={handlePrint} />;
      case 'invoices': return (
        <div className="bg-white p-4 sm:p-8 rounded-2xl border border-slate-100 overflow-hidden">
          <h2 className="text-2xl font-bold mb-6 text-slate-800">Journal des Factures</h2>
          <div className="overflow-x-auto">
            <table className="w-full min-w-[600px]">
              <thead>
                <tr className="text-left text-xs font-bold text-slate-400 uppercase tracking-wider border-b">
                  <th className="pb-4">N° Facture</th>
                  <th className="pb-4">Date</th>
                  <th className="pb-4">Client</th>
                  <th className="pb-4 text-right">Montant</th>
                  <th className="pb-4 text-center">Règlement</th>
                  <th className="pb-4 text-center no-print">Actions</th>
                </tr>
              </thead>
              <tbody className="divide-y divide-slate-100">
                {db.getInvoices().slice().reverse().map(inv => (
                  <tr key={inv.id} className="text-sm text-slate-600 hover:bg-slate-50 transition-colors">
                    <td className="py-4 font-bold text-slate-800">{inv.number}</td>
                    <td className="py-4">{inv.date}</td>
                    <td className="py-4">{inv.petName} <span className="text-slate-400 text-xs">({inv.ownerName})</span></td>
                    <td className="py-4 font-bold text-indigo-600 text-right">{inv.amount.toFixed(2)}€</td>
                    <td className="py-4 text-center">
                      <span className="px-2 py-1 bg-emerald-50 text-emerald-600 rounded-md text-[10px] font-bold uppercase">{inv.paymentMethod}</span>
                    </td>
                    <td className="py-4 text-center no-print">
                      <button 
                        onClick={() => handlePrint(inv)}
                        className="p-2 text-indigo-600 hover:bg-indigo-50 rounded-lg transition-colors flex items-center justify-center gap-1 mx-auto"
                        title="Imprimer / PDF"
                      >
                        <Printer size={16} />
                        <span className="text-xs font-bold uppercase">PDF</span>
                      </button>
                    </td>
                  </tr>
                ))}
              </tbody>
            </table>
          </div>
          {db.getInvoices().length === 0 && (
            <div className="text-center py-20">
              <p className="text-slate-400 font-medium">Aucune facture émise pour le moment.</p>
            </div>
          )}
        </div>
      );
      case 'config': return (
        <div className="space-y-8 pb-12">
          <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-6">
             <EditableConfigSection title="Espèces" items={config.species} onUpdate={(items) => updateConfig('species', items)} />
             <EditableConfigSection title="Types de Poil" items={config.coatTypes} onUpdate={(items) => updateConfig('coatTypes', items)} />
             <EditableConfigSection title="Particularités" items={config.particularities} onUpdate={(items) => updateConfig('particularities', items)} />
             <EditableConfigSection title="Services" items={config.services} onUpdate={(items) => updateConfig('services', items)} />
          </div>
          <div className="pt-4">
            <EditableBreedsSection speciesList={config.species} breedsMap={config.breeds} onUpdateBreeds={updateBreeds} />
          </div>
        </div>
      );
      case 'backup': return (
        <div className="max-w-4xl mx-auto grid grid-cols-1 md:grid-cols-2 gap-8">
          {/* Export Card */}
          <div className="bg-white p-10 rounded-[2.5rem] border border-slate-100 shadow-xl shadow-slate-200/50 flex flex-col items-center text-center">
            <div className="w-20 h-20 bg-indigo-50 text-indigo-600 rounded-3xl flex items-center justify-center mb-6">
              <Download size={40} />
            </div>
            <h2 className="text-2xl font-black text-slate-800 mb-3">Exporter les données</h2>
            <p className="text-slate-500 text-sm mb-8 leading-relaxed">
              Téléchargez une copie de sécurité de vos clients, rendez-vous et factures.
            </p>
            <button 
              onClick={() => {
                const data = { 
                  clients: db.getClients(), 
                  appointments: db.getAppointments(), 
                  invoices: db.getInvoices(), 
                  config: db.getConfig(),
                  exportDate: new Date().toISOString()
                };
                const blob = new Blob([JSON.stringify(data, null, 2)], { type: 'application/json' });
                const url = URL.createObjectURL(blob);
                const a = document.createElement('a');
                a.href = url;
                a.download = `sauvegarde_kanine_${new Date().toISOString().split('T')[0]}.json`;
                a.click();
                URL.revokeObjectURL(url);
              }}
              className="w-full py-4 bg-indigo-600 text-white rounded-2xl font-bold hover:bg-indigo-700 shadow-lg shadow-indigo-100 transition-all flex items-center justify-center gap-2 group"
            >
              <Download size={20} className="group-hover:-translate-y-1 transition-transform" />
              Générer la Sauvegarde
            </button>
          </div>

          {/* Import Card */}
          <div className="bg-white p-10 rounded-[2.5rem] border border-slate-100 shadow-xl shadow-slate-200/50 flex flex-col items-center text-center">
            <div className="w-20 h-20 bg-amber-50 text-amber-600 rounded-3xl flex items-center justify-center mb-6">
              <Upload size={40} />
            </div>
            <h2 className="text-2xl font-black text-slate-800 mb-3">Importer des données</h2>
            <p className="text-slate-500 text-sm mb-8 leading-relaxed">
              Restaurez vos données à partir d'un fichier .json précédemment exporté.
            </p>

            <div className="w-full relative">
              <input 
                type="file" 
                accept=".json"
                onChange={handleImportFile}
                className="absolute inset-0 w-full h-full opacity-0 cursor-pointer z-10"
              />
              <div className="w-full py-4 bg-amber-50 border-2 border-dashed border-amber-200 text-amber-700 rounded-2xl font-bold hover:bg-amber-100 transition-all flex items-center justify-center gap-2">
                <Upload size={20} />
                Sélectionner un fichier .json
              </div>
            </div>

            <div className="mt-6 flex items-start gap-2 p-4 bg-red-50 rounded-2xl text-left">
              <AlertTriangle className="text-red-500 shrink-0" size={16} />
              <p className="text-[11px] font-bold text-red-600 uppercase leading-tight">
                Attention : Cette opération efface les données actuelles.
              </p>
            </div>
          </div>
        </div>
      );
      default: return <div className="p-8">Section en construction...</div>;
    }
  };

  return (
    <Layout activeTab={activeTab} setActiveTab={(t) => { setSelectedClientId(null); setActiveTab(t); }}>
      {renderContent()}

      {/* Overlay de Prévisualisation PDF et Impression */}
      {printingInvoice && (
        <div className="fixed inset-0 z-[100] bg-slate-900/80 backdrop-blur-md flex flex-col items-center justify-start overflow-y-auto pt-8 pb-20 no-print">
           <div className="w-full max-w-[21cm] mb-6 flex justify-between items-center px-4 md:px-0">
              <button 
                onClick={() => setPrintingInvoice(null)}
                className="px-6 py-3 bg-white/10 text-white rounded-xl font-bold hover:bg-white/20 transition-all flex items-center gap-2"
              >
                <X size={20} /> Fermer
              </button>
              <button 
                onClick={() => window.print()}
                className="px-8 py-4 bg-emerald-500 text-white rounded-xl font-black hover:bg-emerald-600 shadow-xl shadow-emerald-500/20 transition-all flex items-center gap-3 animate-bounce"
              >
                <Printer size={24} /> LANCER L'IMPRESSION
              </button>
           </div>
           <div className="bg-white rounded-lg shadow-2xl">
              <InvoicePDF invoice={printingInvoice.inv} client={printingInvoice.cli} />
           </div>
           <div className="mt-8 text-white/40 text-sm italic">
             Appuyez sur "Lancer l'impression" puis choisissez "Enregistrer au format PDF" dans votre navigateur.
           </div>
        </div>
      )}

      {/* Rendu masqué pour l'impression réelle (le navigateur voit ça lors de window.print()) */}
      {printingInvoice && (
        <div className="hidden print:block">
           <InvoicePDF invoice={printingInvoice.inv} client={printingInvoice.cli} />
        </div>
      )}
    </Layout>
  );
};

const EditableConfigSection = ({ title, items, onUpdate }: any) => {
  const [newItem, setNewItem] = useState('');
  const handleAdd = (e: React.FormEvent) => {
    e.preventDefault();
    if (!newItem.trim()) return;
    if (items.includes(newItem.trim())) { alert("Cet élément existe déjà."); return; }
    onUpdate([...items, newItem.trim()]);
    setNewItem('');
  };
  const handleDelete = (itemToDelete: string) => {
    if (window.confirm(`Supprimer "${itemToDelete}" ?`)) onUpdate(items.filter((i: string) => i !== itemToDelete));
  };
  return (
    <div className="bg-white p-5 rounded-2xl border border-slate-100 shadow-sm flex flex-col h-full min-h-[300px]">
      <h3 className="text-sm font-bold mb-4 text-slate-800 flex items-center justify-between uppercase tracking-wider">{title}</h3>
      <div className="flex-1 space-y-2 mb-4 overflow-y-auto max-h-[200px] pr-1">
        {items.map((item: string) => (
          <div key={item} className="flex items-center justify-between group p-2 bg-slate-50 border border-slate-100 rounded-lg">
            <span className="text-xs font-semibold text-slate-700">{item}</span>
            <button onClick={() => handleDelete(item)} className="p-1 text-slate-400 hover:text-red-500 opacity-0 group-hover:opacity-100 transition-all"><Trash2 size={14} /></button>
          </div>
        ))}
      </div>
      <form onSubmit={handleAdd} className="mt-auto">
        <div className="relative">
          <input type="text" value={newItem} onChange={(e) => setNewItem(e.target.value)} placeholder={`Ajouter...`} className="w-full pl-3 pr-10 py-2 bg-white border border-slate-200 rounded-lg focus:ring-2 focus:ring-indigo-500 outline-none transition-all text-xs" />
          <button type="submit" className="absolute right-1 top-1/2 -translate-y-1/2 p-1.5 bg-indigo-600 text-white rounded-md"><Plus size={14} /></button>
        </div>
      </form>
    </div>
  );
};

const EditableBreedsSection = ({ speciesList, breedsMap, onUpdateBreeds }: any) => {
  const [selectedSpecies, setSelectedSpecies] = useState(speciesList[0] || '');
  const [newBreed, setNewBreed] = useState('');
  const currentBreeds = breedsMap[selectedSpecies] || [];
  const handleAdd = (e: React.FormEvent) => {
    e.preventDefault();
    if (!selectedSpecies || !newBreed.trim()) return;
    if (currentBreeds.includes(newBreed.trim())) { alert("Cette race existe déjà."); return; }
    onUpdateBreeds(selectedSpecies, [...currentBreeds, newBreed.trim()]);
    setNewBreed('');
  };
  const handleDelete = (breedToDelete: string) => {
    if (window.confirm(`Supprimer "${breedToDelete}" ?`)) onUpdateBreeds(selectedSpecies, currentBreeds.filter((b: string) => b !== breedToDelete));
  };
  return (
    <div className="bg-white p-8 rounded-3xl border border-slate-100 shadow-sm">
      <div className="flex flex-col md:flex-row md:items-center justify-between gap-6 mb-8">
        <div><h3 className="text-xl font-bold text-slate-800 flex items-center gap-2"><Tags className="text-indigo-600" size={24} /> Gestion des Races</h3></div>
        <div className="flex items-center gap-3 bg-slate-100 p-1.5 rounded-2xl">
          {speciesList.map((sp: string) => (
            <button key={sp} onClick={() => setSelectedSpecies(sp)} className={`px-4 py-2 rounded-xl text-sm font-bold transition-all ${selectedSpecies === sp ? 'bg-white text-indigo-600 shadow-sm' : 'text-slate-500'}`}>{sp}</button>
          ))}
        </div>
      </div>
      <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 xl:grid-cols-4 gap-4">
        {currentBreeds.map((breed: string) => (
          <div key={breed} className="flex items-center justify-between p-4 bg-slate-50 border border-slate-100 rounded-2xl group transition-all">
            <span className="text-sm font-bold text-slate-700">{breed}</span>
            <button onClick={() => handleDelete(breed)} className="p-2 text-slate-300 hover:text-red-500 opacity-0 group-hover:opacity-100 transition-all"><Trash2 size={16} /></button>
          </div>
        ))}
        <form onSubmit={handleAdd} className="relative">
          <input type="text" value={newBreed} disabled={!selectedSpecies} onChange={(e) => setNewBreed(e.target.value)} placeholder={`Ajouter une race...`} className="w-full pl-4 pr-12 py-4 bg-white border-2 border-dashed border-slate-200 rounded-2xl focus:border-indigo-500 outline-none text-sm" />
          <button type="submit" className="absolute right-2 top-1/2 -translate-y-1/2 p-2.5 bg-indigo-600 text-white rounded-xl"><Plus size={20} /></button>
        </form>
      </div>
    </div>
  );
};

export default App;

import { Client, Appointment, Invoice, Configuration } from '../types';
import { INITIAL_CONFIG } from '../constants';

const KEYS = {
  CLIENTS: 'groom_clients',
  APPOINTMENTS: 'groom_appointments',
  INVOICES: 'groom_invoices',
  CONFIG: 'groom_config'
};

export const db = {
  // Config
  getConfig: (): Configuration => {
    const data = localStorage.getItem(KEYS.CONFIG);
    const config = data ? JSON.parse(data) : INITIAL_CONFIG;
    if (!config.breeds) config.breeds = INITIAL_CONFIG.breeds;
    return config;
  },
  saveConfig: (config: Configuration) => localStorage.setItem(KEYS.CONFIG, JSON.stringify(config)),

  updateConfigItems: (category: keyof Configuration, items: string[]) => {
    const config = db.getConfig();
    if (Array.isArray(config[category])) {
      (config[category] as any) = items;
      db.saveConfig(config);
    }
  },

  updateBreeds: (species: string, breeds: string[]) => {
    const config = db.getConfig();
    if (!config.breeds) config.breeds = {};
    config.breeds[species] = breeds;
    db.saveConfig(config);
  },

  // Clients
  getClients: (): Client[] => {
    const data = localStorage.getItem(KEYS.CLIENTS);
    return data ? JSON.parse(data) : [];
  },
  saveClient: (client: Client) => {
    const clients = db.getClients();
    const index = clients.findIndex(c => c.id === client.id);
    if (index >= 0) clients[index] = client;
    else clients.push(client);
    localStorage.setItem(KEYS.CLIENTS, JSON.stringify(clients));
  },
  deleteClient: (id: string) => {
    const clients = db.getClients().filter(c => c.id !== id);
    localStorage.setItem(KEYS.CLIENTS, JSON.stringify(clients));
  },

  // Appointments
  getAppointments: (): Appointment[] => {
    const data = localStorage.getItem(KEYS.APPOINTMENTS);
    return data ? JSON.parse(data) : [];
  },
  saveAppointment: (appt: Appointment) => {
    const appts = db.getAppointments();
    const index = appts.findIndex(a => a.id === appt.id);
    if (index >= 0) appts[index] = appt;
    else appts.push(appt);
    localStorage.setItem(KEYS.APPOINTMENTS, JSON.stringify(appts));
  },
  deleteAppointment: (id: string) => {
    const appts = db.getAppointments().filter(a => a.id !== id);
    localStorage.setItem(KEYS.APPOINTMENTS, JSON.stringify(appts));
  },

  // Invoices
  getInvoices: (): Invoice[] => {
    const data = localStorage.getItem(KEYS.INVOICES);
    return data ? JSON.parse(data) : [];
  },
  saveInvoice: (invoice: Invoice) => {
    const invoices = db.getInvoices();
    invoices.push(invoice);
    localStorage.setItem(KEYS.INVOICES, JSON.stringify(invoices));
  },

  // Global Data Management - Robust version
  importFullData: (data: any) => {
    try {
      if (data.clients && Array.isArray(data.clients)) {
        localStorage.setItem(KEYS.CLIENTS, JSON.stringify(data.clients));
      }
      if (data.appointments && Array.isArray(data.appointments)) {
        localStorage.setItem(KEYS.APPOINTMENTS, JSON.stringify(data.appointments));
      }
      if (data.invoices && Array.isArray(data.invoices)) {
        localStorage.setItem(KEYS.INVOICES, JSON.stringify(data.invoices));
      }
      if (data.config) {
        localStorage.setItem(KEYS.CONFIG, JSON.stringify(data.config));
      }
      return true;
    } catch (e) {
      console.error("Database import error:", e);
      return false;
    }
  }
};

