import React, { useState, useEffect } from 'react';
import { db } from '../services/database';
import { Appointment, Client, Invoice } from '../types';
import { 
  Calendar as CalendarIcon, 
  Clock, 
  ChevronLeft, 
  ChevronRight, 
  FileText, 
  CheckCircle2, 
  Trash2, 
  Plus, 
  Euro, 
  MessageSquare, 
  Printer,
  ChevronDown
} from 'lucide-react';

const generateId = () => Math.random().toString(36).substring(2, 15) + Date.now().toString(36);

interface PlanningProps {
  onPrintInvoice?: (invoice: Invoice) => void;
}

const Planning: React.FC<PlanningProps> = ({ onPrintInvoice }) => {
  const [view, setView] = useState<'day' | 'month'>('month');
  const [currentDate, setCurrentDate] = useState(new Date());
  const [appointments, setAppointments] = useState<Appointment[]>([]);
  const [clients, setClients] = useState<Client[]>([]);
  const [isModalOpen, setIsModalOpen] = useState(false);
  const [isInvoiceModalOpen, setIsInvoiceModalOpen] = useState(false);
  const [selectedAppt, setSelectedAppt] = useState<Appointment | null>(null);
  const [invoiceAmount, setInvoiceAmount] = useState('50');
  const [invoiceNotes, setInvoiceNotes] = useState('');
  const [paymentMethod, setPaymentMethod] = useState<Invoice['paymentMethod']>('Carte');

  const config = db.getConfig();

  const refreshData = () => {
    setAppointments(db.getAppointments());
    setClients(db.getClients());
  };

  useEffect(() => {
    refreshData();
  }, []);

  const formatDate = (date: Date) => date.toISOString().split('T')[0];
  const dateStr = formatDate(currentDate);

  const dailyAppts = appointments
    .filter(a => a.date === dateStr)
    .sort((a, b) => a.time.localeCompare(b.time));

  // Calendar Logic
  const getDaysInMonth = (date: Date) => {
    const year = date.getFullYear();
    const month = date.getMonth();
    const firstDay = new Date(year, month, 1).getDay(); // 0 = Dimanche
    const adjustedFirstDay = firstDay === 0 ? 6 : firstDay - 1; // 0 = Lundi
    const daysInMonth = new Date(year, month + 1, 0).getDate();
    return { adjustedFirstDay, daysInMonth };
  };

  const { adjustedFirstDay, daysInMonth } = getDaysInMonth(currentDate);
  const prevMonthDays = new Date(currentDate.getFullYear(), currentDate.getMonth(), 0).getDate();

  const handleDayClick = (day: number) => {
    const newDate = new Date(currentDate.getFullYear(), currentDate.getMonth(), day);
    setCurrentDate(newDate);
    setView('day');
  };

  const handleSaveAppt = (e: React.FormEvent<HTMLFormElement>) => {
    e.preventDefault();
    const formData = new FormData(e.currentTarget);
    const clientSelect = formData.get('client') as string;

    if (!clientSelect) return alert("Sélectionnez un client");

    const [petName, ownerName] = clientSelect.split(' - ');
    const client = clients.find(c => c.name === petName && c.ownerName === ownerName);

    const newAppt: Appointment = {
      id: selectedAppt?.id || generateId(),
      date: formData.get('date') as string,
      time: formData.get('time') as string,
      clientId: client?.id || '',
      clientName: ownerName,
      petName: petName,
      service: formData.get('service') as string,
      notes: formData.get('notes') as string,
      duration: parseInt(formData.get('duration') as string),
      status: selectedAppt?.status || 'pending'
    };

    db.saveAppointment(newAppt);
    refreshData();
    setIsModalOpen(false);
    setSelectedAppt(null);
  };

  const handleConfirmInvoice = () => {
    if (!selectedAppt) return;
    const amount = parseFloat(invoiceAmount);
    const invoiceNumber = `FAC-${Date.now().toString().slice(-6)}`;
    const newInvoice: Invoice = {
      id: generateId(),
      number: invoiceNumber,
      date: formatDate(new Date()),
      clientId: selectedAppt.clientId,
      petName: selectedAppt.petName,
      ownerName: selectedAppt.clientName,
      amount,
      paymentMethod,
      appointmentId: selectedAppt.id,
      notes: invoiceNotes
    };
    db.saveInvoice(newInvoice);
    db.saveAppointment({ ...selectedAppt, status: 'invoiced' });
    refreshData();
    setIsInvoiceModalOpen(false);
    if(confirm(`Facture émise. Imprimer ?`)) onPrintInvoice?.(newInvoice);
  };

  return (
    <div className="space-y-6 h-full flex flex-col no-print">
      {/* Header Planning */}
      <div className="flex flex-col md:flex-row items-center justify-between gap-4">
        <div className="flex items-center gap-4 bg-white p-1.5 rounded-2xl shadow-sm border border-slate-100">
          <button onClick={() => setView('month')} className={`px-5 py-2 rounded-xl text-sm font-bold transition-all ${view === 'month' ? 'bg-indigo-600 text-white' : 'text-slate-500 hover:bg-slate-50'}`}>Mensuel</button>
          <button onClick={() => setView('day')} className={`px-5 py-2 rounded-xl text-sm font-bold transition-all ${view === 'day' ? 'bg-indigo-600 text-white' : 'text-slate-500 hover:bg-slate-50'}`}>Quotidien</button>
        </div>

        <div className="flex items-center gap-4">
          <button onClick={() => {
            const d = new Date(currentDate);
            view === 'month' ? d.setMonth(d.getMonth() - 1) : d.setDate(d.getDate() - 1);
            setCurrentDate(d);
          }} className="p-2 bg-white rounded-xl border hover:bg-slate-50"><ChevronLeft size={20}/></button>

          <h2 className="text-lg font-black text-slate-800 min-w-[200px] text-center uppercase tracking-tight">
            {currentDate.toLocaleDateString('fr-FR', view === 'month' ? { month: 'long', year: 'numeric' } : { weekday: 'long', day: 'numeric', month: 'long' })}
          </h2>

          <button onClick={() => {
            const d = new Date(currentDate);
            view === 'month' ? d.setMonth(d.getMonth() + 1) : d.setDate(d.getDate() + 1);
            setCurrentDate(d);
          }} className="p-2 bg-white rounded-xl border hover:bg-slate-50"><ChevronRight size={20}/></button>
        </div>

        <button onClick={() => { setSelectedAppt(null); setIsModalOpen(true); }} className="px-6 py-3 bg-indigo-600 text-white rounded-xl font-bold shadow-lg shadow-indigo-100 flex items-center gap-2 hover:bg-indigo-700 transition-all">
          <Plus size={20}/> Nouveau RDV
        </button>
      </div>

      {/* Main View Area */}
      <div className="flex-1 overflow-hidden bg-white rounded-3xl border border-slate-100 shadow-sm flex flex-col">
        {view === 'month' ? (
          <div className="flex-1 flex flex-col overflow-hidden">
            {/* Jours de la semaine */}
            <div className="calendar-grid border-b bg-slate-50/50">
              {['Lun', 'Mar', 'Mer', 'Jeu', 'Ven', 'Sam', 'Dim'].map(d => (
                <div key={d} className="py-3 text-center text-[10px] font-black text-slate-400 uppercase tracking-widest">{d}</div>
              ))}
            </div>
            {/* Grille de dates */}
            <div className="calendar-grid flex-1 overflow-y-auto">
              {/* Padding mois précédent */}
              {Array.from({ length: adjustedFirstDay }).map((_, i) => {
                const dayNum = prevMonthDays - adjustedFirstDay + i + 1;
                return <div key={`prev-${i}`} className="h-32 border-b border-r border-slate-50 p-2 text-slate-300 bg-slate-50/20 text-xs font-bold">{dayNum}</div>;
              })}
              {/* Jours du mois */}
              {Array.from({ length: daysInMonth }).map((_, i) => {
                const day = i + 1;
                const d = new Date(currentDate.getFullYear(), currentDate.getMonth(), day);
                const dStr = formatDate(d);
                const dayAppts = appointments.filter(a => a.date === dStr);
                const isToday = formatDate(new Date()) === dStr;

                return (
                  <div key={day} onClick={() => handleDayClick(day)} className={`h-32 border-b border-r border-slate-50 p-2 cursor-pointer transition-colors relative hover:bg-indigo-50/30 group ${isToday ? 'bg-indigo-50/10' : ''}`}>
                    <span className={`text-xs font-black ${isToday ? 'text-indigo-600 bg-indigo-100 px-2 py-1 rounded-lg' : 'text-slate-400 group-hover:text-indigo-400'}`}>{day}</span>
                    <div className="mt-2 space-y-1 overflow-hidden">
                      {dayAppts.slice(0, 3).map(a => (
                        <div key={a.id} className={`text-[10px] p-1 rounded font-bold truncate ${a.status === 'invoiced' ? 'bg-emerald-100 text-emerald-700' : 'bg-indigo-100 text-indigo-700'}`}>
                          {a.time} {a.petName}
                        </div>
                      ))}
                      {dayAppts.length > 3 && <div className="text-[9px] text-slate-400 font-bold text-center">+{dayAppts.length - 3} autres</div>}
                    </div>
                  </div>
                );
              })}
            </div>
          </div>
        ) : (
          <div className="flex-1 p-8 overflow-y-auto">
            {dailyAppts.length > 0 ? (
              <div className="space-y-4">
                {dailyAppts.map(appt => (
                  <div key={appt.id} className="flex items-center gap-6 p-6 rounded-2xl border border-slate-100 hover:border-indigo-100 hover:bg-indigo-50/20 transition-all group">
                    <div className="w-20 text-center border-r border-slate-100 pr-6">
                      <p className="text-xl font-black text-slate-800">{appt.time}</p>
                      <p className="text-[10px] font-bold text-slate-400 uppercase">{appt.duration}m</p>
                    </div>
                    <div className="flex-1">
                      <div className="flex items-center gap-3">
                        <h4 className="text-lg font-bold text-slate-800">{appt.petName}</h4>
                        <span className="px-2 py-0.5 bg-indigo-50 text-indigo-600 text-[10px] font-black uppercase rounded-md">{appt.service}</span>
                        {appt.status === 'invoiced' && <span className="flex items-center gap-1 text-emerald-600 font-black text-[10px] uppercase bg-emerald-50 px-2 py-0.5 rounded-md"><CheckCircle2 size={12}/> Payé</span>}
                      </div>
                      <p className="text-sm text-slate-500">Client: {appt.clientName}</p>
                    </div>
                    <div className="flex items-center gap-2">
                      {appt.status !== 'invoiced' ? (
                        <button onClick={() => { setSelectedAppt(appt); setIsInvoiceModalOpen(true); }} className="flex items-center gap-2 px-5 py-2.5 bg-emerald-600 text-white rounded-xl text-sm font-black hover:bg-emerald-700 shadow-md">
                          <Euro size={16} /> Facturer
                        </button>
                      ) : (
                        <button onClick={() => {
                          const inv = db.getInvoices().find(i => i.appointmentId === appt.id);
                          if(inv) onPrintInvoice?.(inv);
                        }} className="p-2.5 bg-slate-100 text-slate-600 rounded-xl hover:bg-indigo-100 hover:text-indigo-600 transition-colors">
                          <Printer size={18} />
                        </button>
                      )}
                      <button onClick={() => { if(confirm("Supprimer ?")) { db.deleteAppointment(appt.id); refreshData(); } }} className="p-2.5 text-slate-300 hover:text-red-500 transition-colors"><Trash2 size={20}/></button>
                    </div>
                  </div>
                ))}
              </div>
            ) : (
              <div className="h-full flex flex-col items-center justify-center text-slate-300 py-20">
                <Clock size={64} className="opacity-10 mb-4" />
                <p className="font-bold">Journée libre !</p>
              </div>
            )}
          </div>
        )}
      </div>

      {/* Modal Facturation */}
      {isInvoiceModalOpen && selectedAppt && (
        <div className="fixed inset-0 bg-slate-900/80 backdrop-blur-sm z-[200] flex items-center justify-center p-4">
          <div className="bg-white rounded-[2.5rem] w-full max-w-xl shadow-2xl overflow-hidden animate-in zoom-in-95">
            <div className="bg-indigo-600 p-8 text-white">
              <h3 className="text-2xl font-black">Encaissement</h3>
              <p className="opacity-70 font-medium">{selectedAppt.petName} - {selectedAppt.service}</p>
            </div>
            <div className="p-8 space-y-6">
              <div className="grid grid-cols-2 gap-6">
                <div>
                  <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest mb-2 block">Montant (€)</label>
                  <input autoFocus type="number" value={invoiceAmount} onChange={e => setInvoiceAmount(e.target.value)} className="w-full text-3xl font-black text-slate-800 bg-slate-50 border-none rounded-2xl p-4 focus:ring-4 focus:ring-indigo-100" />
                </div>
                <div>
                  <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest mb-2 block">Mode</label>
                  <select value={paymentMethod} onChange={e => setPaymentMethod(e.target.value as any)} className="w-full p-4 bg-slate-50 rounded-2xl font-bold border-none focus:ring-4 focus:ring-indigo-100">
                    {['Carte', 'Espèces', 'Chèque', 'Virement'].map(m => <option key={m} value={m}>{m}</option>)}
                  </select>
                </div>
              </div>
              <div>
                <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest mb-2 block">Notes de prestation (Sur PDF)</label>
                <textarea value={invoiceNotes} onChange={e => setInvoiceNotes(e.target.value)} rows={3} className="w-full p-4 bg-slate-50 border-none rounded-2xl text-sm resize-none" placeholder="Ex: Chien très calme, tonte 9mm effectuée." />
              </div>
              <div className="flex gap-4">
                <button onClick={handleConfirmInvoice} className="flex-1 py-5 bg-indigo-600 text-white rounded-2xl font-black text-lg hover:bg-indigo-700 shadow-xl transition-all">Valider la Facture</button>
                <button onClick={() => setIsInvoiceModalOpen(false)} className="px-8 py-5 bg-slate-100 text-slate-500 rounded-2xl font-bold">Annuler</button>
              </div>
            </div>
          </div>
        </div>
      )}

      {/* Modal Nouveau RDV */}
      {isModalOpen && (
        <div className="fixed inset-0 bg-slate-900/60 backdrop-blur-sm z-[200] flex items-center justify-center p-4">
          <div className="bg-white rounded-3xl w-full max-w-lg shadow-2xl overflow-hidden animate-in zoom-in-95">
            <div className="p-6 border-b flex justify-between items-center bg-slate-50">
              <h3 className="text-xl font-black text-slate-800">Prise de Rendez-vous</h3>
              <button onClick={() => setIsModalOpen(false)} className="p-2 hover:bg-slate-200 rounded-full transition-colors">✕</button>
            </div>
            <form onSubmit={handleSaveAppt} className="p-8 space-y-6">
              <div className="grid grid-cols-2 gap-4">
                <div className="space-y-1.5">
                  <label className="text-[10px] font-black text-slate-400 uppercase">Date</label>
                  <input type="date" name="date" defaultValue={dateStr} required className="w-full px-4 py-3 bg-slate-50 border border-slate-100 rounded-xl font-bold" />
                </div>
                <div className="space-y-1.5">
                  <label className="text-[10px] font-black text-slate-400 uppercase">Heure</label>
                  <input type="time" name="time" defaultValue="09:00" required className="w-full px-4 py-3 bg-slate-50 border border-slate-100 rounded-xl font-bold" />
                </div>
              </div>
              <div className="space-y-1.5">
                <label className="text-[10px] font-black text-slate-400 uppercase">Client (Animal - Propriétaire)</label>
                <select name="client" required className="w-full px-4 py-3 bg-slate-50 border border-slate-100 rounded-xl font-bold">
                  <option value="">Sélectionner...</option>
                  {clients.map(c => <option key={c.id} value={`${c.name} - ${c.ownerName}`}>{c.name} ({c.ownerName})</option>)}
                </select>
              </div>
              <div className="grid grid-cols-2 gap-4">
                <div className="space-y-1.5">
                  <label className="text-[10px] font-black text-slate-400 uppercase">Soin</label>
                  <select name="service" required className="w-full px-4 py-3 bg-slate-50 border border-slate-100 rounded-xl font-bold">
                    {config.services.map(s => <option key={s} value={s}>{s}</option>)}
                  </select>
                </div>
                <div className="space-y-1.5">
                  <label className="text-[10px] font-black text-slate-400 uppercase">Durée (min)</label>
                  <input type="number" name="duration" defaultValue="60" step="15" className="w-full px-4 py-3 bg-slate-50 border border-slate-100 rounded-xl font-bold" />
                </div>
              </div>
              <button type="submit" className="w-full py-4 bg-indigo-600 text-white rounded-xl font-black shadow-lg shadow-indigo-100">Confirmer le RDV</button>
            </form>
          </div>
        </div>
      )}
    </div>
  );
};

export default Planning;

import React, { useState } from 'react';
import { db } from '../services/database';
import { 
  Users, 
  Calendar as CalendarIcon, 
  Euro, 
  TrendingUp,
  Download,
  FileSpreadsheet
} from 'lucide-react';
import { 
  BarChart, 
  Bar, 
  XAxis, 
  YAxis, 
  CartesianGrid, 
  Tooltip, 
  ResponsiveContainer,
  Cell
} from 'recharts';

const Dashboard: React.FC<{ onNavigateToClient: (id: string) => void }> = ({ onNavigateToClient }) => {
  const clients = db.getClients();
  const appointments = db.getAppointments();
  const invoices = db.getInvoices();

  const [period, setPeriod] = useState<'month' | 'quarter' | 'year'>('month');

  const totalRevenue = invoices.reduce((acc, inv) => acc + inv.amount, 0);

  // Group invoices by month
  const getMonthlyData = () => {
    const months: Record<string, number> = {};
    invoices.forEach(inv => {
      const monthKey = inv.date.substring(0, 7); // YYYY-MM
      months[monthKey] = (months[monthKey] || 0) + inv.amount;
    });
    return Object.entries(months).map(([name, total]) => ({ name, total })).slice(-6);
  };

  const currentYear = new Date().getFullYear();
  const yearlyRevenue = invoices
    .filter(inv => inv.date.startsWith(currentYear.toString()))
    .reduce((acc, inv) => acc + inv.amount, 0);

  const exportFinancials = () => {
    const headers = ["ID", "Facture", "Date", "Animal", "Propriétaire", "Soin", "Montant", "Règlement"];
    const rows = invoices.map(inv => [
      inv.id,
      inv.number,
      inv.date,
      inv.petName,
      inv.ownerName,
      inv.notes || "Soin toilettage",
      inv.amount.toString(),
      inv.paymentMethod
    ]);

    const csvContent = "data:text/csv;charset=utf-8," 
      + [headers, ...rows].map(e => e.join(";")).join("\n");

    const encodedUri = encodeURI(csvContent);
    const link = document.createElement("a");
    link.setAttribute("href", encodedUri);
    link.setAttribute("download", `comptabilite_kanine_${currentYear}.csv`);
    document.body.appendChild(link);
    link.click();
    document.body.removeChild(link);
  };

  return (
    <div className="space-y-8 animate-in fade-in duration-500">
      <div className="flex justify-between items-center">
        <h2 className="text-2xl font-black text-slate-800">Analyse de l'Activité</h2>
        <button onClick={exportFinancials} className="flex items-center gap-2 px-6 py-3 bg-emerald-600 text-white rounded-xl font-bold shadow-lg shadow-emerald-100 hover:bg-emerald-700 transition-all">
          <FileSpreadsheet size={20} /> Exporter Compta (CSV)
        </button>
      </div>

      <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-6">
        <StatCard icon={<Users className="text-indigo-600" />} label="Base Clients" value={clients.length} color="bg-indigo-50" />
        <StatCard icon={<CalendarIcon className="text-purple-600" />} label="RDV prévus" value={appointments.filter(a => a.status === 'pending').length} color="bg-purple-50" />
        <StatCard icon={<Euro className="text-emerald-600" />} label="C.A. Annuel" value={`${yearlyRevenue.toFixed(2)}€`} color="bg-emerald-50" />
        <StatCard icon={<TrendingUp className="text-orange-600" />} label="C.A. Global" value={`${totalRevenue.toFixed(2)}€`} color="bg-orange-50" />
      </div>

      <div className="grid grid-cols-1 lg:grid-cols-3 gap-8">
        <div className="lg:col-span-2 bg-white p-8 rounded-[2.5rem] shadow-sm border border-slate-100">
          <div className="flex justify-between items-center mb-8">
            <h3 className="text-lg font-black text-slate-800 uppercase tracking-tighter">Performance Mensuelle</h3>
            <div className="flex bg-slate-100 p-1 rounded-xl text-[10px] font-black uppercase">
              <button onClick={() => setPeriod('month')} className={`px-3 py-1.5 rounded-lg ${period === 'month' ? 'bg-white shadow-sm' : 'text-slate-400'}`}>Mois</button>
              <button onClick={() => setPeriod('quarter')} className={`px-3 py-1.5 rounded-lg ${period === 'quarter' ? 'bg-white shadow-sm' : 'text-slate-400'}`}>Trimestre</button>
            </div>
          </div>
          <div className="h-80">
            <ResponsiveContainer width="100%" height="100%">
              <BarChart data={getMonthlyData()}>
                <CartesianGrid strokeDasharray="3 3" vertical={false} stroke="#f1f5f9" />
                <XAxis dataKey="name" axisLine={false} tickLine={false} tick={{fill: '#94a3b8', fontSize: 10, fontWeight: 800}} dy={10} />
                <YAxis axisLine={false} tickLine={false} tick={{fill: '#94a3b8', fontSize: 10, fontWeight: 800}} />
                <Tooltip 
                  cursor={{fill: '#f8fafc'}}
                  contentStyle={{ borderRadius: '16px', border: 'none', boxShadow: '0 20px 25px -5px rgb(0 0 0 / 0.1)', padding: '16px' }}
                />
                <Bar dataKey="total" fill="#6366f1" radius={[8, 8, 0, 0]} barSize={50}>
                   {getMonthlyData().map((entry, index) => (
                      <Cell key={`cell-${index}`} fill={index === 5 ? '#4f46e5' : '#e2e8f0'} />
                   ))}
                </Bar>
              </BarChart>
            </ResponsiveContainer>
          </div>
        </div>

        <div className="bg-white p-8 rounded-[2.5rem] shadow-sm border border-slate-100 flex flex-col">
          <h3 className="text-lg font-black text-slate-800 uppercase tracking-tighter mb-6">Répartition Encaissements</h3>
          <div className="space-y-4 flex-1">
             <PaymentSplit label="Carte Bancaire" value={invoices.filter(i => i.paymentMethod === 'Carte').reduce((a,b) => a+b.amount, 0)} color="bg-indigo-500" total={totalRevenue} />
             <PaymentSplit label="Espèces" value={invoices.filter(i => i.paymentMethod === 'Espèces').reduce((a,b) => a+b.amount, 0)} color="bg-emerald-500" total={totalRevenue} />
             <PaymentSplit label="Chèques / Vir." value={invoices.filter(i => ['Chèque', 'Virement'].includes(i.paymentMethod)).reduce((a,b) => a+b.amount, 0)} color="bg-amber-500" total={totalRevenue} />
          </div>
          <div className="mt-8 pt-8 border-t border-slate-50">
             <div className="p-4 bg-slate-50 rounded-2xl">
                <p className="text-[10px] font-black text-slate-400 uppercase mb-1">Rappel fiscal</p>
                <p className="text-xs text-slate-500 font-medium">Seuil de franchise TVA auto-entrepreneur 2024 : 36 800€ (Prestations de service).</p>
             </div>
          </div>
        </div>
      </div>
    </div>
  );
};

const StatCard = ({ icon, label, value, color }: any) => (
  <div className="bg-white p-6 rounded-3xl shadow-sm border border-slate-100 flex items-center gap-4 transition-transform hover:-translate-y-1">
    <div className={`p-4 rounded-2xl ${color}`}>{icon}</div>
    <div>
      <p className="text-[10px] font-black text-slate-400 uppercase tracking-widest leading-tight mb-1">{label}</p>
      <p className="text-2xl font-black text-slate-900 leading-tight">{value}</p>
    </div>
  </div>
);

const PaymentSplit = ({ label, value, color, total }: any) => {
  const pct = total > 0 ? (value / total) * 100 : 0;
  return (
    <div className="space-y-2">
      <div className="flex justify-between text-xs font-black uppercase tracking-tighter">
        <span className="text-slate-500">{label}</span>
        <span className="text-slate-900">{value.toFixed(2)}€</span>
      </div>
      <div className="h-3 bg-slate-100 rounded-full overflow-hidden">
        <div className={`h-full ${color} rounded-full transition-all duration-1000`} style={{ width: `${pct}%` }}></div>
      </div>
    </div>
  );
};

export default Dashboard;

