} from 'lucide-react';

const generateId = () => Math.random().toString(36).substring(2, 15) + Date.now().toString(36);

interface PlanningProps {
  onPrintInvoice?: (invoice: Invoice) => void;
}

const Planning: React.FC<PlanningProps> = ({ onPrintInvoice }) => {
  const [view, setView] = useState<'day' | 'month' | 'upcoming'>('month');
  const [currentDate, setCurrentDate] = useState(new Date());
  const [appointments, setAppointments] = useState<Appointment[]>([]);
  const [clients, setClients] = useState<Client[]>([]);
  const [isModalOpen, setIsModalOpen] = useState(false);
  const [isInvoiceModalOpen, setIsInvoiceModalOpen] = useState(false);
  const [selectedAppt, setSelectedAppt] = useState<Appointment | null>(null);

  const [invoiceAmount, setInvoiceAmount] = useState('50');
  const [invoiceNotes, setInvoiceNotes] = useState('');
  const [paymentMethod, setPaymentMethod] = useState<Invoice['paymentMethod']>('Carte');

  const config = db.getConfig();

  const refreshData = () => {
    setAppointments(db.getAppointments());
    setClients(db.getClients());
  };

  useEffect(() => {
    refreshData();
  }, []);

  const formatDate = (date: Date) => date.toISOString().split('T')[0];
  const dateStr = formatDate(currentDate);

  const dailyAppts = appointments
    .filter(a => a.date === dateStr)
    .sort((a, b) => a.time.localeCompare(b.time));

  const upcomingAppts = appointments
    .filter(a => a.date >= formatDate(new Date()))
    .sort((a, b) => a.date.localeCompare(b.date) || a.time.localeCompare(b.time));

  const getDaysInMonth = (date: Date) => {
    const year = date.getFullYear();
    const month = date.getMonth();
    const firstDay = new Date(year, month, 1).getDay();
    const adjustedFirstDay = firstDay === 0 ? 6 : firstDay - 1;
    const daysInMonth = new Date(year, month + 1, 0).getDate();
    return { adjustedFirstDay, daysInMonth };
  };

  const { adjustedFirstDay, daysInMonth } = getDaysInMonth(currentDate);
  const prevMonthDays = new Date(currentDate.getFullYear(), currentDate.getMonth(), 0).getDate();

  const handleSaveAppt = (e: React.FormEvent<HTMLFormElement>) => {
    e.preventDefault();
    const formData = new FormData(e.currentTarget);
    const clientSelect = formData.get('client') as string;
    if (!clientSelect) return;
    const [petName, ownerName] = clientSelect.split(' - ');
    const client = clients.find(c => c.name === petName && c.ownerName === ownerName);

    const newAppt: Appointment = {
      id: generateId(),
      date: formData.get('date') as string,
      time: formData.get('time') as string,
      clientId: client?.id || '',
      clientName: ownerName,
      petName: petName,
      service: formData.get('service') as string,
      notes: "",
      duration: parseInt(formData.get('duration') as string),
      status: 'pending'
    };

    db.saveAppointment(newAppt);
    refreshData();
    setIsModalOpen(false);
  };

  const handleConfirmInvoice = () => {
    if (!selectedAppt) return;
    const newInvoice: Invoice = {
      id: generateId(),
      number: `FAC-${Date.now().toString().slice(-6)}`,
      date: formatDate(new Date()),
      clientId: selectedAppt.clientId,
      petName: selectedAppt.petName,
      ownerName: selectedAppt.clientName,
      amount: parseFloat(invoiceAmount),
      paymentMethod,
      appointmentId: selectedAppt.id,
      notes: invoiceNotes
    };
    db.saveInvoice(newInvoice);
    db.saveAppointment({ ...selectedAppt, status: 'invoiced' });
    refreshData();
    setIsInvoiceModalOpen(false);
    if(confirm("Facture émise. Imprimer ?")) onPrintInvoice?.(newInvoice);
  };

  const ApptCard = ({ appt }: { appt: Appointment }) => (
    <div className="flex items-center gap-6 p-6 rounded-2xl border border-slate-100 bg-white hover:border-indigo-100 transition-all shadow-sm">
      <div className="w-24 text-center border-r border-slate-50 pr-6">
        <p className="text-xs font-black text-indigo-400 uppercase">{new Date(appt.date).toLocaleDateString('fr-FR', { weekday: 'short', day: 'numeric', month: 'short' })}</p>
        <p className="text-lg font-black text-slate-800">{appt.time}</p>
      </div>
      <div className="flex-1">
        <div className="flex items-center gap-3">
          <h4 className="text-lg font-bold text-slate-800">{appt.petName}</h4>
          <span className="px-2 py-0.5 bg-indigo-50 text-indigo-600 text-[10px] font-black uppercase rounded-md">{appt.service}</span>
        </div>
        <p className="text-sm text-slate-500">Propriétaire: {appt.clientName}</p>
      </div>
      <div className="flex items-center gap-2">
        {appt.status !== 'invoiced' ? (
          <button onClick={() => { setSelectedAppt(appt); setIsInvoiceModalOpen(true); }} className="flex items-center gap-2 px-5 py-2.5 bg-emerald-600 text-white rounded-xl text-sm font-black hover:bg-emerald-700 shadow-md">
            <Euro size={16} /> Facturer
          </button>
        ) : (
          <button onClick={() => { const inv = db.getInvoices().find(i => i.appointmentId === appt.id); if(inv) onPrintInvoice?.(inv); }} className="p-2.5 bg-slate-100 text-slate-600 rounded-xl"><Printer size={18} /></button>
        )}
        <button onClick={() => { if(confirm("Supprimer ce RDV ?")) { db.deleteAppointment(appt.id); refreshData(); } }} className="p-2.5 text-slate-300 hover:text-red-400"><Trash2 size={20}/></button>
      </div>
    </div>
  );

  return (
    <div className="space-y-6 h-full flex flex-col no-print">
      <div className="flex flex-col lg:flex-row items-center justify-between gap-4">
        <div className="flex items-center gap-2 bg-white p-1.5 rounded-2xl shadow-sm border border-slate-100">
          <button onClick={() => setView('month')} className={`px-4 py-2 rounded-xl text-xs font-bold transition-all ${view === 'month' ? 'bg-indigo-600 text-white' : 'text-slate-500 hover:bg-slate-50'}`}>Mensuel</button>
          <button onClick={() => setView('upcoming')} className={`px-4 py-2 rounded-xl text-xs font-bold transition-all ${view === 'upcoming' ? 'bg-indigo-600 text-white' : 'text-slate-500 hover:bg-slate-50'}`}>À Venir</button>
          <button onClick={() => setView('day')} className={`px-4 py-2 rounded-xl text-xs font-bold transition-all ${view === 'day' ? 'bg-indigo-600 text-white' : 'text-slate-500 hover:bg-slate-50'}`}>Quotidien</button>
        </div>

        {view !== 'upcoming' && (
          <div className="flex items-center gap-4">
            <button onClick={() => { const d = new Date(currentDate); view === 'month' ? d.setMonth(d.getMonth()-1) : d.setDate(d.getDate()-1); setCurrentDate(d); }} className="p-2 bg-white rounded-xl border"><ChevronLeft size={20}/></button>
            <h2 className="text-sm font-black text-slate-800 min-w-[150px] text-center uppercase">
              {currentDate.toLocaleDateString('fr-FR', view === 'month' ? { month: 'long', year: 'numeric' } : { day: 'numeric', month: 'long' })}
            </h2>
            <button onClick={() => { const d = new Date(currentDate); view === 'month' ? d.setMonth(d.getMonth()+1) : d.setDate(d.getDate()+1); setCurrentDate(d); }} className="p-2 bg-white rounded-xl border"><ChevronRight size={20}/></button>
          </div>
        )}

        <button onClick={() => setIsModalOpen(true)} className="px-6 py-3 bg-indigo-600 text-white rounded-xl font-bold shadow-lg flex items-center gap-2 hover:bg-indigo-700">
          <Plus size={20}/> Nouveau RDV
        </button>
      </div>

      <div className="flex-1 bg-white rounded-3xl border border-slate-100 shadow-sm overflow-hidden flex flex-col">
        {view === 'month' && (
          <div className="flex-1 flex flex-col">
            <div className="calendar-grid border-b bg-slate-50/50">
              {['Lun', 'Mar', 'Mer', 'Jeu', 'Ven', 'Sam', 'Dim'].map(d => (
                <div key={d} className="py-2 text-center text-[10px] font-black text-slate-400 uppercase tracking-widest">{d}</div>
              ))}
            </div>
            <div className="calendar-grid flex-1 overflow-y-auto">
              {Array.from({ length: adjustedFirstDay }).map((_, i) => <div key={i} className="h-32 border-b border-r bg-slate-50/20" />)}
              {Array.from({ length: daysInMonth }).map((_, i) => {
                const day = i + 1;
                const dStr = formatDate(new Date(currentDate.getFullYear(), currentDate.getMonth(), day));
                const dayAppts = appointments.filter(a => a.date === dStr);
                const isToday = formatDate(new Date()) === dStr;
                return (
                  <div key={day} onClick={() => { setCurrentDate(new Date(currentDate.getFullYear(), currentDate.getMonth(), day)); setView('day'); }} className={`h-32 border-b border-r p-2 cursor-pointer hover:bg-indigo-50/30 group ${isToday ? 'bg-indigo-50/10' : ''}`}>
                    <span className={`text-[10px] font-black ${isToday ? 'text-indigo-600 bg-indigo-100 px-2 rounded-lg' : 'text-slate-400'}`}>{day}</span>
                    <div className="mt-1 space-y-1">
                      {dayAppts.slice(0, 3).map(a => <div key={a.id} className="text-[9px] p-0.5 rounded font-black truncate bg-indigo-100 text-indigo-700">{a.petName}</div>)}
                    </div>
                  </div>
                );
              })}
            </div>
          </div>
        )}

        {(view === 'day' || view === 'upcoming') && (
          <div className="p-8 space-y-4 overflow-y-auto flex-1 bg-slate-50/30">
            {(view === 'day' ? dailyAppts : upcomingAppts).length > 0 ? (
              (view === 'day' ? dailyAppts : upcomingAppts).map(appt => <ApptCard key={appt.id} appt={appt} />)
            ) : (
              <div className="h-full flex flex-col items-center justify-center text-slate-300 py-20">
                <Clock size={64} className="opacity-10 mb-4" />
                <p className="font-bold">Aucun rendez-vous {view === 'upcoming' ? 'à venir' : 'ce jour'}.</p>
              </div>
            )}
          </div>
        )}
      </div>

      {isInvoiceModalOpen && selectedAppt && (
        <div className="fixed inset-0 bg-slate-900/80 backdrop-blur-sm z-[200] flex items-center justify-center p-4">
          <div className="bg-white rounded-[2.5rem] w-full max-w-xl shadow-2xl overflow-hidden">
            <div className="bg-indigo-600 p-8 text-white">
              <h3 className="text-2xl font-black">Encaissement</h3>
              <p className="opacity-70">{selectedAppt.petName} - {selectedAppt.service}</p>
            </div>
            <div className="p-8 space-y-6">
              <div className="grid grid-cols-2 gap-6">
                <div><label className="text-[10px] font-black text-slate-400 uppercase mb-2 block">Montant (€)</label><input type="number" value={invoiceAmount} onChange={e => setInvoiceAmount(e.target.value)} className="w-full text-3xl font-black bg-slate-50 rounded-2xl p-4" /></div>
                <div><label className="text-[10px] font-black text-slate-400 uppercase mb-2 block">Mode</label><select value={paymentMethod} onChange={e => setPaymentMethod(e.target.value as any)} className="w-full p-4 bg-slate-50 rounded-2xl font-bold">{['Carte', 'Espèces', 'Chèque', 'Virement'].map(m => <option key={m} value={m}>{m}</option>)}</select></div>
              </div>
              <textarea value={invoiceNotes} onChange={e => setInvoiceNotes(e.target.value)} rows={3} className="w-full p-4 bg-slate-50 rounded-2xl text-sm" placeholder="Notes sur la prestation..." />
              <div className="flex gap-4">
                <button onClick={handleConfirmInvoice} className="flex-1 py-5 bg-indigo-600 text-white rounded-2xl font-black text-lg">Valider la Facture</button>
                <button onClick={() => setIsInvoiceModalOpen(false)} className="px-8 py-5 bg-slate-100 text-slate-500 rounded-2xl font-bold">Annuler</button>
              </div>
            </div>
          </div>
        </div>
      )}

      {isModalOpen && (
        <div className="fixed inset-0 bg-slate-900/60 backdrop-blur-sm z-[200] flex items-center justify-center p-4">
          <div className="bg-white rounded-3xl w-full max-w-lg shadow-2xl overflow-hidden p-8">
            <h3 className="text-xl font-black text-slate-800 mb-6">Nouveau Rendez-vous</h3>
            <form onSubmit={handleSaveAppt} className="space-y-6">
              <div className="grid grid-cols-2 gap-4">
                <input type="date" name="date" defaultValue={dateStr} required className="w-full px-4 py-3 bg-slate-50 rounded-xl font-bold" />
                <input type="time" name="time" defaultValue="09:00" required className="w-full px-4 py-3 bg-slate-50 rounded-xl font-bold" />
              </div>
              <select name="client" required className="w-full px-4 py-3 bg-slate-50 rounded-xl font-bold">
                <option value="">Sélectionner un client...</option>
                {clients.map(c => <option key={c.id} value={`${c.name} - ${c.ownerName}`}>{c.name} ({c.ownerName})</option>)}
              </select>
              <select name="service" required className="w-full px-4 py-3 bg-slate-50 rounded-xl font-bold">
                {config.services.map(s => <option key={s} value={s}>{s}</option>)}
              </select>
              <input type="number" name="duration" defaultValue="60" className="w-full px-4 py-3 bg-slate-50 rounded-xl font-bold" />
              <button type="submit" className="w-full py-4 bg-indigo-600 text-white rounded-xl font-black">Confirmer</button>
              <button type="button" onClick={() => setIsModalOpen(false)} className="w-full text-slate-400 font-bold text-sm">Fermer</button>
            </form>
          </div>
        </div>
      )}
    </div>
  );
};

