import { Client, Appointment, Invoice, Configuration } from '../types';
import { INITIAL_CONFIG } from '../constants';

const KEYS = {
  CLIENTS: 'groom_clients',
  APPOINTMENTS: 'groom_appointments',
  INVOICES: 'groom_invoices',
  CONFIG: 'groom_config'
};

export const db = {
  getConfig: (): Configuration => {
    const data = localStorage.getItem(KEYS.CONFIG);
    const config = data ? JSON.parse(data) : INITIAL_CONFIG;
    if (!config.breeds) config.breeds = INITIAL_CONFIG.breeds;
    return config;
  },
  saveConfig: (config: Configuration) => localStorage.setItem(KEYS.CONFIG, JSON.stringify(config)),

  updateConfigItems: (category: keyof Configuration, items: string[]) => {
    const config = db.getConfig();
    if (Array.isArray(config[category])) {
      (config[category] as any) = items;
      db.saveConfig(config);
    }
  },

  updateBreeds: (species: string, breeds: string[]) => {
    const config = db.getConfig();
    if (!config.breeds) config.breeds = {};
    config.breeds[species] = breeds;
    db.saveConfig(config);
  },

  getClients: (): Client[] => {
    try {
      const data = localStorage.getItem(KEYS.CLIENTS);
      return data ? JSON.parse(data) : [];
    } catch(e) { return []; }
  },
  saveClient: (client: Client) => {
    const clients = db.getClients();
    const index = clients.findIndex(c => c.id === client.id);
    if (index >= 0) clients[index] = client;
    else clients.push(client);
    localStorage.setItem(KEYS.CLIENTS, JSON.stringify(clients));
  },
  deleteClient: (id: string) => {
    const clients = db.getClients().filter(c => c.id !== id);
    localStorage.setItem(KEYS.CLIENTS, JSON.stringify(clients));
    // Optionnel: supprimer aussi ses RDV? On garde pour l'historique compta
  },

  getAppointments: (): Appointment[] => {
    try {
      const data = localStorage.getItem(KEYS.APPOINTMENTS);
      return data ? JSON.parse(data) : [];
    } catch(e) { return []; }
  },
  saveAppointment: (appt: Appointment) => {
    const appts = db.getAppointments();
    const index = appts.findIndex(a => a.id === appt.id);
    if (index >= 0) appts[index] = appt;
    else appts.push(appt);
    localStorage.setItem(KEYS.APPOINTMENTS, JSON.stringify(appts));
  },
  deleteAppointment: (id: string) => {
    const appts = db.getAppointments().filter(a => a.id !== id);
    localStorage.setItem(KEYS.APPOINTMENTS, JSON.stringify(appts));
  },

  getInvoices: (): Invoice[] => {
    try {
      const data = localStorage.getItem(KEYS.INVOICES);
      return data ? JSON.parse(data) : [];
    } catch(e) { return []; }
  },
  saveInvoice: (invoice: Invoice) => {
    const invoices = db.getInvoices();
    invoices.push(invoice);
    localStorage.setItem(KEYS.INVOICES, JSON.stringify(invoices));
  },
  deleteInvoice: (id: string) => {
    const invoices = db.getInvoices().filter(i => i.id !== id);
    localStorage.setItem(KEYS.INVOICES, JSON.stringify(invoices));
  },

  importFullData: (data: any): boolean => {
    try {
      if (!data || typeof data !== 'object') return false;

      // Mappings de clés possibles (flexibilité pour l'import)
      const mappings = [
        { dataKey: 'clients', storeKey: KEYS.CLIENTS },
        { dataKey: 'appointments', storeKey: KEYS.APPOINTMENTS },
        { dataKey: 'appts', storeKey: KEYS.APPOINTMENTS },
        { dataKey: 'invoices', storeKey: KEYS.INVOICES },
        { dataKey: 'config', storeKey: KEYS.CONFIG }
      ];

      mappings.forEach(({ dataKey, storeKey }) => {
        if (data[dataKey]) {
          localStorage.setItem(storeKey, JSON.stringify(data[dataKey]));
        }
      });
      return true;
    } catch (e) {
      console.error("Database import error:", e);
      return false;
    }
  }
};

import React, { useState, useEffect, useRef } from 'react';
import { 
  Search, Plus, User, Phone, Mail, MapPin, Sparkles, 
  Trash2, Edit3, Camera, History, FileText, ChevronRight, 
  Image as ImageIcon, Save, X, Calendar 
} from 'lucide-react';
import { db } from '../services/database';
import { Client, Invoice, Appointment } from '../types';

const generateId = () => Math.random().toString(36).substring(2, 15) + Date.now().toString(36);

const ClientList: React.FC<{ initialClientId?: string | null }> = ({ initialClientId }) => {
  const [clients, setClients] = useState<Client[]>([]);
  const [search, setSearch] = useState('');
  const [selectedClient, setSelectedClient] = useState<Client | null>(null);
  const [isEditing, setIsEditing] = useState(false);
  const [history, setHistory] = useState<(Appointment & { invoice?: Invoice })[]>([]);
  const [formSpecies, setFormSpecies] = useState<string>('Chien');

  const config = db.getConfig();

  const loadClients = () => {
    const loaded = db.getClients();
    setClients(loaded);
    return loaded;
  };

  useEffect(() => {
    const loaded = loadClients();
    if (initialClientId) {
      const found = loaded.find(c => c.id === initialClientId);
      if (found) { 
        setSelectedClient(found); 
        setFormSpecies(found.species); 
        loadHistory(found.id); 
      }
    }
  }, [initialClientId]);

  const loadHistory = (clientId: string) => {
    const allAppts = db.getAppointments().filter(a => a.clientId === clientId);
    const allInvoices = db.getInvoices();
    const combined = allAppts.map(appt => ({
      ...appt,
      invoice: allInvoices.find(inv => inv.appointmentId === appt.id)
    })).sort((a, b) => b.date.localeCompare(a.date));
    setHistory(combined);
  };

  const filteredClients = clients.filter(c => 
    c.name.toLowerCase().includes(search.toLowerCase()) || 
    c.ownerName.toLowerCase().includes(search.toLowerCase())
  );

  const handleSaveClient = (e: React.FormEvent<HTMLFormElement>) => {
    e.preventDefault();
    const formData = new FormData(e.currentTarget);

    const newClient: Client = {
      id: selectedClient && isEditing ? selectedClient.id : generateId(),
      name: formData.get('name') as string,
      species: formData.get('species') as string,
      breed: formData.get('breed') as string,
      coatType: formData.get('coatType') as string,
      birthDate: formData.get('birthDate') as string,
      ownerName: formData.get('ownerName') as string,
      phone: formData.get('phone') as string,
      email: formData.get('email') as string,
      address: formData.get('address') as string,
      particularities: Array.from(formData.getAll('particularities')) as string[],
      notes: formData.get('notes') as string,
      photoProfile: selectedClient?.photoProfile,
      createdAt: selectedClient?.createdAt || new Date().toISOString()
    };

    db.saveClient(newClient);
    loadClients();
    setSelectedClient(newClient);
    setIsEditing(false);
  };

  const handleFileUpload = (apptId: string, type: 'photoBefore' | 'photoAfter', e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;
    const reader = new FileReader();
    reader.onloadend = () => {
      const base64 = reader.result as string;
      const allAppts = db.getAppointments();
      const index = allAppts.findIndex(a => a.id === apptId);
      if (index >= 0) {
        allAppts[index] = { ...allAppts[index], [type]: base64 };
        localStorage.setItem('groom_appointments', JSON.stringify(allAppts));
        loadHistory(selectedClient!.id);
      }
    };
    reader.readAsDataURL(file);
  };

  return (
    <div className="flex flex-col lg:flex-row gap-8 h-[calc(100vh-140px)]">
