        <div className="flex gap-2">
          <div className="relative flex-1">
            <Search className="absolute left-3 top-1/2 -translate-y-1/2 text-slate-400" size={18} />
            <input type="text" placeholder="Rechercher animal ou client..." className="w-full pl-10 pr-4 py-2 bg-slate-50 rounded-xl text-sm" value={search} onChange={e => setSearch(e.target.value)} />
          </div>
          <button onClick={() => { setSelectedClient(null); setIsEditing(true); setFormSpecies('Chien'); setHistory([]); }} className="p-2 bg-indigo-600 text-white rounded-xl shadow-md hover:bg-indigo-700 transition-colors"><Plus size={20} /></button>
        </div>
        <div className="flex-1 overflow-y-auto space-y-2">
