import { Configuration, Invoice, Client } from './types';

const App: React.FC = () => {
  const [activeTab, setActiveTab] = useState('dashboard');
  const [selectedClientId, setSelectedClientId] = useState<string | null>(null);
  const [config, setConfig] = useState<Configuration>(db.getConfig());
  const [printingInvoice, setPrintingInvoice] = useState<{inv: Invoice, cli?: Client} | null>(null);

  const fileInputRef = useRef<HTMLInputElement>(null);

  const handlePrint = (invoice: Invoice) => {
    const clients = db.getClients();
    const client = clients.find(c => c.id === invoice.clientId);
    setPrintingInvoice({ inv: invoice, cli: client });
  };

  const handleImport = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;

    const reader = new FileReader();
    reader.onload = (event) => {
      try {
        const content = event.target?.result as string;
        const json = JSON.parse(content);

        if (confirm("ATTENTION : Cette action va écraser TOUTES vos données actuelles. Confirmer la restauration ?")) {
          const success = db.importFullData(json);
          if (success) {
            alert("✅ Données restaurées avec succès ! L'application va redémarrer.");
            window.location.reload();
          } else {
            alert("❌ Erreur : Le fichier ne contient pas les données attendues.");
          }
        }
      } catch (err) {
        alert("❌ Erreur : Le fichier JSON est invalide ou corrompu.");
        console.error(err);
      }
    };
    reader.readAsText(file);
    // On réinitialise l'input pour permettre de sélectionner le même fichier deux fois
    e.target.value = '';
  };

  const renderInvoicesList = () => (
    <div className="bg-white p-8 rounded-[2.5rem] border border-slate-100 shadow-sm overflow-hidden animate-in fade-in slide-in-from-bottom-4">
