const generateId = () => Math.random().toString(36).substring(2, 15) + Date.now().toString(36);

const ClientList: React.FC<{ initialClientId?: string | null }> = ({ initialClientId }) => {
  const [clients, setClients] = useState<Client[]>([]);
  const [search, setSearch] = useState('');
  const [selectedClient, setSelectedClient] = useState<Client | null>(null);
  const [isEditing, setIsEditing] = useState(false);
  const [history, setHistory] = useState<(Appointment & { invoice?: Invoice })[]>([]);
  const [formSpecies, setFormSpecies] = useState<string>('Chien');
  const [fullScreenPhoto, setFullScreenPhoto] = useState<string | null>(null);

  const config = db.getConfig();

  const loadClients = () => {
    const loaded = db.getClients();
    setClients(loaded);
    return loaded;
  };

  useEffect(() => {
    const loaded = loadClients();
    if (initialClientId) {
      const found = loaded.find(c => c.id === initialClientId);
      if (found) { setSelectedClient(found); setFormSpecies(found.species); loadHistory(found.id); }
    }
  }, [initialClientId]);

  const loadHistory = (clientId: string) => {
    const allAppts = db.getAppointments().filter(a => a.clientId === clientId);
    const allInvoices = db.getInvoices();
    const combined = allAppts.map(appt => ({
      ...appt,
      invoice: allInvoices.find(inv => inv.appointmentId === appt.id)
    })).sort((a, b) => b.date.localeCompare(a.date));
    setHistory(combined);
  };

  const filteredClients = clients.filter(c => 
    c.name.toLowerCase().includes(search.toLowerCase()) || 
    c.ownerName.toLowerCase().includes(search.toLowerCase())
  );

  const handleSaveClient = (e: React.FormEvent<HTMLFormElement>) => {
    e.preventDefault();
    const formData = new FormData(e.currentTarget);

    const newClient: Client = {
      id: selectedClient && isEditing ? selectedClient.id : generateId(),
      name: formData.get('name') as string,
      species: formData.get('species') as string,
      breed: formData.get('breed') as string,
      coatType: formData.get('coatType') as string,
      birthDate: formData.get('birthDate') as string,
      ownerName: formData.get('ownerName') as string,
      phone: formData.get('phone') as string,
      email: formData.get('email') as string,
      address: formData.get('address') as string,
      particularities: Array.from(formData.getAll('particularities')) as string[],
      notes: formData.get('notes') as string,
      photoProfile: selectedClient?.photoProfile,
      createdAt: selectedClient?.createdAt || new Date().toISOString()
    };

    db.saveClient(newClient);
    loadClients();
    setSelectedClient(newClient);
    setIsEditing(false);
  };

  const handleFileUpload = (apptId: string, type: 'photoBefore' | 'photoAfter', e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;
    const reader = new FileReader();
    reader.onloadend = () => {
      const base64 = reader.result as string;
      const allAppts = db.getAppointments();
      const index = allAppts.findIndex(a => a.id === apptId);
      if (index >= 0) {
        allAppts[index] = { ...allAppts[index], [type]: base64 };
        localStorage.setItem('groom_appointments', JSON.stringify(allAppts));
        loadHistory(selectedClient!.id);
      }
    };
    reader.readAsDataURL(file);
  };

  const handleProfilePhotoUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file || !selectedClient) return;
    const reader = new FileReader();
    reader.onloadend = () => {
      const base64 = reader.result as string;
      const updated = { ...selectedClient, photoProfile: base64 };
      db.saveClient(updated);
      setSelectedClient(updated);
      loadClients();
    };
    reader.readAsDataURL(file);
  };

  const downloadPhoto = (base64: string, name: string) => {
    const link = document.createElement('a');
    link.href = base64;
    link.download = `kanine_${name}_${Date.now()}.png`;
    link.click();
  };

  return (
