          <div key={it} className="flex justify-between items-center p-3 bg-slate-50 rounded-xl group transition-colors hover:bg-slate-100">
            <span className="text-sm font-bold text-slate-800">{it}</span>
            <button onClick={() => onUpdate(items.filter((i: string) => i !== it))} className="text-red-400 opacity-0 group-hover:opacity-100 transition-opacity p-1">×</button>
          </div>
        ))}
        {items.length === 0 && <p className="text-center text-slate-300 text-xs italic py-10">Aucun élément</p>}
      </div>
      <div className="flex gap-2">
        <input type="text" value={val} onChange={e => setVal(e.target.value)} onKeyPress={e => e.key === 'Enter' && val && (onUpdate([...items, val]), setVal(''))} className="flex-1 px-4 py-3 bg-slate-50 border border-slate-100 rounded-xl text-sm font-bold focus:ring-2 focus:ring-indigo-100 outline-none" placeholder="Ajouter..." />
        <button onClick={() => { if(val) onUpdate([...items, val]); setVal(''); }} className="p-3 bg-indigo-600 text-white rounded-xl font-bold hover:bg-indigo-700 shadow-sm">+</button>
      </div>
    </div>
  );
};

export default App;

import React, { useState, useEffect, useRef } from 'react';
import { 
  Search, Plus, User, Phone, Mail, MapPin, Sparkles, 
  Trash2, Edit3, Camera, History, FileText, ChevronRight, 
  Image as ImageIcon, Save, X, Calendar, Download, Maximize2
} from 'lucide-react';
import { db } from '../services/database';
import { Client, Invoice, Appointment } from '../types';

const generateId = () => Math.random().toString(36).substring(2, 15) + Date.now().toString(36);

const ClientList: React.FC<{ initialClientId?: string | null }> = ({ initialClientId }) => {
  const [clients, setClients] = useState<Client[]>([]);
  const [search, setSearch] = useState('');
  const [selectedClient, setSelectedClient] = useState<Client | null>(null);
  const [isEditing, setIsEditing] = useState(false);
  const [history, setHistory] = useState<(Appointment & { invoice?: Invoice })[]>([]);
  const [formSpecies, setFormSpecies] = useState<string>('Chien');
  const [selectedPhoto, setSelectedPhoto] = useState<string | null>(null);

  const config = db.getConfig();

  const loadClients = () => {
    const loaded = db.getClients();
    setClients(loaded);
    return loaded;
  };

  useEffect(() => {
    const loaded = loadClients();
    if (initialClientId) {
      const found = loaded.find(c => c.id === initialClientId);
      if (found) { 
        setSelectedClient(found); 
        setFormSpecies(found.species); 
        loadHistory(found.id); 
      }
    }
  }, [initialClientId]);

  const loadHistory = (clientId: string) => {
    const allAppts = db.getAppointments().filter(a => a.clientId === clientId);
    const allInvoices = db.getInvoices();
    const combined = allAppts.map(appt => ({
      ...appt,
      invoice: allInvoices.find(inv => inv.appointmentId === appt.id)
    })).sort((a, b) => b.date.localeCompare(a.date));
    setHistory(combined);
  };

  const filteredClients = clients.filter(c => 
    c.name.toLowerCase().includes(search.toLowerCase()) || 
    c.ownerName.toLowerCase().includes(search.toLowerCase())
  );

  const handleSaveClient = (e: React.FormEvent<HTMLFormElement>) => {
    e.preventDefault();
    const formData = new FormData(e.currentTarget);

    const newClient: Client = {
      id: selectedClient && isEditing ? selectedClient.id : generateId(),
      name: formData.get('name') as string,
      species: formData.get('species') as string,
      breed: formData.get('breed') as string,
      coatType: formData.get('coatType') as string,
      birthDate: formData.get('birthDate') as string,
      ownerName: formData.get('ownerName') as string,
      phone: formData.get('phone') as string,
      email: formData.get('email') as string,
      address: formData.get('address') as string,
      particularities: Array.from(formData.getAll('particularities')) as string[],
      notes: formData.get('notes') as string,
      photoProfile: selectedClient?.photoProfile, // Sera mis à jour via le bouton photo si existant
      createdAt: selectedClient?.createdAt || new Date().toISOString()
    };

    db.saveClient(newClient);
    loadClients();
    setSelectedClient(newClient);
    setIsEditing(false);
  };

  const handlePetPhotoUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file || !selectedClient) return;
    const reader = new FileReader();
    reader.onloadend = () => {
      const base64 = reader.result as string;
      const updatedClient = { ...selectedClient, photoProfile: base64 };
      db.saveClient(updatedClient);
      setSelectedClient(updatedClient);
      loadClients();
    };
    reader.readAsDataURL(file);
  };

  const handleHistoryPhotoUpload = (apptId: string, type: 'photoBefore' | 'photoAfter', e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;
    const reader = new FileReader();
    reader.onloadend = () => {
      const base64 = reader.result as string;
      const allAppts = db.getAppointments();
      const index = allAppts.findIndex(a => a.id === apptId);
      if (index >= 0) {
        allAppts[index] = { ...allAppts[index], [type]: base64 };
        localStorage.setItem('groom_appointments', JSON.stringify(allAppts));
        loadHistory(selectedClient!.id);
      }
    };
    reader.readAsDataURL(file);
  };

  const downloadImage = (base64: string, name: string) => {
    const link = document.createElement('a');
    link.href = base64;
    link.download = `kanine_${name}_${Date.now()}.png`;
    document.body.appendChild(link);
    link.click();
    document.body.removeChild(link);
  };

  return (
    <div className="flex flex-col lg:flex-row gap-8 h-[calc(100vh-140px)]">
      {/* Sidebar */}
      <div className="w-full lg:w-96 flex flex-col gap-4 bg-white p-4 rounded-2xl shadow-sm border border-slate-100 overflow-hidden">
        <div className="flex gap-2">
          <div className="relative flex-1">
            <Search className="absolute left-3 top-1/2 -translate-y-1/2 text-slate-400" size={18} />
            <input type="text" placeholder="Rechercher..." className="w-full pl-10 pr-4 py-2 bg-slate-50 rounded-xl text-sm" value={search} onChange={e => setSearch(e.target.value)} />
          </div>
          <button onClick={() => { setSelectedClient(null); setIsEditing(true); setFormSpecies('Chien'); setHistory([]); }} className="p-2 bg-indigo-600 text-white rounded-xl"><Plus size={20} /></button>
        </div>
        <div className="flex-1 overflow-y-auto space-y-2">
          {filteredClients.map(client => (
            <button key={client.id} onClick={() => { setSelectedClient(client); setIsEditing(false); setFormSpecies(client.species); loadHistory(client.id); }} className={`w-full text-left p-4 rounded-xl transition-all ${selectedClient?.id === client.id ? 'bg-indigo-50 border-l-4 border-indigo-600' : 'hover:bg-slate-50'}`}>
              <h4 className="font-bold text-slate-800">{client.name}</h4>
              <p className="text-xs text-slate-400">{client.ownerName} • {client.species}</p>
            </button>
          ))}
        </div>
      </div>

      {/* Main Content Area */}
      <div className="flex-1 bg-white rounded-2xl shadow-sm border border-slate-100 overflow-y-auto relative">
        {isEditing ? (
          <form onSubmit={handleSaveClient} className="p-8 space-y-8">
            <div className="flex justify-between items-center mb-6">
              <h2 className="text-2xl font-black text-slate-800">{selectedClient ? 'Modifier Client' : 'Nouveau Client'}</h2>
              <button type="button" onClick={() => setIsEditing(false)} className="p-2 text-slate-400 hover:bg-slate-50 rounded-lg"><X size={20}/></button>
            </div>

            <div className="grid grid-cols-1 md:grid-cols-2 gap-8">
              <div className="space-y-6">
                <h3 className="text-xs font-black text-slate-400 uppercase tracking-widest border-b pb-2">Animal</h3>
                <div className="space-y-4">
                  <input name="name" defaultValue={selectedClient?.name} placeholder="Nom de l'animal" required className="w-full px-4 py-3 bg-slate-50 border border-slate-100 rounded-xl font-bold" />
                  <div className="grid grid-cols-2 gap-4">
                    <select name="species" value={formSpecies} onChange={e => setFormSpecies(e.target.value)} required className="w-full px-4 py-3 bg-slate-50 border border-slate-100 rounded-xl font-bold">
                      {config.species.map(s => <option key={s} value={s}>{s}</option>)}
                    </select>
                    <select name="breed" defaultValue={selectedClient?.breed} required className="w-full px-4 py-3 bg-slate-50 border border-slate-100 rounded-xl font-bold">
                      {(config.breeds[formSpecies] || ["Autre"]).map(b => <option key={b} value={b}>{b}</option>)}
                    </select>
                  </div>
                  <div className="grid grid-cols-2 gap-4">
                    <select name="coatType" defaultValue={selectedClient?.coatType} required className="w-full px-4 py-3 bg-slate-50 border border-slate-100 rounded-xl font-bold">
                      {config.coatTypes.map(c => <option key={c} value={c}>{c}</option>)}
                    </select>
                    <input type="date" name="birthDate" defaultValue={selectedClient?.birthDate} className="w-full px-4 py-3 bg-slate-50 border border-slate-100 rounded-xl font-bold" />
                  </div>
                </div>
              </div>

              <div className="space-y-6">
                <h3 className="text-xs font-black text-slate-400 uppercase tracking-widest border-b pb-2">Propriétaire</h3>
                <div className="space-y-4">
                  <input name="ownerName" defaultValue={selectedClient?.ownerName} placeholder="Nom Complet" required className="w-full px-4 py-3 bg-slate-50 border border-slate-100 rounded-xl font-bold" />
                  <div className="grid grid-cols-2 gap-4">
                    <input name="phone" defaultValue={selectedClient?.phone} placeholder="Téléphone" required className="w-full px-4 py-3 bg-slate-50 border border-slate-100 rounded-xl font-bold" />
                    <input type="email" name="email" defaultValue={selectedClient?.email} placeholder="Email" className="w-full px-4 py-3 bg-slate-50 border border-slate-100 rounded-xl font-bold" />
                  </div>
                  <input name="address" defaultValue={selectedClient?.address} placeholder="Adresse" className="w-full px-4 py-3 bg-slate-50 border border-slate-100 rounded-xl font-bold" />
                </div>
              </div>
            </div>

            <div className="space-y-4">
              <h3 className="text-xs font-black text-slate-400 uppercase tracking-widest">Particularités</h3>
              <div className="flex flex-wrap gap-3">
                {config.particularities.map(p => (
                  <label key={p} className="flex items-center gap-2 px-4 py-2 bg-slate-50 rounded-xl cursor-pointer hover:bg-indigo-50">
                    <input type="checkbox" name="particularities" value={p} defaultChecked={selectedClient?.particularities.includes(p)} className="rounded text-indigo-600" />
                    <span className="text-xs font-bold">{p}</span>
                  </label>
                ))}
              </div>
            </div>

            <textarea name="notes" defaultValue={selectedClient?.notes} placeholder="Notes et recommandations..." rows={4} className="w-full px-4 py-3 bg-slate-50 border border-slate-100 rounded-xl text-sm"></textarea>

            <button type="submit" className="w-full py-5 bg-indigo-600 text-white rounded-2xl font-black text-xl shadow-lg">Enregistrer</button>
          </form>
        ) : selectedClient ? (
          <div className="p-8 space-y-12">
            <div className="flex justify-between items-start">
               <div className="flex items-center gap-6">
                  {/* PHOTO DE PROFIL DE L'ANIMAL */}
                  <div className="relative group w-24 h-24 bg-indigo-50 rounded-[2.5rem] flex items-center justify-center shadow-inner overflow-hidden border-4 border-white">
                    {selectedClient.photoProfile ? (
