                  </div>
               </div>
               <div className="flex gap-2">
                 <button onClick={() => setIsEditing(true)} className="p-3 bg-slate-50 text-slate-600 rounded-2xl hover:bg-indigo-50"><Edit3 size={20}/></button>
                 <button onClick={() => { if(confirm("Supprimer ce client ?")) { db.deleteClient(selectedClient.id); loadClients(); setSelectedClient(null); } }} className="p-3 bg-slate-50 text-red-400 rounded-2xl hover:bg-red-50"><Trash2 size={20}/></button>
               </div>
