          <button onClick={() => setView('upcoming')} className={`px-4 py-2 rounded-xl text-xs font-bold transition-all ${view === 'upcoming' ? 'bg-indigo-600 text-white' : 'text-slate-500 hover:bg-slate-50'}`}>À Venir</button>
          <button onClick={() => setView('day')} className={`px-4 py-2 rounded-xl text-xs font-bold transition-all ${view === 'day' ? 'bg-indigo-600 text-white' : 'text-slate-500 hover:bg-slate-50'}`}>Quotidien</button>
        </div>

        {view !== 'upcoming' && (
