import React, { useState, useRef } from 'react';
import Layout from './components/Layout';
import Dashboard from './views/Dashboard';
import ClientList from './views/ClientList';
import Planning from './views/Planning';
import InvoicePDF from './components/InvoicePDF';
import { db } from './services/database';
import { Plus, Trash2, X, Tags, Printer, Download, Upload, AlertTriangle, FileText, CheckCircle } from 'lucide-react';
import { Configuration, Invoice, Client } from './types';
import { createRoot } from 'react-dom/client';

const App: React.FC = () => {
  const [activeTab, setActiveTab] = useState('dashboard');
  const [selectedClientId, setSelectedClientId] = useState<string | null>(null);
  const [config, setConfig] = useState<Configuration>(db.getConfig());

  const fileInputRef = useRef<HTMLInputElement>(null);

  // STRATÉGIE D'IMPRESSION ISOLÉE (Solution ultime pour feuilles blanches)
  const handlePrint = (invoice: Invoice) => {
    const clients = db.getClients();
    const client = clients.find(c => c.id === invoice.clientId);

    const printWindow = window.open('', '_blank', 'width=900,height=1200');
    if (!printWindow) {
      alert("Veuillez autoriser les fenêtres contextuelles (popups) pour imprimer.");
      return;
    }

    printWindow.document.write(`
      <!DOCTYPE html>
      <html>
        <head>
          <title>Facture ${invoice.number}</title>
          <script src="https://cdn.tailwindcss.com"></script>
          <link href="https://fonts.googleapis.com/css2?family=Inter:wght@400;700;900&display=swap" rel="stylesheet">
          <style>
            body { font-family: 'Inter', sans-serif; margin: 0; padding: 0; -webkit-print-color-adjust: exact; }
            @page { 
              size: A4; 
              margin: 0; 
            }
            @media print {
              body { margin: 0; padding: 0; }
              #print-root { width: 210mm; height: 297mm; overflow: hidden; }
            }
          </style>
        </head>
        <body>
          <div id="print-root"></div>
        </body>
      </html>
    `);

    // On rend le composant dans la nouvelle fenêtre une fois chargée
    setTimeout(() => {
      const container = printWindow.document.getElementById('print-root');
      if (container) {
        const root = createRoot(container);
        root.render(<InvoicePDF invoice={invoice} client={client} />);

        // On attend que les polices et images soient là
        setTimeout(() => {
          printWindow.print();
          // printWindow.close();
        }, 800);
      }
    }, 100);
  };

  const handleImport = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;

    const reader = new FileReader();
    reader.onload = (event) => {
      try {
        const content = event.target?.result as string;
        const json = JSON.parse(content);

        if (confirm("ATTENTION : Cette action va écraser TOUTES vos données actuelles par celles du fichier. Confirmer ?")) {
          const success = db.importFullData(json);
          if (success) {
            alert("✅ Restauration terminée ! Redémarrage...");
            window.location.reload();
          } else {
            alert("❌ Le fichier ne semble pas valide.");
          }
        }
      } catch (err) {
        alert("❌ Erreur de lecture du fichier JSON.");
      }
    };
    reader.readAsText(file);
    e.target.value = '';
  };

  const renderInvoicesList = () => (
    <div className="bg-white p-8 rounded-[2.5rem] border border-slate-100 shadow-sm overflow-hidden animate-in fade-in">
      <h2 className="text-2xl font-black mb-8 text-slate-800 uppercase tracking-tighter flex items-center gap-3">
        <FileText className="text-indigo-600" /> Journal de Facturation
      </h2>
      <div className="overflow-x-auto">
        <table className="w-full min-w-[800px]">
          <thead>
            <tr className="text-left text-[10px] font-black text-slate-400 uppercase tracking-widest border-b pb-4">
              <th className="pb-4">N° Facture</th>
              <th className="pb-4">Date</th>
              <th className="pb-4">Animal</th>
              <th className="pb-4 text-right">Montant</th>
              <th className="pb-4 text-center">Paiement</th>
              <th className="pb-4 text-center">Actions</th>
            </tr>
          </thead>
          <tbody className="divide-y divide-slate-50">
            {db.getInvoices().slice().reverse().map(inv => (
              <tr key={inv.id} className="text-sm hover:bg-slate-50/50 transition-colors group">
                <td className="py-5 font-black text-slate-900">{inv.number}</td>
                <td className="py-5 text-slate-500">{new Date(inv.date).toLocaleDateString()}</td>
                <td className="py-5">
                  <span className="font-bold text-slate-800">{inv.petName}</span>
                  <span className="text-slate-400 text-[10px] font-bold block uppercase tracking-tighter">{inv.ownerName}</span>
                </td>
                <td className="py-5 text-right font-black text-indigo-600 text-lg">{inv.amount.toFixed(2)}€</td>
                <td className="py-5 text-center">
                   <span className="px-3 py-1 bg-emerald-50 text-emerald-600 rounded-lg text-[10px] font-black uppercase tracking-tighter border border-emerald-100">{inv.paymentMethod}</span>
                </td>
                <td className="py-5 text-center">
                  <div className="flex justify-center gap-2">
                    <button onClick={() => handlePrint(inv)} className="p-2 text-indigo-600 hover:bg-indigo-50 rounded-xl transition-all shadow-sm"><Printer size={18} /></button>
                    <button onClick={() => { if(confirm("Supprimer définitivement cette facture du journal ?")) { db.deleteInvoice(inv.id); window.location.reload(); } }} className="p-2 text-red-400 hover:bg-red-50 rounded-xl transition-all shadow-sm"><Trash2 size={18} /></button>
                  </div>
                </td>
              </tr>
            ))}
            {db.getInvoices().length === 0 && (
              <tr><td colSpan={6} className="py-20 text-center text-slate-400 font-bold italic">Aucune facture enregistrée</td></tr>
            )}
          </tbody>
        </table>
      </div>
    </div>
  );

  return (
    <Layout activeTab={activeTab} setActiveTab={(t) => { setSelectedClientId(null); setActiveTab(t); }}>
      {activeTab === 'dashboard' && <Dashboard onNavigateToClient={(id) => { setSelectedClientId(id); setActiveTab('clients'); }} />}
      {activeTab === 'clients' && <ClientList initialClientId={selectedClientId} />}
      {activeTab === 'planning' && <Planning onPrintInvoice={handlePrint} />}
      {activeTab === 'invoices' && renderInvoicesList()}
      {activeTab === 'config' && (
        <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-8">
           <EditableConfigSection title="Espèces" items={config.species} onUpdate={(items) => { db.updateConfigItems('species', items); setConfig(db.getConfig()); }} />
           <EditableConfigSection title="Types de Poil" items={config.coatTypes} onUpdate={(items) => { db.updateConfigItems('coatTypes', items); setConfig(db.getConfig()); }} />
           <EditableConfigSection title="Particularités" items={config.particularities} onUpdate={(items) => { db.updateConfigItems('particularities', items); setConfig(db.getConfig()); }} />
           <EditableConfigSection title="Prestations" items={config.services} onUpdate={(items) => { db.updateConfigItems('services', items); setConfig(db.getConfig()); }} />
        </div>
      )}
      {activeTab === 'backup' && (
        <div className="max-w-4xl mx-auto grid grid-cols-1 md:grid-cols-2 gap-12 animate-in fade-in duration-500">
          <div className="bg-white p-12 rounded-[3.5rem] border border-slate-100 shadow-xl flex flex-col items-center text-center transition-transform hover:-translate-y-2">
            <div className="w-24 h-24 bg-indigo-50 text-indigo-600 rounded-[2.5rem] flex items-center justify-center mb-8 shadow-inner"><Download size={48} /></div>
            <h2 className="text-3xl font-black mb-4">Exporter</h2>
            <p className="text-slate-500 text-sm mb-10 leading-relaxed max-w-[250px]">Téléchargez une copie de sécurité au format JSON pour vos archives.</p>
