              const url = URL.createObjectURL(blob);
              const a = document.createElement('a'); a.href = url; a.download = `backup_kanine_${new Date().toISOString().split('T')[0]}.json`; a.click();
            }} className="w-full py-5 bg-indigo-600 text-white rounded-2xl font-black text-lg shadow-xl shadow-indigo-100 hover:bg-indigo-700 transition-all">Télécharger le JSON</button>
          </div>

          <div className="bg-white p-12 rounded-[3.5rem] border border-slate-100 shadow-xl flex flex-col items-center text-center transition-transform hover:-translate-y-2">
            <div className="w-24 h-24 bg-amber-50 text-amber-600 rounded-[2.5rem] flex items-center justify-center mb-8 shadow-inner"><Upload size={48} /></div>
            <h2 className="text-3xl font-black mb-4">Restaurer</h2>
            <input type="file" ref={fileInputRef} onChange={handleImport} accept=".json" className="hidden" />
            <p className="text-slate-500 text-sm mb-10 leading-relaxed max-w-[250px]">Récupérez vos données depuis une sauvegarde précédente.</p>
            <button onClick={() => fileInputRef.current?.click()} className="w-full py-5 bg-amber-500 text-white rounded-2xl font-black text-lg shadow-xl shadow-amber-100 hover:bg-amber-600 transition-all">Choisir un fichier</button>
          </div>
        </div>
      )}
    </Layout>
  );
};

