import { Client, Appointment, Invoice, Configuration } from '../types';
import { INITIAL_CONFIG } from '../constants';

const KEYS = {
  CLIENTS: 'groom_clients',
  APPOINTMENTS: 'groom_appointments',
  INVOICES: 'groom_invoices',
  CONFIG: 'groom_config',
  HISTORY: 'groom_history',
  AUDIT: 'groom_audit_log'
};

export interface AuditEntry {
  id: string;
  timestamp: string;
  action: string;
  details: string;
}

export const db = {
  // --- GESTION DE L'HISTORIQUE ---
  private_saveSnapshot: (action: string, details: string) => {
    const currentState = {
      clients: db.getClients(),
      appointments: db.getAppointments(),
      invoices: db.getInvoices(),
      config: db.getConfig()
    };

    // Sauvegarde du snapshot
    const history = JSON.parse(localStorage.getItem(KEYS.HISTORY) || '[]');
    history.unshift(currentState);
    localStorage.setItem(KEYS.HISTORY, JSON.stringify(history.slice(0, 20))); // On garde 20 étapes

    // Ajout au log d'audit
    const audit = JSON.parse(localStorage.getItem(KEYS.AUDIT) || '[]');
    audit.unshift({
      id: Math.random().toString(36).substr(2, 9),
      timestamp: new Date().toISOString(),
      action,
      details
    });
    localStorage.setItem(KEYS.AUDIT, JSON.stringify(audit.slice(0, 50)));
  },

  undo: (): boolean => {
    const history = JSON.parse(localStorage.getItem(KEYS.HISTORY) || '[]');
    if (history.length === 0) return false;

    const previousState = history.shift();
    localStorage.setItem(KEYS.HISTORY, JSON.stringify(history));

    localStorage.setItem(KEYS.CLIENTS, JSON.stringify(previousState.clients));
    localStorage.setItem(KEYS.APPOINTMENTS, JSON.stringify(previousState.appointments));
    localStorage.setItem(KEYS.INVOICES, JSON.stringify(previousState.invoices));
    localStorage.setItem(KEYS.CONFIG, JSON.stringify(previousState.config));

    return true;
  },

  getAuditLog: (): AuditEntry[] => JSON.parse(localStorage.getItem(KEYS.AUDIT) || '[]'),

  // --- CONFIGURATION ---
  getConfig: (): Configuration => {
    try {
      const data = localStorage.getItem(KEYS.CONFIG);
      const config = data ? JSON.parse(data) : INITIAL_CONFIG;
      return config;
    } catch { return INITIAL_CONFIG; }
  },
  saveConfig: (config: Configuration) => {
    db.private_saveSnapshot("Modif. Config", "Mise à jour des paramètres généraux");
    localStorage.setItem(KEYS.CONFIG, JSON.stringify(config));
  },

  updateConfigItems: (category: keyof Configuration, items: string[]) => {
    const config = db.getConfig();
    db.private_saveSnapshot("Modif. Config", `Catégorie: ${category}`);
    if (Array.isArray(config[category])) {
      (config[category] as any) = items;
      localStorage.setItem(KEYS.CONFIG, JSON.stringify(config));
    }
  },

  // --- CLIENTS ---
  getClients: (): Client[] => {
    try {
      const data = localStorage.getItem(KEYS.CLIENTS);
      return data ? JSON.parse(data) : [];
    } catch(e) { return []; }
  },
  saveClient: (client: Client) => {
    const clients = db.getClients();
    const index = clients.findIndex(c => c.id === client.id);
    const isNew = index < 0;
    db.private_saveSnapshot(isNew ? "Nouveau Client" : "Modif. Client", client.name);

    if (!isNew) clients[index] = client;
    else clients.push(client);
    localStorage.setItem(KEYS.CLIENTS, JSON.stringify(clients));
  },
  deleteClient: (id: string) => {
    const client = db.getClients().find(c => c.id === id);
    db.private_saveSnapshot("Suppression Client", client?.name || id);

    // Suppression en cascade
    const clients = db.getClients().filter(c => c.id !== id);
    const appointments = db.getAppointments().filter(a => a.clientId !== id);
    const invoices = db.getInvoices().filter(i => i.clientId !== id);

    localStorage.setItem(KEYS.CLIENTS, JSON.stringify(clients));
    localStorage.setItem(KEYS.APPOINTMENTS, JSON.stringify(appointments));
    localStorage.setItem(KEYS.INVOICES, JSON.stringify(invoices));
  },

  // --- RDV ---
  getAppointments: (): Appointment[] => {
    try {
      const data = localStorage.getItem(KEYS.APPOINTMENTS);
      return data ? JSON.parse(data) : [];
    } catch(e) { return []; }
  },
  saveAppointment: (appt: Appointment) => {
    const appts = db.getAppointments();
    const index = appts.findIndex(a => a.id === appt.id);
    db.private_saveSnapshot(index < 0 ? "Nouveau RDV" : "Modif. RDV", `${appt.petName} le ${appt.date}`);

    if (index >= 0) appts[index] = appt;
    else appts.push(appt);
    localStorage.setItem(KEYS.APPOINTMENTS, JSON.stringify(appts));
  },
  deleteAppointment: (id: string) => {
    const appt = db.getAppointments().find(a => a.id === id);
    db.private_saveSnapshot("Suppression RDV", appt ? `${appt.petName} (${appt.date})` : id);
    const appts = db.getAppointments().filter(a => a.id !== id);
    localStorage.setItem(KEYS.APPOINTMENTS, JSON.stringify(appts));
  },

  // --- FACTURES ---
  getInvoices: (): Invoice[] => {
    try {
      const data = localStorage.getItem(KEYS.INVOICES);
      return data ? JSON.parse(data) : [];
    } catch(e) { return []; }
  },
  saveInvoice: (invoice: Invoice) => {
    db.private_saveSnapshot("Nouvelle Facture", invoice.number);
    const invoices = db.getInvoices();
    invoices.push(invoice);
    localStorage.setItem(KEYS.INVOICES, JSON.stringify(invoices));
  },
  deleteInvoice: (id: string) => {
    const inv = db.getInvoices().find(i => i.id === id);
    db.private_saveSnapshot("Suppression Facture", inv?.number || id);
    const invoices = db.getInvoices().filter(i => i.id !== id);
    localStorage.setItem(KEYS.INVOICES, JSON.stringify(invoices));
  },

  // --- MAINTENANCE ---
  getStorageStats: () => {
    let totalUsed = 0;
    for (const key in localStorage) {
      if (localStorage.hasOwnProperty(key) && key.startsWith('groom_')) {
        totalUsed += (localStorage.getItem(key)?.length || 0) * 2;
      }
    }
    return {
      usedMB: (totalUsed / 1024 / 1024).toFixed(2),
      clientsCount: db.getClients().length,
      appointmentsCount: db.getAppointments().length,
      invoicesCount: db.getInvoices().length
    };
  },

  exportAsJSON: () => {
    const data = {
      clients: db.getClients(),
      appointments: db.getAppointments(),
      invoices: db.getInvoices(),
      config: db.getConfig(),
      version: "5.0",
      exportedAt: new Date().toISOString()
    };
    return JSON.stringify(data, null, 2);
  },

  importFullData: (jsonString: string): { success: boolean, message: string } => {
    try {
      const data = JSON.parse(jsonString.trim());
      if (!data.clients && !data.appointments && !data.config) {
        return { success: false, message: "Structure JSON invalide." };
      }

      db.private_saveSnapshot("Restauration Complète", "Depuis fichier/texte externe");

      if (data.clients) localStorage.setItem(KEYS.CLIENTS, JSON.stringify(data.clients));
      if (data.appointments) localStorage.setItem(KEYS.APPOINTMENTS, JSON.stringify(data.appointments));
      if (data.invoices) localStorage.setItem(KEYS.INVOICES, JSON.stringify(data.invoices));
      if (data.config) localStorage.setItem(KEYS.CONFIG, JSON.stringify(data.config));

      return { success: true, message: "Importation terminée." };
    } catch (e) {
      return { success: false, message: "Le texte n'est pas un JSON valide." };
    }
  },

  resetAll: () => {
    Object.values(KEYS).forEach(k => localStorage.removeItem(k));
    window.location.reload();
  }
};

