import Dashboard from './views/Dashboard';
import ClientList from './views/ClientList';
import Planning from './views/Planning';
import InvoicePDF from './components/InvoicePDF';
import { db } from './services/database';
import { 
  Plus, Trash2, X, Tags, Printer, Download, Upload, 
  AlertTriangle, FileText, CheckCircle, Clipboard, 
  Database, RefreshCw, HardDrive, ShieldAlert, History as HistoryIcon,
  Clock, CheckCircle2, AlertCircle
} from 'lucide-react';
import { Configuration, Invoice, Client } from './types';
import { createRoot } from 'react-dom/client';

const App: React.FC = () => {
  const [activeTab, setActiveTab] = useState('dashboard');
  const [selectedClientId, setSelectedClientId] = useState<string | null>(null);
  const [config, setConfig] = useState<Configuration>(db.getConfig());
  const [importText, setImportText] = useState('');

  const fileInputRef = useRef<HTMLInputElement>(null);

  const handlePrint = (invoice: Invoice) => {
    const clients = db.getClients();
    const client = clients.find(c => c.id === invoice.clientId);
    const printWindow = window.open('', '_blank', 'width=900,height=1200');
    if (!printWindow) return;
    printWindow.document.write(`
      <html><head><title>Facture ${invoice.number}</title><script src="https://cdn.tailwindcss.com"></script></head>
      <body><div id="root"></div></body></html>
    `);
    setTimeout(() => {
      const container = printWindow.document.getElementById('root');
      if (container) {
        const root = createRoot(container);
        root.render(<InvoicePDF invoice={invoice} client={client} />);
        setTimeout(() => printWindow.print(), 800);
      }
    }, 100);
  };

  const handleFileImport = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;
    const reader = new FileReader();
    reader.onload = (event) => {
      const content = event.target?.result as string;
      setImportText(content);
    };
    reader.readAsText(file);
  };

  const processImport = () => {
    const cleanContent = importText.trim();
    if (!cleanContent) {
      alert("Veuillez d'abord sélectionner un fichier ou coller vos données.");
      return;
    }

    if (confirm("⚠️ ATTENTION : Toutes les données actuelles seront remplacées. Continuer ?")) {
      const result = db.importFullData(cleanContent);
      if (result.success) {
        alert("✅ Données restaurées avec succès ! L'application va redémarrer.");
        window.location.reload();
      } else {
        alert("❌ Erreur d'importation : " + result.message);
      }
    }
  };

