import { Client, Appointment, Invoice, Configuration } from '../types';
import { INITIAL_CONFIG } from '../constants';

const KEYS = {
  CLIENTS: 'groom_clients',
  APPOINTMENTS: 'groom_appointments',
  INVOICES: 'groom_invoices',
  CONFIG: 'groom_config',
  HISTORY: 'groom_history',
  AUDIT: 'groom_audit_log'
};

export interface AuditEntry {
  id: string;
  timestamp: string;
  action: string;
  details: string;
}

export const db = {
  // --- SYSTÈME DE SAUVEGARDE D'ÉTAT (SNAPSHOT) ---
  private_saveSnapshot: (action: string, details: string) => {
    try {
      // On capture l'état ACTUEL avant qu'il ne soit modifié
      const stateToSave = {
        clients: db.getClients(),
        appointments: db.getAppointments(),
        invoices: db.getInvoices(),
        config: db.getConfig()
      };

      const historyStr = localStorage.getItem(KEYS.HISTORY);
      const history = historyStr ? JSON.parse(historyStr) : [];

      history.unshift(stateToSave);
      // On garde 15 versions maximum
      localStorage.setItem(KEYS.HISTORY, JSON.stringify(history.slice(0, 15)));

      // Journal d'audit
      const auditStr = localStorage.getItem(KEYS.AUDIT);
      const audit = auditStr ? JSON.parse(auditStr) : [];
      audit.unshift({
        id: Math.random().toString(36).substr(2, 9),
        timestamp: new Date().toISOString(),
        action,
        details
      });
      localStorage.setItem(KEYS.AUDIT, JSON.stringify(audit.slice(0, 50)));
    } catch (e) {
      console.warn("Espace historique saturé, suppression des anciens snapshots.");
      localStorage.removeItem(KEYS.HISTORY);
    }
  },

  undo: (): boolean => {
    try {
      const historyStr = localStorage.getItem(KEYS.HISTORY);
      if (!historyStr) return false;

      const history = JSON.parse(historyStr);
      if (history.length === 0) return false;

      const previousState = history.shift(); // Récupère le dernier snapshot
      localStorage.setItem(KEYS.HISTORY, JSON.stringify(history));

      if (previousState) {
        localStorage.setItem(KEYS.CLIENTS, JSON.stringify(previousState.clients || []));
        localStorage.setItem(KEYS.APPOINTMENTS, JSON.stringify(previousState.appointments || []));
        localStorage.setItem(KEYS.INVOICES, JSON.stringify(previousState.invoices || []));
        localStorage.setItem(KEYS.CONFIG, JSON.stringify(previousState.config || INITIAL_CONFIG));
        return true;
      }
      return false;
    } catch (e) {
      console.error("Undo error:", e);
      return false;
    }
  },

  getAuditLog: (): AuditEntry[] => {
    try {
      const data = localStorage.getItem(KEYS.AUDIT);
      return data ? JSON.parse(data) : [];
    } catch { return []; }
  },

  // --- CONFIGURATION ---
  getConfig: (): Configuration => {
    try {
      const data = localStorage.getItem(KEYS.CONFIG);
      return data ? JSON.parse(data) : INITIAL_CONFIG;
    } catch { return INITIAL_CONFIG; }
  },

  updateConfigItems: (category: keyof Configuration, items: string[]) => {
    db.private_saveSnapshot("Modif. Config", `Catégorie: ${category}`);
    const config = db.getConfig();
    if (Array.isArray(config[category])) {
      (config[category] as any) = items;
      localStorage.setItem(KEYS.CONFIG, JSON.stringify(config));
    }
  },

  // --- CLIENTS ---
  getClients: (): Client[] => {
    try {
      const data = localStorage.getItem(KEYS.CLIENTS);
      return data ? JSON.parse(data) : [];
    } catch { return []; }
  },
  saveClient: (client: Client) => {
    const clients = db.getClients();
    const index = clients.findIndex(c => c.id === client.id);
    db.private_saveSnapshot(index < 0 ? "Nouveau Client" : "Modif. Client", client.name);

    if (index >= 0) clients[index] = client;
    else clients.push(client);
    localStorage.setItem(KEYS.CLIENTS, JSON.stringify(clients));
  },
  deleteClient: (id: string) => {
    const clients = db.getClients();
    const client = clients.find(c => c.id === id);
    if (!client) return;
    db.private_saveSnapshot("Suppression Client", client.name);

    const newClients = clients.filter(c => c.id !== id);
    const newAppts = db.getAppointments().filter(a => a.clientId !== id);
    const newInvoices = db.getInvoices().filter(i => i.clientId !== id);

    localStorage.setItem(KEYS.CLIENTS, JSON.stringify(newClients));
    localStorage.setItem(KEYS.APPOINTMENTS, JSON.stringify(newAppts));
    localStorage.setItem(KEYS.INVOICES, JSON.stringify(newInvoices));
  },

  // --- RENDEZ-VOUS ---
  getAppointments: (): Appointment[] => {
    try {
      const data = localStorage.getItem(KEYS.APPOINTMENTS);
      return data ? JSON.parse(data) : [];
    } catch { return []; }
  },
  saveAppointment: (appt: Appointment) => {
    const appts = db.getAppointments();
    const index = appts.findIndex(a => a.id === appt.id);
    db.private_saveSnapshot(index < 0 ? "Nouveau RDV" : "Modif. RDV", `${appt.petName} (${appt.date})`);

    if (index >= 0) appts[index] = appt;
    else appts.push(appt);
    localStorage.setItem(KEYS.APPOINTMENTS, JSON.stringify(appts));
  },
  deleteAppointment: (id: string) => {
    const appts = db.getAppointments();
    const appt = appts.find(a => a.id === id);
    db.private_saveSnapshot("Suppression RDV", appt ? `${appt.petName} (${appt.date})` : "RDV");
    localStorage.setItem(KEYS.APPOINTMENTS, JSON.stringify(appts.filter(a => a.id !== id)));
  },

  // --- FACTURES ---
  getInvoices: (): Invoice[] => {
    try {
      const data = localStorage.getItem(KEYS.INVOICES);
      return data ? JSON.parse(data) : [];
    } catch { return []; }
  },
  saveInvoice: (invoice: Invoice) => {
    db.private_saveSnapshot("Nouvelle Facture", invoice.number);
    const invoices = db.getInvoices();
    invoices.push(invoice);
    localStorage.setItem(KEYS.INVOICES, JSON.stringify(invoices));
  },
  deleteInvoice: (id: string) => {
    const invoices = db.getInvoices();
    const inv = invoices.find(i => i.id === id);
    db.private_saveSnapshot("Suppression Facture", inv?.number || "Facture");
    localStorage.setItem(KEYS.INVOICES, JSON.stringify(invoices.filter(i => i.id !== id)));
  },

  // --- IMPORT / EXPORT AVANCÉ ---
  exportAsJSON: () => {
    const data = {
      clients: db.getClients(),
      appointments: db.getAppointments(),
      invoices: db.getInvoices(),
      config: db.getConfig(),
      metadata: {
        app: "Ka'nine v5",
        exportedAt: new Date().toISOString()
      }
    };
    return JSON.stringify(data);
  },

  importFullData: (jsonString: string): { success: boolean, message: string } => {
    try {
      const data = JSON.parse(jsonString.trim());

      // Validation stricte
      if (!data || (typeof data !== 'object')) throw new Error("Format JSON invalide.");
      if (!data.clients && !data.appointments) throw new Error("Le fichier ne contient pas de données Ka'nine.");

      // On sauvegarde l'état actuel avant l'importation
      db.private_saveSnapshot("Importation", "Restauration globale");

      // Test de stockage avant validation finale
      try {
        localStorage.setItem(KEYS.CLIENTS, JSON.stringify(data.clients || []));
        localStorage.setItem(KEYS.APPOINTMENTS, JSON.stringify(data.appointments || []));
        localStorage.setItem(KEYS.INVOICES, JSON.stringify(data.invoices || []));
        localStorage.setItem(KEYS.CONFIG, JSON.stringify(data.config || INITIAL_CONFIG));
      } catch (quotaError) {
        // Si ça échoue ici, c'est que les données sont trop lourdes pour le navigateur
        return { success: false, message: "Mémoire du navigateur saturée. Essayez d'importer un fichier sans trop de photos." };
      }

      return { success: true, message: "Importation terminée." };
    } catch (e: any) {
      return { success: false, message: e.message || "Erreur lors de la lecture des données." };
    }
  },

  resetAll: () => {
    if (confirm("⚠️ ATTENTION : Toutes vos données vont être effacées définitivement. Continuer ?")) {
      Object.values(KEYS).forEach(k => localStorage.removeItem(k));
      window.location.reload();
    }
  }
};

