import { Client, Appointment, Invoice, Configuration } from '../types';
import { INITIAL_CONFIG } from '../constants';

const KEYS = {
  CLIENTS: 'groom_clients',
  APPOINTMENTS: 'groom_appointments',
  INVOICES: 'groom_invoices',
  CONFIG: 'groom_config',
  AUDIT: 'groom_audit_log'
};

export const db = {
  logAction: (action: string, details: string) => {
    try {
      const auditStr = localStorage.getItem(KEYS.AUDIT);
      const audit = auditStr ? JSON.parse(auditStr) : [];
      audit.unshift({
        id: Math.random().toString(36).substr(2, 9),
        timestamp: new Date().toISOString(),
        action,
        details
      });
      localStorage.setItem(KEYS.AUDIT, JSON.stringify(audit.slice(0, 30)));
    } catch (e) {}
  },

  getConfig: (): Configuration & { logo?: string } => {
    try {
      const data = localStorage.getItem(KEYS.CONFIG);
      return data ? JSON.parse(data) : INITIAL_CONFIG;
    } catch { return INITIAL_CONFIG; }
  },

  saveConfig: (config: any) => {
    localStorage.setItem(KEYS.CONFIG, JSON.stringify(config));
  },

  updateConfigItems: (category: keyof Configuration, items: string[]) => {
    const config = db.getConfig();
    if (Array.isArray(config[category])) {
      (config[category] as any) = items;
      db.saveConfig(config);
    }
  },

  getClients: (): Client[] => {
    try {
      const data = localStorage.getItem(KEYS.CLIENTS);
      return data ? JSON.parse(data) : [];
    } catch { return []; }
  },

  saveClient: (client: Client) => {
    const clients = db.getClients();
    const index = clients.findIndex(c => c.id === client.id);
    if (index >= 0) clients[index] = client;
    else clients.push(client);

    try {
      localStorage.setItem(KEYS.CLIENTS, JSON.stringify(clients));
      db.logAction(index < 0 ? "Nouveau Client" : "Modif. Client", client.name);
    } catch (e) {
      alert("Erreur : Mémoire saturée. Supprimez quelques photos anciennes pour continuer.");
    }
  },

  deleteClient: (id: string) => {
    // 1. Filtrer les clients
    const clients = db.getClients().filter(c => c.id !== id);
    // 2. Filtrer les RDV liés
    const appts = db.getAppointments().filter(a => a.clientId !== id);
    // 3. Filtrer les factures liées
    const invoices = db.getInvoices().filter(i => i.clientId !== id);

    // Sauvegarde atomique (tout ou rien)
    localStorage.setItem(KEYS.CLIENTS, JSON.stringify(clients));
    localStorage.setItem(KEYS.APPOINTMENTS, JSON.stringify(appts));
    localStorage.setItem(KEYS.INVOICES, JSON.stringify(invoices));

    db.logAction("Suppression Totale", `ID: ${id}`);
    return true;
  },

  getAppointments: (): Appointment[] => {
    try {
      const data = localStorage.getItem(KEYS.APPOINTMENTS);
      return data ? JSON.parse(data) : [];
    } catch { return []; }
  },
  saveAppointment: (appt: Appointment) => {
    const appts = db.getAppointments();
    const index = appts.findIndex(a => a.id === appt.id);
    if (index >= 0) appts[index] = appt;
    else appts.push(appt);
    localStorage.setItem(KEYS.APPOINTMENTS, JSON.stringify(appts));
    db.logAction("RDV", `${appt.petName} - ${appt.date}`);
  },
  deleteAppointment: (id: string) => {
    const appts = db.getAppointments().filter(a => a.id !== id);
    localStorage.setItem(KEYS.APPOINTMENTS, JSON.stringify(appts));
  },

  getInvoices: (): Invoice[] => {
    try {
      const data = localStorage.getItem(KEYS.INVOICES);
      return data ? JSON.parse(data) : [];
    } catch { return []; }
  },
  saveInvoice: (invoice: Invoice) => {
    const invoices = db.getInvoices();
    invoices.push(invoice);
    localStorage.setItem(KEYS.INVOICES, JSON.stringify(invoices));
  },
  deleteInvoice: (id: string) => {
    const invoices = db.getInvoices().filter(i => i.id !== id);
    localStorage.setItem(KEYS.INVOICES, JSON.stringify(invoices));
  },

  importFullData: (jsonString: string): { success: boolean, message: string } => {
    try {
      const data = JSON.parse(jsonString.trim());
      if (!data.clients) throw new Error("Format invalide.");

      Object.values(KEYS).forEach(k => localStorage.removeItem(k));
      localStorage.setItem(KEYS.CLIENTS, JSON.stringify(data.clients));
      localStorage.setItem(KEYS.APPOINTMENTS, JSON.stringify(data.appointments || []));
      localStorage.setItem(KEYS.INVOICES, JSON.stringify(data.invoices || []));
      localStorage.setItem(KEYS.CONFIG, JSON.stringify(data.config || INITIAL_CONFIG));

      return { success: true, message: "Restauration terminée." };
    } catch (e: any) {
      return { success: false, message: e.message };
    }
  },

  resetAll: () => {
    if (confirm("Supprimer TOUTES les données définitivement ?")) {
      Object.values(KEYS).forEach(k => localStorage.removeItem(k));
      window.location.reload();
    }
  }
};

import { Client, Appointment, Invoice, Configuration } from '../types';
import { INITIAL_CONFIG } from '../constants';

const KEYS = {
  CLIENTS: 'groom_clients',
  APPOINTMENTS: 'groom_appointments',
  INVOICES: 'groom_invoices',
  CONFIG: 'groom_config',
  AUDIT: 'groom_audit_log'
};

export const db = {
  logAction: (action: string, details: string) => {
    try {
      const auditStr = localStorage.getItem(KEYS.AUDIT);
      const audit = auditStr ? JSON.parse(auditStr) : [];
      audit.unshift({
        id: Math.random().toString(36).substr(2, 9),
        timestamp: new Date().toISOString(),
        action,
        details
      });
      localStorage.setItem(KEYS.AUDIT, JSON.stringify(audit.slice(0, 30)));
    } catch (e) {}
  },

  getConfig: (): Configuration & { logo?: string } => {
    try {
      const data = localStorage.getItem(KEYS.CONFIG);
      return data ? JSON.parse(data) : INITIAL_CONFIG;
    } catch { return INITIAL_CONFIG; }
  },

  saveConfig: (config: any) => {
    localStorage.setItem(KEYS.CONFIG, JSON.stringify(config));
  },

  getClients: (): Client[] => {
    try {
      const data = localStorage.getItem(KEYS.CLIENTS);
      const parsed = data ? JSON.parse(data) : [];
      return Array.isArray(parsed) ? parsed : [];
    } catch { return []; }
  },

  saveClient: (client: Client) => {
    const clients = db.getClients();
    const index = clients.findIndex(c => c.id === client.id);
    if (index >= 0) clients[index] = client;
    else clients.push(client);
    localStorage.setItem(KEYS.CLIENTS, JSON.stringify(clients));
  },

  deleteClient: (id: string) => {
    // Suppression réelle dans le localStorage
    const clients = db.getClients().filter(c => c.id !== id);
    const appts = db.getAppointments().filter(a => a.clientId !== id);
    const invoices = db.getInvoices().filter(i => i.clientId !== id);

    localStorage.setItem(KEYS.CLIENTS, JSON.stringify(clients));
    localStorage.setItem(KEYS.APPOINTMENTS, JSON.stringify(appts));
    localStorage.setItem(KEYS.INVOICES, JSON.stringify(invoices));

    db.logAction("Suppression Client", `ID: ${id}`);
    return true;
  },

  getAppointments: (): Appointment[] => {
    try {
      const data = localStorage.getItem(KEYS.APPOINTMENTS);
      const parsed = data ? JSON.parse(data) : [];
      return Array.isArray(parsed) ? parsed : [];
    } catch { return []; }
  },

  saveAppointment: (appt: Appointment) => {
    const appts = db.getAppointments();
    const index = appts.findIndex(a => a.id === appt.id);
    if (index >= 0) appts[index] = appt;
    else appts.push(appt);
    localStorage.setItem(KEYS.APPOINTMENTS, JSON.stringify(appts));
  },

  deleteAppointment: (id: string) => {
    const appts = db.getAppointments().filter(a => a.id !== id);
    localStorage.setItem(KEYS.APPOINTMENTS, JSON.stringify(appts));
  },

  getInvoices: (): Invoice[] => {
    try {
      const data = localStorage.getItem(KEYS.INVOICES);
      return data ? JSON.parse(data) : [];
    } catch { return []; }
  },

  saveInvoice: (invoice: Invoice) => {
    const invoices = db.getInvoices();
    invoices.push(invoice);
    localStorage.setItem(KEYS.INVOICES, JSON.stringify(invoices));
  },

  exportAsJSON: () => {
    const data = {
      clients: db.getClients(),
      appointments: db.getAppointments(),
      invoices: db.getInvoices(),
      config: db.getConfig()
    };
    return JSON.stringify(data);
  },

  importFullData: (jsonString: string): { success: boolean, message: string } => {
    try {
      const data = JSON.parse(jsonString.trim());
      if (!data.clients || !Array.isArray(data.clients)) {
        throw new Error("Le fichier ne contient pas de liste de clients valide.");
      }

      // Nettoyage complet avant réécriture
      localStorage.clear(); 

      localStorage.setItem(KEYS.CLIENTS, JSON.stringify(data.clients));
      localStorage.setItem(KEYS.APPOINTMENTS, JSON.stringify(data.appointments || []));
      localStorage.setItem(KEYS.INVOICES, JSON.stringify(data.invoices || []));
      localStorage.setItem(KEYS.CONFIG, JSON.stringify(data.config || INITIAL_CONFIG));

      return { success: true, message: "Données restaurées avec succès." };
    } catch (e: any) {
      console.error("Import Error:", e);
      return { success: false, message: "Erreur lors de l'import : " + e.message };
    }
  }
};

import React, { useState, useEffect } from 'react';
import { db } from '../services/database';
import { Appointment, Client, Invoice } from '../types';
import { 
  Calendar as CalendarIcon, 
  Clock, 
  ChevronLeft, 
  ChevronRight, 
  Trash2, 
  Plus, 
  Euro, 
  Printer,
  AlertTriangle,
  X
} from 'lucide-react';

const generateId = () => Math.random().toString(36).substring(2, 15) + Date.now().toString(36);

interface PlanningProps {
  onPrintInvoice?: (invoice: Invoice) => void;
}

const Planning: React.FC<PlanningProps> = ({ onPrintInvoice }) => {
  const [view, setView] = useState<'day' | 'month' | 'upcoming'>('month');
  const [currentDate, setCurrentDate] = useState(new Date());
  const [appointments, setAppointments] = useState<Appointment[]>([]);
  const [clients, setClients] = useState<Client[]>([]);
  const [isModalOpen, setIsModalOpen] = useState(false);
  const [isInvoiceModalOpen, setIsInvoiceModalOpen] = useState(false);
  const [selectedAppt, setSelectedAppt] = useState<Appointment | null>(null);

  const [invoiceAmount, setInvoiceAmount] = useState('50');
  const [invoiceNotes, setInvoiceNotes] = useState('');
  const [paymentMethod, setPaymentMethod] = useState<Invoice['paymentMethod']>('Carte');

  const config = db.getConfig();

  const refreshData = () => {
    setAppointments(db.getAppointments());
    setClients(db.getClients());
  };

  useEffect(() => {
    refreshData();
  }, []);

  const formatDate = (date: Date) => date.toISOString().split('T')[0];
  const dateStr = formatDate(currentDate);

  const getDaysInMonth = (date: Date) => {
    const year = date.getFullYear();
    const month = date.getMonth();
    const firstDay = new Date(year, month, 1).getDay();
    // Monday start adjust (0 is Sunday)
    const adjustedFirstDay = firstDay === 0 ? 6 : firstDay - 1;
    const daysInMonth = new Date(year, month + 1, 0).getDate();
    return { adjustedFirstDay, daysInMonth };
  };

  const checkOverlap = (date: string, time: string, duration: number) => {
    const newStart = new Date(`${date}T${time}`).getTime();
    const newEnd = newStart + duration * 60000;

    return appointments.find(appt => {
      if (appt.date !== date || appt.status === 'cancelled') return false;
      const existStart = new Date(`${appt.date}T${appt.time}`).getTime();
      const existEnd = existStart + (appt.duration || 60) * 60000;
      return (newStart < existEnd && newEnd > existStart);
    });
  };

  const handleSaveAppt = (e: React.FormEvent<HTMLFormElement>) => {
    e.preventDefault();
    const formData = new FormData(e.currentTarget);
    const clientSelect = formData.get('client') as string;
    if (!clientSelect) return;

    const [petName, ownerName] = clientSelect.split(' - ');
    const client = clients.find(c => c.name === petName && c.ownerName === ownerName);

    const date = formData.get('date') as string;
    const time = formData.get('time') as string;
    const duration = parseInt(formData.get('duration') as string);

    // BLOCAGE DÉFINITIF DES DOUBLONS
    const conflict = checkOverlap(date, time, duration);
    if (conflict) {
      alert(`⚠️ CONFLIT DÉTECTÉ : Un rendez-vous existe déjà pour ${conflict.petName} à ${conflict.time} (durée ${conflict.duration}min). Veuillez choisir un autre créneau.`);
      return; // Stop l'enregistrement
    }

    const newAppt: Appointment = {
      id: generateId(),
      date,
      time,
      clientId: client?.id || '',
      clientName: ownerName,
      petName: petName,
      service: formData.get('service') as string,
      notes: formData.get('notes') as string,
      duration,
      status: 'pending'
    };

    db.saveAppointment(newAppt);
    refreshData();
    setIsModalOpen(false);
  };

  const handleConfirmInvoice = () => {
    if (!selectedAppt) return;
    const newInvoice: Invoice = {
      id: generateId(),
      number: `FAC-${Date.now().toString().slice(-6)}`,
      date: formatDate(new Date()),
      clientId: selectedAppt.clientId,
      petName: selectedAppt.petName,
      ownerName: selectedAppt.clientName,
      amount: parseFloat(invoiceAmount),
      paymentMethod,
      appointmentId: selectedAppt.id,
      notes: invoiceNotes || selectedAppt.notes
    };
    db.saveInvoice(newInvoice);
    db.saveAppointment({ ...selectedAppt, status: 'invoiced' });
    refreshData();
    setIsInvoiceModalOpen(false);
    if(confirm("Facture émise. Imprimer ?")) onPrintInvoice?.(newInvoice);
  };

  const { adjustedFirstDay, daysInMonth } = getDaysInMonth(currentDate);
  const calendarDays = [];

  // Remplissage des cases vides au début
  for (let i = 0; i < adjustedFirstDay; i++) calendarDays.push(null);
  // Jours du mois
  for (let i = 1; i <= daysInMonth; i++) calendarDays.push(i);
  // Remplissage jusqu'à 42 pour avoir 6 lignes complètes systématiquement
  while (calendarDays.length < 42) calendarDays.push(null);

  return (
    <div className="space-y-6 flex flex-col h-full min-h-0 bg-slate-50/50 p-6 rounded-[2.5rem]">
      <div className="flex flex-col lg:flex-row items-center justify-between gap-4 shrink-0">
        <div className="flex items-center gap-2 bg-white p-1.5 rounded-2xl shadow-sm border border-slate-100">
          <button onClick={() => setView('month')} className={`px-5 py-2.5 rounded-xl text-xs font-black transition-all uppercase tracking-widest ${view === 'month' ? 'bg-indigo-600 text-white shadow-lg' : 'text-slate-400 hover:bg-slate-50'}`}>Mois</button>
          <button onClick={() => setView('upcoming')} className={`px-5 py-2.5 rounded-xl text-xs font-black transition-all uppercase tracking-widest ${view === 'upcoming' ? 'bg-indigo-600 text-white shadow-lg' : 'text-slate-400 hover:bg-slate-50'}`}>À Venir</button>
        </div>

        <div className="flex items-center gap-6">
          <div className="flex items-center gap-4 bg-white px-6 py-2 rounded-2xl border border-slate-100 shadow-sm">
            <button onClick={() => { 
              const d = new Date(currentDate); 
              d.setMonth(d.getMonth() - 1); 
              setCurrentDate(d); 
            }} className="p-2 hover:bg-slate-50 rounded-full transition-colors"><ChevronLeft size={20} /></button>
            <h3 className="text-sm font-black text-slate-900 uppercase tracking-tighter w-32 text-center">
              {currentDate.toLocaleDateString('fr-FR', { month: 'long', year: 'numeric' })}
            </h3>
            <button onClick={() => { 
              const d = new Date(currentDate); 
              d.setMonth(d.getMonth() + 1); 
              setCurrentDate(d); 
            }} className="p-2 hover:bg-slate-50 rounded-full transition-colors"><ChevronRight size={20} /></button>
          </div>
          <button onClick={() => setIsModalOpen(true)} className="flex items-center gap-3 px-6 py-3 bg-indigo-600 text-white rounded-2xl font-black text-sm uppercase tracking-widest shadow-xl shadow-indigo-100 hover:scale-105 active:scale-95 transition-all">
            <Plus size={20} /> Nouveau RDV
          </button>
        </div>
      </div>

      <div className="flex-1 min-h-0 overflow-y-auto">
        {view === 'month' ? (
          <div className="bg-white rounded-[2.5rem] border border-slate-100 shadow-sm overflow-hidden flex flex-col">
            <div className="calendar-grid border-b border-slate-50 bg-slate-50/50">
              {['Lun', 'Mar', 'Mer', 'Jeu', 'Ven', 'Sam', 'Dim'].map(day => (
                <div key={day} className="py-4 text-center text-[10px] font-black text-slate-400 uppercase tracking-[0.2em]">{day}</div>
              ))}
            </div>
            <div className="calendar-grid flex-1 overflow-y-auto">
              {calendarDays.map((day, i) => {
                const dayStr = day ? formatDate(new Date(currentDate.getFullYear(), currentDate.getMonth(), day)) : '';
                const dayAppts = appointments.filter(a => a.date === dayStr);
                const isToday = dayStr === formatDate(new Date());

                return (
                  <div key={i} className={`min-h-[120px] p-2 border-r border-b border-slate-50 relative group transition-colors ${day ? 'hover:bg-slate-50/50' : 'bg-slate-50/20'}`}>
                    {day && (
                      <>
                        <span className={`text-xs font-black ${isToday ? 'bg-indigo-600 text-white px-2 py-1 rounded-lg' : 'text-slate-300'} mb-2 inline-block`}>{day}</span>
                        <div className="space-y-1">
                          {dayAppts.map(appt => (
                            <button key={appt.id} onClick={() => { setSelectedAppt(appt); setView('day'); setCurrentDate(new Date(appt.date)); }} className={`w-full text-left px-2 py-1.5 rounded-lg text-[10px] font-bold truncate transition-all ${appt.status === 'invoiced' ? 'bg-emerald-50 text-emerald-700 border border-emerald-100' : 'bg-indigo-50 text-indigo-700 border border-indigo-100'}`}>
                              {appt.time} • {appt.petName}
                            </button>
                          ))}
                        </div>
                      </>
                    )}
                  </div>
                );
              })}
            </div>
          </div>
        ) : (
          <div className="max-w-4xl mx-auto space-y-4 pb-10">
            {appointments
              .filter(a => view === 'upcoming' ? a.date >= formatDate(new Date()) : a.date === dateStr)
              .sort((a, b) => a.date.localeCompare(b.date) || a.time.localeCompare(b.time))
              .map(appt => (
                <div key={appt.id} className="flex items-center gap-6 p-6 rounded-3xl border border-slate-100 bg-white hover:border-indigo-100 transition-all shadow-sm group">
                  <div className="w-24 text-center border-r border-slate-50 pr-6">
                    <p className="text-[10px] font-black text-indigo-400 uppercase tracking-widest">{new Date(appt.date).toLocaleDateString('fr-FR', { weekday: 'short', day: 'numeric' })}</p>
                    <p className="text-xl font-black text-slate-800 tracking-tighter">{appt.time}</p>
                  </div>
                  <div className="flex-1">
                    <div className="flex items-center gap-3 mb-1">
                      <h4 className="text-lg font-black text-slate-900 uppercase italic tracking-tighter">{appt.petName}</h4>
                      <span className="px-3 py-1 bg-slate-900 text-white text-[9px] font-black uppercase rounded-full tracking-widest">{appt.service}</span>
                    </div>
                    <p className="text-xs text-slate-400 font-bold flex items-center gap-2 uppercase tracking-widest">
                      <Clock size={12}/> {appt.duration} MIN • {appt.clientName}
                    </p>
                  </div>
                  <div className="flex items-center gap-2">
                    {appt.status !== 'invoiced' ? (
                      <button onClick={() => { setSelectedAppt(appt); setInvoiceAmount('50'); setIsInvoiceModalOpen(true); }} className="flex items-center gap-2 px-6 py-3 bg-emerald-600 text-white rounded-2xl text-xs font-black uppercase tracking-widest hover:bg-emerald-700 shadow-lg shadow-emerald-50 transition-all">
                        <Euro size={16} /> Facturer
                      </button>
                    ) : (
                      <div className="flex items-center gap-2">
                         <span className="text-[10px] font-black text-emerald-500 bg-emerald-50 px-3 py-2 rounded-xl uppercase border border-emerald-100">Payé</span>
                         <button onClick={() => { const inv = db.getInvoices().find(i => i.appointmentId === appt.id); if(inv) onPrintInvoice?.(inv); }} className="p-3 bg-slate-100 text-slate-600 rounded-2xl hover:bg-slate-200 transition-colors"><Printer size={18} /></button>
                      </div>
                    )}
                    <button onClick={() => { if(confirm("Supprimer ce RDV ?")) { db.deleteAppointment(appt.id); refreshData(); } }} className="p-3 text-slate-300 hover:text-red-500 hover:bg-red-50 rounded-2xl transition-all opacity-0 group-hover:opacity-100"><Trash2 size={20}/></button>
                  </div>
                </div>
              ))
            }
          </div>
        )}
      </div>

      {/* Modal Nouveau RDV */}
      {isModalOpen && (
        <div className="fixed inset-0 z-[100] bg-slate-900/60 backdrop-blur-sm flex items-center justify-center p-4">
          <div className="bg-white w-full max-w-xl rounded-[3rem] shadow-2xl overflow-hidden border border-white/20">
            <form onSubmit={handleSaveAppt} className="p-10 space-y-8">
              <div className="flex justify-between items-center mb-2">
                <h2 className="text-3xl font-black text-slate-900 uppercase tracking-tighter italic">Nouveau Rendez-vous</h2>
                <button type="button" onClick={() => setIsModalOpen(false)} className="p-3 hover:bg-slate-100 rounded-2xl transition-colors"><X size={24}/></button>
              </div>

              <div className="space-y-6">
                <div className="space-y-2">
                  <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest px-1">Choisir un Client</label>
                  <select name="client" required className="w-full px-6 py-4 bg-slate-50 border border-slate-100 rounded-2xl font-black text-slate-800 outline-none focus:ring-4 ring-indigo-50 transition-all">
                    <option value="">Sélectionner...</option>
                    {clients.map(c => <option key={c.id} value={`${c.name} - ${c.ownerName}`}>{c.name} ({c.ownerName})</option>)}
                  </select>
                </div>

                <div className="grid grid-cols-2 gap-6">
                  <div className="space-y-2">
                    <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest px-1">Date</label>
                    <input type="date" name="date" defaultValue={dateStr} required className="w-full px-6 py-4 bg-slate-50 border border-slate-100 rounded-2xl font-black text-slate-800 outline-none" />
                  </div>
                  <div className="space-y-2">
                    <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest px-1">Heure</label>
                    <input type="time" name="time" defaultValue="09:00" required className="w-full px-6 py-4 bg-slate-50 border border-slate-100 rounded-2xl font-black text-slate-800 outline-none" />
                  </div>
                </div>

                <div className="grid grid-cols-2 gap-6">
                  <div className="space-y-2">
                    <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest px-1">Soin</label>
                    <select name="service" required className="w-full px-6 py-4 bg-slate-50 border border-slate-100 rounded-2xl font-black text-slate-800 outline-none">
                      {config.services.map(s => <option key={s} value={s}>{s}</option>)}
                    </select>
                  </div>
                  <div className="space-y-2">
                    <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest px-1">Durée (minutes)</label>
                    <input type="number" name="duration" defaultValue="60" step="15" className="w-full px-6 py-4 bg-slate-50 border border-slate-100 rounded-2xl font-black text-slate-800 outline-none" />
                  </div>
                </div>

                <textarea name="notes" placeholder="Notes particulières..." className="w-full px-6 py-4 bg-slate-50 border border-slate-100 rounded-2xl text-sm font-medium h-24 outline-none"></textarea>
              </div>

              <button type="submit" className="w-full py-6 bg-indigo-600 text-white rounded-[2rem] font-black text-xl uppercase tracking-widest shadow-2xl shadow-indigo-200 hover:bg-indigo-700 transition-all active:scale-[0.98]">
                Confirmer le Rendez-vous
              </button>
            </form>
          </div>
        </div>
      )}

      {/* Modal Facturation Rapide */}
      {isInvoiceModalOpen && selectedAppt && (
        <div className="fixed inset-0 z-[100] bg-slate-900/60 backdrop-blur-sm flex items-center justify-center p-4">
           <div className="bg-white w-full max-w-lg rounded-[3rem] shadow-2xl overflow-hidden">
             <div className="p-10 space-y-8">
                <div className="flex justify-between items-center">
                   <h2 className="text-3xl font-black text-slate-900 uppercase tracking-tighter italic">Émettre Facture</h2>
                   <button onClick={() => setIsInvoiceModalOpen(false)} className="p-3 hover:bg-slate-100 rounded-2xl"><X size={24}/></button>
                </div>

                <div className="p-6 bg-slate-50 rounded-3xl border border-slate-100">
                   <p className="text-[10px] font-black text-slate-400 uppercase tracking-widest mb-1">Prestation pour</p>
                   <p className="text-xl font-black text-slate-900">{selectedAppt.petName} ({selectedAppt.clientName})</p>
                </div>

                <div className="space-y-6">
                   <div className="space-y-2">
                      <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest px-1">Montant TTC (€)</label>
                      <input type="number" value={invoiceAmount} onChange={e => setInvoiceAmount(e.target.value)} className="w-full px-8 py-5 bg-indigo-50 border-2 border-indigo-100 rounded-[2rem] font-black text-3xl text-indigo-600 text-center outline-none" />
                   </div>

                   <div className="space-y-2">
                      <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest px-1">Mode de Règlement</label>
                      <div className="grid grid-cols-2 gap-3">
                         {['Carte', 'Espèces', 'Chèque', 'Virement'].map(m => (
                           <button key={m} onClick={() => setPaymentMethod(m as any)} className={`py-4 rounded-2xl text-xs font-black uppercase tracking-widest border-2 transition-all ${paymentMethod === m ? 'bg-slate-900 text-white border-slate-900 shadow-xl' : 'bg-white text-slate-400 border-slate-100 hover:bg-slate-50'}`}>
                             {m}
                           </button>
                         ))}
                      </div>
                   </div>
                </div>

