          </div>
          <button onClick={() => { setSelectedClient(null); setIsEditing(true); setFormSpecies('Chien'); setHistory([]); }} className="p-3 bg-indigo-600 text-white rounded-2xl shadow-lg shadow-indigo-100 hover:scale-105 transition-all"><Plus size={24} /></button>
        </div>
        <div className="flex-1 overflow-y-auto space-y-3 pr-2">
          {filteredClients.map(client => (
            <button key={client.id} onClick={() => { setSelectedClient(client); setIsEditing(false); setFormSpecies(client.species); loadHistory(client.id); }} className={`w-full text-left p-5 rounded-2xl transition-all border-2 ${selectedClient?.id === client.id ? 'bg-indigo-50 border-indigo-200' : 'bg-white border-transparent hover:bg-slate-50'}`}>
              <h4 className="font-black text-slate-900 uppercase tracking-tighter italic">{client.name}</h4>
              <p className="text-[10px] text-slate-400 font-bold uppercase tracking-widest">{client.ownerName} • {client.species}</p>
            </button>
          ))}
        </div>
      </div>

      {/* Main Content Area */}
