      const auditStr = localStorage.getItem(KEYS.AUDIT);
      return auditStr ? JSON.parse(auditStr) : [];
    } catch { return []; }
  },

  getConfig: (): Configuration & { logo?: string } => {
    try {
      const data = localStorage.getItem(KEYS.CONFIG);
      return data ? JSON.parse(data) : INITIAL_CONFIG;
    } catch { return INITIAL_CONFIG; }
  },

  saveConfig: (config: any) => {
    localStorage.setItem(KEYS.CONFIG, JSON.stringify(config));
  },

  updateConfigItems: (key: keyof Configuration, items: string[]) => {
    const config = db.getConfig();
    (config as any)[key] = items;
    db.saveConfig(config);
  },

  getClients: (): Client[] => {
    try {
      const data = localStorage.getItem(KEYS.CLIENTS);
      const parsed = data ? JSON.parse(data) : [];
      return Array.isArray(parsed) ? parsed : [];
    } catch { return []; }
  },

  saveClient: (client: Client) => {
    const clients = db.getClients();
    const index = clients.findIndex(c => c.id === client.id);
    if (index >= 0) clients[index] = client;
    else clients.push(client);
    localStorage.setItem(KEYS.CLIENTS, JSON.stringify(clients));
  },

  deleteClient: (id: string) => {
    const clients = db.getClients().filter(c => c.id !== id);
    const appts = db.getAppointments().filter(a => a.clientId !== id);
    const invoices = db.getInvoices().filter(i => i.clientId !== id);

    localStorage.setItem(KEYS.CLIENTS, JSON.stringify(clients));
    localStorage.setItem(KEYS.APPOINTMENTS, JSON.stringify(appts));
    localStorage.setItem(KEYS.INVOICES, JSON.stringify(invoices));

    db.logAction("Suppression Client", `ID: ${id}`);
    return true;
  },

  getAppointments: (): Appointment[] => {
    try {
      const data = localStorage.getItem(KEYS.APPOINTMENTS);
      const parsed = data ? JSON.parse(data) : [];
      return Array.isArray(parsed) ? parsed : [];
    } catch { return []; }
  },

  saveAppointment: (appt: Appointment) => {
    const appts = db.getAppointments();
    const index = appts.findIndex(a => a.id === appt.id);
    if (index >= 0) appts[index] = appt;
    else appts.push(appt);
    localStorage.setItem(KEYS.APPOINTMENTS, JSON.stringify(appts));
  },

  deleteAppointment: (id: string) => {
    const appts = db.getAppointments().filter(a => a.id !== id);
    localStorage.setItem(KEYS.APPOINTMENTS, JSON.stringify(appts));
  },

  getInvoices: (): Invoice[] => {
    try {
      const data = localStorage.getItem(KEYS.INVOICES);
      return data ? JSON.parse(data) : [];
    } catch { return []; }
  },

  saveInvoice: (invoice: Invoice) => {
    const invoices = db.getInvoices();
    invoices.push(invoice);
    localStorage.setItem(KEYS.INVOICES, JSON.stringify(invoices));
  },

  deleteInvoice: (id: string) => {
    const invoices = db.getInvoices().filter(i => i.id !== id);
    localStorage.setItem(KEYS.INVOICES, JSON.stringify(invoices));
    db.logAction("Suppression Facture", `ID: ${id}`);
  },

  exportAsJSON: () => {
    const data = {
      clients: db.getClients(),
      appointments: db.getAppointments(),
      invoices: db.getInvoices(),
      config: db.getConfig()
    };
    return JSON.stringify(data);
  },

  importFullData: (jsonString: string): ImportResult => {
    const logs: string[] = [];
    const log = (msg: string) => logs.push(`[${new Date().toLocaleTimeString()}] ${msg}`);

    try {
      log("Début de l'importation...");
      if (!jsonString || jsonString.trim() === "") throw new Error("Le contenu est vide.");

      log("Analyse du format JSON...");
      const data = JSON.parse(jsonString.trim());

      log("Vérification de la structure...");
      if (!data.clients || !Array.isArray(data.clients)) {
        throw new Error("La clé 'clients' est absente ou n'est pas une liste.");
      }

      log(`Structure validée : ${data.clients.length} clients trouvés.`);
      log(`Vérification RDV : ${data.appointments?.length || 0} trouvés.`);
      log(`Vérification Factures : ${data.invoices?.length || 0} trouvées.`);

      log("Préparation du stockage local...");
      // On teste d'abord si on peut tout stringifier (vérification mémoire)
      const clientsStr = JSON.stringify(data.clients);
      const apptsStr = JSON.stringify(data.appointments || []);
      const invsStr = JSON.stringify(data.invoices || []);
      const configStr = JSON.stringify(data.config || INITIAL_CONFIG);

      log("Nettoyage de l'ancienne base...");
      localStorage.clear();

      log("Injection des nouvelles données...");
      localStorage.setItem(KEYS.CLIENTS, clientsStr);
      localStorage.setItem(KEYS.APPOINTMENTS, apptsStr);
      localStorage.setItem(KEYS.INVOICES, invsStr);
      localStorage.setItem(KEYS.CONFIG, configStr);

      log("Opération terminée avec succès.");
      return { success: true, message: "Données restaurées.", logs };
    } catch (e: any) {
      log(`ERREUR CRITIQUE : ${e.message}`);
      console.error("Import error details:", e);
      return { success: false, message: e.message, logs };
    }
  },

  resetAll: () => {
    if (window.confirm("🚨 Voulez-vous vraiment TOUT supprimer ? Cette action est irréversible.")) {
      localStorage.clear();
      window.location.reload();
    }
  }
};

import React, { useState, useRef } from 'react';
import Layout from './components/Layout';
import Dashboard from './views/Dashboard';
import ClientList from './views/ClientList';
import Planning from './views/Planning';
import InvoicePDF from './components/InvoicePDF';
import { db } from './services/database';
import { 
  Trash2, Printer, Download, Upload, FileText, 
  Database, History as HistoryIcon,
  AlertCircle, Save, Camera, ImageIcon, X,
  Terminal, CheckCircle2
} from 'lucide-react';
import { Invoice } from './types';
import { createRoot } from 'react-dom/client';

const App: React.FC = () => {
  const [activeTab, setActiveTab] = useState('dashboard');
  const [selectedClientId, setSelectedClientId] = useState<string | null>(null);
  const [config, setConfig] = useState(db.getConfig());
  const [importLogs, setImportLogs] = useState<string[]>([]);
  const [isImporting, setIsImporting] = useState(false);

  const fileInputRef = useRef<HTMLInputElement>(null);
  const logoInputRef = useRef<HTMLInputElement>(null);

  const handlePrint = (invoice: Invoice) => {
    const clients = db.getClients();
    const client = clients.find(c => c.id === invoice.clientId);
    const printWindow = window.open('', '_blank', 'width=900,height=1200');
    if (!printWindow) return;
    printWindow.document.write(`
      <html><head><title>Facture ${invoice.number}</title><script src="https://cdn.tailwindcss.com"></script></head>
      <body><div id="root"></div></body></html>
    `);
    setTimeout(() => {
      const container = printWindow.document.getElementById('root');
      if (container) {
        const root = createRoot(container);
        root.render(<InvoicePDF invoice={invoice} client={client} />);
        setTimeout(() => printWindow.print(), 800);
      }
    }, 100);
  };

  const handleLogoUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;
    const reader = new FileReader();
    reader.onloadend = () => {
      const base64 = reader.result as string;
      const newConfig = { ...config, logo: base64 };
      db.saveConfig(newConfig);
      setConfig(newConfig);
      alert("Logo mis à jour.");
    };
    reader.readAsDataURL(file);
  };

  const handleFileImport = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;

    setIsImporting(true);
    setImportLogs([`[${new Date().toLocaleTimeString()}] Fichier sélectionné : ${file.name}`]);

    const reader = new FileReader();
    reader.onload = (event) => {
      const content = event.target?.result as string;
      const result = db.importFullData(content);
      setImportLogs(result.logs);
      if (result.success) {
        setTimeout(() => window.location.reload(), 2000);
      }
      setIsImporting(false);
    };
    reader.onerror = () => {
      setImportLogs(prev => [...prev, "ERREUR : Impossible de lire le fichier."]);
      setIsImporting(false);
    };
    reader.readAsText(file);
