              </div>
            </div>

            <div className="flex items-center justify-between md:justify-end gap-10 border-t md:border-t-0 pt-4 md:pt-0">
               <div className="text-right">
                  <p className="text-[10px] font-black text-slate-400 uppercase tracking-widest mb-1">Montant TTC</p>
                  <p className="text-2xl font-black text-slate-900">{inv.amount.toFixed(2)}€</p>
               </div>
               <div className="flex gap-2">
                  <button onClick={() => handlePrint(inv)} className="p-4 bg-indigo-600 text-white rounded-2xl hover:bg-indigo-700 shadow-lg shadow-indigo-100 transition-all active:scale-90">
                    <Printer size={20} />
                  </button>
                  <button onClick={() => { if(confirm("Supprimer ?")) { db.deleteInvoice(inv.id); window.location.reload(); } }} className="p-4 text-red-400 hover:bg-red-50 rounded-2xl transition-all">
                    <Trash2 size={20} />
                  </button>
               </div>
            </div>
          </div>
        ))}
      </div>
    </div>
  );

  return (
