      link.href = url;
      link.download = `kanine_sauvegarde_${new Date().toISOString().split('T')[0]}.json`;

      document.body.appendChild(link);
      link.click();

      // Petit délai pour laisser le navigateur initier le téléchargement avant de révoquer
      setTimeout(() => {
        document.body.removeChild(link);
        window.URL.revokeObjectURL(url);
