                  <button onClick={() => { if(confirm("Supprimer ?")) { db.deleteInvoice(inv.id); window.location.reload(); } }} className="p-4 text-red-400 hover:bg-red-50 rounded-2xl transition-all">
                    <Trash2 size={20} />
