import { Client, Appointment, Invoice, Configuration } from '../types';
import { INITIAL_CONFIG } from '../constants';

const KEYS = {
  CLIENTS: 'groom_clients',
  APPOINTMENTS: 'groom_appointments',
  INVOICES: 'groom_invoices',
  CONFIG: 'groom_config',
  AUDIT: 'groom_audit_log'
};

export interface ImportResult {
  success: boolean;
  message: string;
  logs: string[];
}

export const db = {
  logAction: (action: string, details: string) => {
    try {
      const auditStr = localStorage.getItem(KEYS.AUDIT);
      const audit = auditStr ? JSON.parse(auditStr) : [];
      audit.unshift({
        id: Math.random().toString(36).substr(2, 9),
        timestamp: new Date().toISOString(),
        action,
        details
      });
      localStorage.setItem(KEYS.AUDIT, JSON.stringify(audit.slice(0, 30)));
    } catch (e) {}
  },

  getAuditLog: (): any[] => {
    try {
      const auditStr = localStorage.getItem(KEYS.AUDIT);
      return auditStr ? JSON.parse(auditStr) : [];
    } catch { return []; }
  },

  getConfig: (): Configuration & { logo?: string } => {
    try {
      const data = localStorage.getItem(KEYS.CONFIG);
      return data ? JSON.parse(data) : INITIAL_CONFIG;
    } catch { return INITIAL_CONFIG; }
  },

  saveConfig: (config: any) => {
    localStorage.setItem(KEYS.CONFIG, JSON.stringify(config));
  },

  updateConfigItems: (key: keyof Configuration, items: string[]) => {
    const config = db.getConfig();
    (config as any)[key] = items;
    db.saveConfig(config);
  },

  getClients: (): Client[] => {
    try {
      const data = localStorage.getItem(KEYS.CLIENTS);
      const parsed = data ? JSON.parse(data) : [];
      return Array.isArray(parsed) ? parsed : [];
    } catch { return []; }
  },

  saveClient: (client: Client) => {
    const clients = db.getClients();
    const index = clients.findIndex(c => c.id === client.id);
    if (index >= 0) clients[index] = client;
    else clients.push(client);
    localStorage.setItem(KEYS.CLIENTS, JSON.stringify(clients));
  },

  deleteClient: (id: string) => {
    const clients = db.getClients().filter(c => c.id !== id);
    const appts = db.getAppointments().filter(a => a.clientId !== id);
    const invoices = db.getInvoices().filter(i => i.clientId !== id);

    localStorage.setItem(KEYS.CLIENTS, JSON.stringify(clients));
    localStorage.setItem(KEYS.APPOINTMENTS, JSON.stringify(appts));
    localStorage.setItem(KEYS.INVOICES, JSON.stringify(invoices));

    db.logAction("Suppression Client", `ID: ${id}`);
    return true;
  },

  getAppointments: (): Appointment[] => {
    try {
      const data = localStorage.getItem(KEYS.APPOINTMENTS);
      const parsed = data ? JSON.parse(data) : [];
      return Array.isArray(parsed) ? parsed : [];
    } catch { return []; }
  },

  saveAppointment: (appt: Appointment) => {
    const appts = db.getAppointments();
    const index = appts.findIndex(a => a.id === appt.id);
    if (index >= 0) appts[index] = appt;
    else appts.push(appt);
    localStorage.setItem(KEYS.APPOINTMENTS, JSON.stringify(appts));
  },

  deleteAppointment: (id: string) => {
    const appts = db.getAppointments().filter(a => a.id !== id);
    localStorage.setItem(KEYS.APPOINTMENTS, JSON.stringify(appts));
  },

  getInvoices: (): Invoice[] => {
    try {
      const data = localStorage.getItem(KEYS.INVOICES);
      return data ? JSON.parse(data) : [];
    } catch { return []; }
  },

  saveInvoice: (invoice: Invoice) => {
    const invoices = db.getInvoices();
    invoices.push(invoice);
    localStorage.setItem(KEYS.INVOICES, JSON.stringify(invoices));
  },

  deleteInvoice: (id: string) => {
    const invoices = db.getInvoices().filter(i => i.id !== id);
    localStorage.setItem(KEYS.INVOICES, JSON.stringify(invoices));
    db.logAction("Suppression Facture", `ID: ${id}`);
  },

  exportAsJSON: () => {
    const data = {
      clients: db.getClients(),
      appointments: db.getAppointments(),
      invoices: db.getInvoices(),
      config: db.getConfig()
    };
    return JSON.stringify(data);
  },

  // Export CSV léger pour les clients (Sans images)
  exportClientsCSV: () => {
    const clients = db.getClients();
    const headers = ["Nom Animal", "Espece", "Race", "Type Poil", "Proprietaire", "Telephone", "Email", "Adresse", "Notes"];
    const rows = clients.map(c => [
      c.name, c.species, c.breed, c.coatType, c.ownerName, 
      `'${c.phone}`, // Force le format texte pour Excel
      c.email, c.address?.replace(/;/g, ','), c.notes?.replace(/[\r\n;]/g, ' ')
    ]);
    return [headers, ...rows].map(e => e.join(";")).join("\n");
  },

  // Export CSV pour la comptabilité
  exportInvoicesCSV: () => {
    const invoices = db.getInvoices();
    const headers = ["Numero", "Date", "Animal", "Proprietaire", "Montant", "Paiement", "Notes"];
    const rows = invoices.map(inv => [
      inv.number, inv.date, inv.petName, inv.ownerName, inv.amount, inv.paymentMethod, inv.notes?.replace(/[\r\n;]/g, ' ')
    ]);
    return [headers, ...rows].map(e => e.join(";")).join("\n");
  },

  importFullData: (jsonString: string): ImportResult => {
    const logs: string[] = [];
    const log = (msg: string) => logs.push(`[${new Date().toLocaleTimeString()}] ${msg}`);

    try {
      const rawSize = (jsonString.length / 1024 / 1024).toFixed(2);
      log(`Fichier chargé : ${rawSize} Mo`);

      if (!jsonString || jsonString.trim() === "") throw new Error("Le contenu est vide.");

      log("Analyse du JSON...");
      const data = JSON.parse(jsonString.trim());

      log("Validation des clés...");
      if (!data.clients || !Array.isArray(data.clients)) throw new Error("Format invalide (Clé 'clients' manquante).");

      log(`${data.clients.length} clients détectés.`);

      log("Écriture définitive...");
      localStorage.setItem(KEYS.CLIENTS, JSON.stringify(data.clients));
      localStorage.setItem(KEYS.APPOINTMENTS, JSON.stringify(data.appointments || []));
      localStorage.setItem(KEYS.INVOICES, JSON.stringify(data.invoices || []));
      localStorage.setItem(KEYS.CONFIG, JSON.stringify(data.config || INITIAL_CONFIG));

      log("SYNK : Données synchronisées avec succès.");
      return { success: true, message: "OK", logs };
    } catch (e: any) {
      log(`ERREUR : ${e.message}`);
      return { success: false, message: e.message, logs };
    }
  },

  resetAll: () => {
    if (window.confirm("🚨 ATTENTION : Voulez-vous vraiment TOUT effacer ?")) {
      localStorage.clear();
      window.location.reload();
    }
  }
};

import React, { useState, useRef } from 'react';
import Layout from './components/Layout';
import Dashboard from './views/Dashboard';
import ClientList from './views/ClientList';
import Planning from './views/Planning';
import InvoicePDF from './components/InvoicePDF';
import { db } from './services/database';
import { 
  Trash2, Printer, Download, Upload, FileText, 
  Database, History as HistoryIcon,
  AlertCircle, Save, Camera, ImageIcon, X,
  Terminal, CheckCircle2, ShieldCheck, Loader2,
  FileSpreadsheet, FileJson
} from 'lucide-react';
import { Invoice } from './types';
import { createRoot } from 'react-dom/client';

const App: React.FC = () => {
  const [activeTab, setActiveTab] = useState('dashboard');
  const [selectedClientId, setSelectedClientId] = useState<string | null>(null);
  const [config, setConfig] = useState(db.getConfig());
  const [importLogs, setImportLogs] = useState<string[]>([]);
  const [isImporting, setIsImporting] = useState(false);
  const [status, setStatus] = useState<'idle' | 'preparing' | 'success'>('idle');

  const fileInputRef = useRef<HTMLInputElement>(null);
  const logoInputRef = useRef<HTMLInputElement>(null);

  const handlePrint = (invoice: Invoice) => {
    const clients = db.getClients();
    const client = clients.find(c => c.id === invoice.clientId);
    const printWindow = window.open('', '_blank', 'width=900,height=1200');
    if (!printWindow) return;
    printWindow.document.write(`
      <html><head><title>Facture ${invoice.number}</title><script src="https://cdn.tailwindcss.com"></script></head>
      <body><div id="root"></div></body></html>
    `);
    setTimeout(() => {
      const container = printWindow.document.getElementById('root');
      if (container) {
        const root = createRoot(container);
        root.render(<InvoicePDF invoice={invoice} client={client} />);
        setTimeout(() => printWindow.print(), 800);
      }
    }, 100);
  };

  const downloadCSV = (content: string, filename: string) => {
    try {
      // Ajout du BOM UTF-8 pour le support des accents dans Excel
      const blob = new Blob(["\ufeff" + content], { type: 'text/csv;charset=utf-8;' });
      const url = window.URL.createObjectURL(blob);
      const link = document.createElement('a');
      link.href = url;
      link.setAttribute('download', filename);
      document.body.appendChild(link);
      link.click();
      document.body.removeChild(link);
      window.URL.revokeObjectURL(url);
      setStatus('success');
      setTimeout(() => setStatus('idle'), 2000);
    } catch (e) {
      alert("Erreur export : " + e);
    }
  };

  const handleFileExportJSON = () => {
    setStatus('preparing');
    setTimeout(() => {
      try {
        const json = db.exportAsJSON();
        const blob = new Blob([json], { type: 'application/json' });
        const url = window.URL.createObjectURL(blob);
        const link = document.createElement('a');
        link.href = url;
        link.download = `kanine_full_backup_${new Date().toISOString().split('T')[0]}.json`;
        document.body.appendChild(link);
        link.click();

        setStatus('success');
        setTimeout(() => {
          if (document.body.contains(link)) document.body.removeChild(link);
          window.URL.revokeObjectURL(url);
          setStatus('idle');
        }, 10000);
      } catch (e) {
        alert("Erreur mémoire JSON : Fichier trop lourd. Utilisez l'export CSV pour vos données texte.");
        setStatus('idle');
      }
    }, 100);
  };

  const handleFileImport = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;
    setIsImporting(true);
    const reader = new FileReader();
    reader.onload = (event) => {
      const content = event.target?.result as string;
      const result = db.importFullData(content);
      setImportLogs(result.logs);
      if (result.success) alert("Importation réussie ! L'application va redémarrer.");
      setIsImporting(false);
      window.location.reload();
    };
    reader.readAsText(file);
  };

  const handleLogoUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;
    const reader = new FileReader();
    reader.onloadend = () => {
      const base64 = reader.result as string;
      const newConfig = { ...config, logo: base64 };
      db.saveConfig(newConfig);
      setConfig(newConfig);
      alert("Logo mis à jour.");
    };
    reader.readAsDataURL(file);
