export default App;

import { Client, Appointment, Invoice, Configuration } from '../types';
import { INITIAL_CONFIG } from '../constants';

const KEYS = {
  CLIENTS: 'groom_clients',
  APPOINTMENTS: 'groom_appointments',
  INVOICES: 'groom_invoices',
  CONFIG: 'groom_config',
  AUDIT: 'groom_audit_log'
};

export interface ImportResult {
  success: boolean;
  message: string;
  logs: string[];
}

export const db = {
  logAction: (action: string, details: string) => {
    try {
      const auditStr = localStorage.getItem(KEYS.AUDIT);
      const audit = auditStr ? JSON.parse(auditStr) : [];
      audit.unshift({
        id: Math.random().toString(36).substr(2, 9),
        timestamp: new Date().toISOString(),
        action,
        details
      });
      localStorage.setItem(KEYS.AUDIT, JSON.stringify(audit.slice(0, 30)));
    } catch (e) {}
  },

  getAuditLog: (): any[] => {
    try {
      const auditStr = localStorage.getItem(KEYS.AUDIT);
      return auditStr ? JSON.parse(auditStr) : [];
    } catch { return []; }
  },

  getConfig: (): Configuration & { logo?: string } => {
    try {
      const data = localStorage.getItem(KEYS.CONFIG);
      return data ? JSON.parse(data) : INITIAL_CONFIG;
    } catch { return INITIAL_CONFIG; }
  },

  saveConfig: (config: any) => {
    localStorage.setItem(KEYS.CONFIG, JSON.stringify(config));
  },

  updateConfigItems: (key: keyof Configuration, items: string[]) => {
    const config = db.getConfig();
    (config as any)[key] = items;
    db.saveConfig(config);
  },

  getClients: (): Client[] => {
    try {
      const data = localStorage.getItem(KEYS.CLIENTS);
      const parsed = data ? JSON.parse(data) : [];
      return Array.isArray(parsed) ? parsed : [];
    } catch { return []; }
  },

  saveClient: (client: Client) => {
    const clients = db.getClients();
    const index = clients.findIndex(c => c.id === client.id);
    if (index >= 0) clients[index] = client;
    else clients.push(client);
    localStorage.setItem(KEYS.CLIENTS, JSON.stringify(clients));
  },

  deleteClient: (id: string) => {
    const clients = db.getClients().filter(c => c.id !== id);
    const appts = db.getAppointments().filter(a => a.clientId !== id);
    const invoices = db.getInvoices().filter(i => i.clientId !== id);

    localStorage.setItem(KEYS.CLIENTS, JSON.stringify(clients));
    localStorage.setItem(KEYS.APPOINTMENTS, JSON.stringify(appts));
    localStorage.setItem(KEYS.INVOICES, JSON.stringify(invoices));

    db.logAction("Suppression Client", `ID: ${id}`);
    return true;
  },

  getAppointments: (): Appointment[] => {
    try {
      const data = localStorage.getItem(KEYS.APPOINTMENTS);
      const parsed = data ? JSON.parse(data) : [];
      return Array.isArray(parsed) ? parsed : [];
    } catch { return []; }
  },

  saveAppointment: (appt: Appointment) => {
    const appts = db.getAppointments();
    const index = appts.findIndex(a => a.id === appt.id);
    if (index >= 0) appts[index] = appt;
    else appts.push(appt);
    localStorage.setItem(KEYS.APPOINTMENTS, JSON.stringify(appts));
  },

  deleteAppointment: (id: string) => {
    const appts = db.getAppointments().filter(a => a.id !== id);
    localStorage.setItem(KEYS.APPOINTMENTS, JSON.stringify(appts));
  },

  getInvoices: (): Invoice[] => {
    try {
      const data = localStorage.getItem(KEYS.INVOICES);
      return data ? JSON.parse(data) : [];
    } catch { return []; }
  },

  saveInvoice: (invoice: Invoice) => {
    const invoices = db.getInvoices();
    invoices.push(invoice);
    localStorage.setItem(KEYS.INVOICES, JSON.stringify(invoices));
  },

  deleteInvoice: (id: string) => {
    const invoices = db.getInvoices().filter(i => i.id !== id);
    localStorage.setItem(KEYS.INVOICES, JSON.stringify(invoices));
    db.logAction("Suppression Facture", `ID: ${id}`);
  },

  exportAsJSON: () => {
    const data = {
      clients: db.getClients(),
      appointments: db.getAppointments(),
      invoices: db.getInvoices(),
      config: db.getConfig()
    };
    return JSON.stringify(data);
  },

  exportClientsCSV: () => {
    const clients = db.getClients();
    const headers = ["ID", "Nom Animal", "Espece", "Race", "Poil", "Proprietaire", "Tel", "Email", "Adresse", "Notes"];
    const rows = clients.map(c => [
      c.id,
      c.name,
      c.species,
      c.breed,
      c.coatType,
      c.ownerName,
      `'${c.phone}`, // Prefix pour garder le 0 dans Excel
      c.email,
      (c.address || "").replace(/;/g, ",").replace(/[\n\r]/g, " "),
      (c.notes || "").replace(/;/g, ",").replace(/[\n\r]/g, " ")
    ]);
    return [headers, ...rows].map(r => r.join(";")).join("\n");
  },

  exportInvoicesCSV: () => {
    const invoices = db.getInvoices();
    const headers = ["Numero", "Date", "Animal", "Proprietaire", "Montant", "Paiement", "Details"];
    const rows = invoices.map(inv => [
      inv.number,
      inv.date,
      inv.petName,
      inv.ownerName,
      inv.amount.toString().replace(".", ","), // Virgule pour Excel FR
      inv.paymentMethod,
      (inv.notes || "").replace(/;/g, ",").replace(/[\n\r]/g, " ")
    ]);
    return [headers, ...rows].map(r => r.join(";")).join("\n");
  },

  importFullData: (jsonString: string): ImportResult => {
    const logs: string[] = [];
    try {
      const data = JSON.parse(jsonString);
      localStorage.setItem(KEYS.CLIENTS, JSON.stringify(data.clients || []));
      localStorage.setItem(KEYS.APPOINTMENTS, JSON.stringify(data.appointments || []));
      localStorage.setItem(KEYS.INVOICES, JSON.stringify(data.invoices || []));
      localStorage.setItem(KEYS.CONFIG, JSON.stringify(data.config || INITIAL_CONFIG));
      return { success: true, message: "Import réussi", logs: ["Données restaurées"] };
    } catch (e: any) {
      return { success: false, message: e.message, logs: ["Erreur de lecture"] };
    }
  },

  resetAll: () => {
    if (window.confirm("Tout effacer ?")) {
      localStorage.clear();
      window.location.reload();
    }
  }
};

import React, { useState, useEffect } from 'react';
