  const [config, setConfig] = useState(db.getConfig());
  const [isImporting, setIsImporting] = useState(false);
  const [status, setStatus] = useState<'idle' | 'preparing' | 'success'>('idle');

  const fileInputRef = useRef<HTMLInputElement>(null);
  const logoInputRef = useRef<HTMLInputElement>(null);

  const handlePrint = (invoice: Invoice) => {
    const clients = db.getClients();
    const client = clients.find(c => c.id === invoice.clientId);
    const printWindow = window.open('', '_blank', 'width=900,height=1200');
    if (!printWindow) return;
    printWindow.document.write(`<html><head><script src="https://cdn.tailwindcss.com"></script></head><body><div id="root"></div></body></html>`);
    setTimeout(() => {
      const container = printWindow.document.getElementById('root');
      if (container) {
        const root = createRoot(container);
        root.render(<InvoicePDF invoice={invoice} client={client} />);
        setTimeout(() => printWindow.print(), 1000);
      }
    }, 200);
  };

  const safeDownload = (blob: Blob, filename: string) => {
    const url = window.URL.createObjectURL(blob);
    const link = document.createElement('a');
    link.href = url;
    link.download = filename;
    document.body.appendChild(link);
    link.click();

    // On laisse le lien actif 30 secondes pour éviter le message "déplacé ou supprimé"
    setTimeout(() => {
      if (document.body.contains(link)) document.body.removeChild(link);
      window.URL.revokeObjectURL(url);
    }, 30000);

    setStatus('success');
    setTimeout(() => setStatus('idle'), 3000);
  };

  const handleExportCSV = (type: 'clients' | 'invoices') => {
    setStatus('preparing');
    const content = type === 'clients' ? db.exportClientsCSV() : db.exportInvoicesCSV();
    const blob = new Blob(["\ufeff" + content], { type: 'text/csv;charset=utf-8;' });
    safeDownload(blob, `kanine_${type}_${new Date().toISOString().split('T')[0]}.csv`);
  };

  const handleExportJSON = () => {
    setStatus('preparing');
    try {
      const json = db.exportAsJSON();
      const blob = new Blob([json], { type: 'application/json' });
      safeDownload(blob, `kanine_backup_full_${new Date().toISOString().split('T')[0]}.json`);
    } catch (e) {
      alert("Erreur mémoire : Trop de photos. Utilisez l'export CSV pour vos données texte.");
      setStatus('idle');
    }
  };

  const handleFileImport = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;
    setIsImporting(true);
    const reader = new FileReader();
    reader.onload = (event) => {
      const result = db.importFullData(event.target?.result as string);
      if (result.success) {
        alert("Restauration réussie !");
        window.location.reload();
      } else {
        alert("Erreur lors de l'import.");
        setIsImporting(false);
      }
    };
    reader.readAsText(file);
  };

  const handleLogoUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;
    const reader = new FileReader();
    reader.onloadend = () => {
      const newConfig = { ...config, logo: reader.result as string };
      db.saveConfig(newConfig);
      setConfig(newConfig);
    };
    reader.readAsDataURL(file);
  };

  return (
    <Layout activeTab={activeTab} setActiveTab={(t) => { setSelectedClientId(null); setActiveTab(t); }}>
      {activeTab === 'dashboard' && <Dashboard onNavigateToClient={(id) => { setSelectedClientId(id); setActiveTab('clients'); }} />}
      {activeTab === 'clients' && <ClientList initialClientId={selectedClientId} />}
      {activeTab === 'planning' && <Planning onPrintInvoice={handlePrint} />}
      {activeTab === 'invoices' && (
        <div className="max-w-4xl mx-auto space-y-4">
          <h2 className="text-2xl font-black text-slate-800 uppercase italic">Factures</h2>
          {db.getInvoices().slice().reverse().map(inv => (
            <div key={inv.id} className="bg-white p-6 rounded-3xl border border-slate-100 flex items-center justify-between shadow-sm">
              <div>
                <p className="font-black text-slate-900">{inv.number} - {inv.petName}</p>
                <p className="text-xs text-slate-400">Le {inv.date} • {inv.amount}€ ({inv.paymentMethod})</p>
              </div>
              <div className="flex gap-2">
                <button onClick={() => handlePrint(inv)} className="p-4 bg-indigo-600 text-white rounded-2xl"><Printer size={20}/></button>
                <button onClick={() => { if(confirm("Supprimer ?")) { db.deleteInvoice(inv.id); window.location.reload(); } }} className="p-4 text-red-400 hover:bg-red-50 rounded-2xl"><Trash2 size={20}/></button>
              </div>
            </div>
          ))}
        </div>
      )}
      {activeTab === 'config' && (
        <div className="max-w-2xl mx-auto bg-white p-10 rounded-[3rem] border border-slate-100 shadow-sm space-y-10">
           <div className="flex items-center gap-6">
              <div className="w-32 h-32 bg-slate-50 rounded-3xl border-2 border-dashed border-slate-200 flex items-center justify-center overflow-hidden relative group">
                {config.logo ? <img src={config.logo} className="w-full h-full object-contain" /> : <ImageIcon size={32} className="text-slate-300"/>}
                <label className="absolute inset-0 bg-black/40 opacity-0 group-hover:opacity-100 flex items-center justify-center cursor-pointer transition-opacity">
                   <Camera className="text-white"/>
                   <input type="file" onChange={handleLogoUpload} className="hidden" accept="image/*" />
                </label>
              </div>
              <div>
                <h3 className="text-xl font-black uppercase italic">Logo Entreprise</h3>
                <p className="text-sm text-slate-400">Apparaît sur vos PDF</p>
