              <p className="text-slate-500 text-sm mb-8">Fichier texte ultra-léger compatible Excel. **Garanti sans erreur.**</p>
              <div className="grid grid-cols-1 gap-4">
                <button onClick={() => handleExportCSV('clients')} className="py-4 bg-emerald-600 text-white rounded-2xl font-black uppercase tracking-widest hover:bg-emerald-700 transition-all">Exporter Clients</button>
                <button onClick={() => handleExportCSV('invoices')} className="py-4 bg-emerald-700 text-white rounded-2xl font-black uppercase tracking-widest hover:bg-emerald-800 transition-all">Exporter Factures</button>
              </div>
            </div>

            <div className="bg-white p-10 rounded-[3rem] border border-slate-100 shadow-sm">
              <div className="flex items-center gap-4 mb-8">
                <div className="p-4 bg-indigo-50 text-indigo-600 rounded-2xl"><FileJson size={24} /></div>
                <h3 className="text-xl font-black uppercase italic">Sauvegarde Totale</h3>
              </div>
              <p className="text-slate-500 text-sm mb-8">Contient TOUT (photos incluses). Peut saturer si trop d'images.</p>
              <div className="space-y-4">
                <button onClick={handleExportJSON} disabled={status !== 'idle'} className={`w-full py-4 rounded-2xl font-black uppercase transition-all ${status === 'preparing' ? 'bg-slate-200 text-slate-400' : 'bg-indigo-600 text-white hover:bg-indigo-700'}`}>
