import { Client, Appointment, Invoice, Configuration } from '../types';
import { INITIAL_CONFIG } from '../constants';
import JSZip from 'jszip';

const KEYS = {
  CLIENTS: 'groom_clients',
  APPOINTMENTS: 'groom_appointments',
  INVOICES: 'groom_invoices',
  CONFIG: 'groom_config',
  AUDIT: 'groom_audit_log'
};

/**
 * Transforme des données en CSV de manière sécurisée pour Excel
 * Remplace les ; par des , dans les textes pour éviter de casser les colonnes
 */
const toCSV = (data: any[], headers: string[], keys: string[]) => {
  const sanitize = (val: any) => {
    if (val === null || val === undefined) return "";
    // On transforme en string, on retire les sauts de ligne et on remplace les ; par des ,
    return String(val)
      .replace(/;/g, ",")
      .replace(/[\n\r]/g, " ")
      .trim();
  };

  const headerRow = headers.join(';');
  const rows = data.map(obj => keys.map(k => sanitize(obj[k])).join(';'));
  return [headerRow, ...rows].join('\n');
};

/**
 * Parse un CSV simple (séparateur ;)
 */
const fromCSV = (csv: string) => {
  const lines = csv.split('\n').map(l => l.trim()).filter(l => l !== '');
  if (lines.length < 2) return [];

  const headers = lines[0].split(';');
  return lines.slice(1).map(line => {
    const values = line.split(';');
    const obj: any = {};
    headers.forEach((h, i) => {
      obj[h] = values[i] || "";
    });
    return obj;
  });
};

export const db = {
  // --- GESTION DES DONNÉES DE BASE ---

  getConfig: (): Configuration & { logo?: string } => {
    try {
      const data = localStorage.getItem(KEYS.CONFIG);
      return data ? JSON.parse(data) : INITIAL_CONFIG;
    } catch { return INITIAL_CONFIG; }
  },

  saveConfig: (config: any) => {
    localStorage.setItem(KEYS.CONFIG, JSON.stringify(config));
  },

  getClients: (): Client[] => {
    try {
      const data = localStorage.getItem(KEYS.CLIENTS);
      return Array.isArray(JSON.parse(data || '[]')) ? JSON.parse(data || '[]') : [];
    } catch { return []; }
  },

  getAppointments: (): Appointment[] => {
    try {
      const data = localStorage.getItem(KEYS.APPOINTMENTS);
      return Array.isArray(JSON.parse(data || '[]')) ? JSON.parse(data || '[]') : [];
    } catch { return []; }
  },

  getInvoices: (): Invoice[] => {
    try {
      const data = localStorage.getItem(KEYS.INVOICES);
      return Array.isArray(JSON.parse(data || '[]')) ? JSON.parse(data || '[]') : [];
    } catch { return []; }
  },

  saveClient: (client: Client) => {
    const clients = db.getClients();
    const index = clients.findIndex(c => c.id === client.id);
    if (index >= 0) clients[index] = client;
    else clients.push(client);
    localStorage.setItem(KEYS.CLIENTS, JSON.stringify(clients));
  },

  saveAppointment: (appt: Appointment) => {
    const appts = db.getAppointments();
    const index = appts.findIndex(a => a.id === appt.id);
    if (index >= 0) appts[index] = appt;
    else appts.push(appt);
    localStorage.setItem(KEYS.APPOINTMENTS, JSON.stringify(appts));
  },

  saveInvoice: (invoice: Invoice) => {
    const invoices = db.getInvoices();
    invoices.push(invoice);
    localStorage.setItem(KEYS.INVOICES, JSON.stringify(invoices));
  },

  deleteAppointment: (id: string) => {
    const appts = db.getAppointments().filter(a => a.id !== id);
    localStorage.setItem(KEYS.APPOINTMENTS, JSON.stringify(appts));
  },

  deleteInvoice: (id: string) => {
    const invoices = db.getInvoices().filter(i => i.id !== id);
    localStorage.setItem(KEYS.INVOICES, JSON.stringify(invoices));
  },

  deleteClient: (id: string) => {
    const clients = db.getClients().filter(c => c.id !== id);
    const appts = db.getAppointments().filter(a => a.clientId !== id);
    const invoices = db.getInvoices().filter(i => i.clientId !== id);
    localStorage.setItem(KEYS.CLIENTS, JSON.stringify(clients));
    localStorage.setItem(KEYS.APPOINTMENTS, JSON.stringify(appts));
    localStorage.setItem(KEYS.INVOICES, JSON.stringify(invoices));
    return true;
  },

  // --- SYSTÈME DE SAUVEGARDE TEXTE UNIQUEMENT (ZIP/CSV) ---

  exportDataOnlyZIP: async () => {
    const zip = new JSZip();

    // 1. Clients (On ignore photoProfile)
    const clients = db.getClients().map(({ photoProfile, ...rest }) => rest);
    const clientHeaders = ["id", "name", "species", "breed", "coatType", "birthDate", "ownerName", "phone", "email", "address", "notes", "createdAt"];
    zip.file("clients.csv", "\ufeff" + toCSV(clients, clientHeaders, clientHeaders));

    // 2. Rendez-vous (On ignore photoBefore/After)
    const appts = db.getAppointments().map(({ photoBefore, photoAfter, ...rest }) => rest);
    const apptHeaders = ["id", "date", "time", "clientId", "clientName", "petName", "service", "notes", "duration", "status"];
    zip.file("rendez_vous.csv", "\ufeff" + toCSV(appts, apptHeaders, apptHeaders));

    // 3. Factures
    const invoices = db.getInvoices();
    const invHeaders = ["id", "number", "date", "clientId", "petName", "ownerName", "amount", "paymentMethod", "appointmentId", "notes"];
    zip.file("factures.csv", "\ufeff" + toCSV(invoices, invHeaders, invHeaders));

    // 4. Config
    zip.file("config.json", JSON.stringify(db.getConfig()));

    return await zip.generateAsync({ type: "blob" });
  },

  importDataOnlyZIP: async (file: File) => {
    try {
      const zip = await JSZip.loadAsync(file);

      const clientCSV = await zip.file("clients.csv")?.async("string");
      const apptCSV = await zip.file("rendez_vous.csv")?.async("string");
      const invCSV = await zip.file("factures.csv")?.async("string");
      const configJSON = await zip.file("config.json")?.async("string");

      if (!clientCSV) throw new Error("Le fichier ZIP ne semble pas être une sauvegarde Ka'nine valide (clients.csv manquant).");

      const clients = fromCSV(clientCSV.replace(/^\ufeff/, ''));
      const appointments = apptCSV ? fromCSV(apptCSV.replace(/^\ufeff/, '')) : [];
      const invoices = invCSV ? fromCSV(invCSV.replace(/^\ufeff/, '')) : [];
      const config = configJSON ? JSON.parse(configJSON) : INITIAL_CONFIG;

      // Nettoyage avant import pour éviter les mélanges
      Object.values(KEYS).forEach(key => localStorage.removeItem(key));

      // Conversion des types
      invoices.forEach(inv => inv.amount = parseFloat(inv.amount) || 0);
      appointments.forEach(a => a.duration = parseInt(a.duration) || 60);

      // Sauvegarde
      localStorage.setItem(KEYS.CLIENTS, JSON.stringify(clients));
      localStorage.setItem(KEYS.APPOINTMENTS, JSON.stringify(appointments));
      localStorage.setItem(KEYS.INVOICES, JSON.stringify(invoices));
      localStorage.setItem(KEYS.CONFIG, JSON.stringify(config));

      return true;
    } catch (e: any) {
      alert("Erreur d'importation : " + e.message);
      return false;
    }
  },

  resetAll: () => {
    // Suppression ciblée pour être sûr de ne rien laisser
    localStorage.removeItem(KEYS.CLIENTS);
    localStorage.removeItem(KEYS.APPOINTMENTS);
    localStorage.removeItem(KEYS.INVOICES);
    localStorage.removeItem(KEYS.CONFIG);
    localStorage.removeItem(KEYS.AUDIT);

    // Optionnel : tout vider si vraiment nécessaire
    // localStorage.clear(); 

    window.location.reload();
  }
};

