import { Client, Appointment, Invoice, Configuration } from '../types';
import { INITIAL_CONFIG } from '../constants';
import JSZip from 'jszip';

const KEYS = {
  CLIENTS: 'groom_clients',
  APPOINTMENTS: 'groom_appointments',
  INVOICES: 'groom_invoices',
  CONFIG: 'groom_config',
  AUDIT: 'groom_audit_log'
};

/**
 * Transforme des données en CSV de manière sécurisée
 */
const toCSV = (data: any[], headers: string[], keys: string[]) => {
  const sanitize = (val: any) => {
    if (val === null || val === undefined) return "";
    let str = String(val).replace(/;/g, ",").replace(/[\n\r]/g, " ").trim();
    return str;
  };

  const headerRow = headers.join(';');
  const rows = data.map(obj => keys.map(k => sanitize(obj[k])).join(';'));
  return [headerRow, ...rows].join('\n');
};

/**
 * Parse un CSV avec gestion d'erreurs
 */
const fromCSV = (csv: string) => {
  const lines = csv.split(/\r?\n/).map(l => l.trim()).filter(l => l !== '');
  if (lines.length < 2) return [];

  const headers = lines[0].split(';').map(h => h.trim());
  return lines.slice(1).map((line, index) => {
    const values = line.split(';');
    const obj: any = {};
    headers.forEach((h, i) => {
      obj[h] = values[i] !== undefined ? values[i].trim() : "";
    });
    return obj;
  });
};

export const db = {
  getConfig: (): Configuration & { logo?: string } => {
    try {
      const data = localStorage.getItem(KEYS.CONFIG);
      return data ? JSON.parse(data) : INITIAL_CONFIG;
    } catch { return INITIAL_CONFIG; }
  },

  saveConfig: (config: any) => {
    localStorage.setItem(KEYS.CONFIG, JSON.stringify(config));
  },

  getClients: (): Client[] => {
    try {
      const data = localStorage.getItem(KEYS.CLIENTS);
      const parsed = JSON.parse(data || '[]');
      return Array.isArray(parsed) ? parsed : [];
    } catch { return []; }
  },

  getAppointments: (): Appointment[] => {
