  const fileInputRef = useRef<HTMLInputElement>(null);

  const handlePrint = (invoice: Invoice) => {
    const clients = db.getClients();
    const client = clients.find(c => c.id === invoice.clientId);
    const printWindow = window.open('', '_blank', 'width=900,height=1200');
    if (!printWindow) return;
    printWindow.document.write(`<html><head><script src="https://cdn.tailwindcss.com"></script></head><body><div id="root"></div></body></html>`);
    setTimeout(() => {
      const container = printWindow.document.getElementById('root');
      if (container) {
        const root = createRoot(container);
        root.render(<InvoicePDF invoice={invoice} client={client} />);
        setTimeout(() => printWindow.print(), 1000);
      }
    }, 200);
  };

  const handleExportZIP = async () => {
    setIsProcessing(true);
    try {
      const blob = await db.exportDataOnlyZIP();
      const url = window.URL.createObjectURL(blob);
      const link = document.createElement('a');
      link.href = url;
      link.download = `sauvegarde_kanine_${new Date().toISOString().split('T')[0]}.zip`;
      document.body.appendChild(link);
      link.click();
      setTimeout(() => {
        if (document.body.contains(link)) document.body.removeChild(link);
        window.URL.revokeObjectURL(url);
      }, 15000);
    } catch (e) {
      alert("Erreur lors de l'export.");
    } finally {
      setIsProcessing(false);
    }
  };

  const handleImportZIP = async (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;

    if (!confirm("⚠️ ÉCRASEMENT DES DONNÉES\n\nSouhaitez-vous vraiment remplacer TOUTES vos données actuelles par celles contenues dans ce ZIP ?\n\nCette action est irréversible.")) {
      e.target.value = '';
      return;
    }

    setIsProcessing(true);
    try {
      const success = await db.importDataOnlyZIP(file);
      if (success) {
        alert("✅ Données restaurées avec succès !");
        window.location.reload();
      }
    } catch (err) {
      console.error(err);
      alert("Erreur fatale lors du traitement du fichier.");
    } finally {
      setIsProcessing(false);
      if (fileInputRef.current) fileInputRef.current.value = '';
