      const newConfig = { ...config, logo: reader.result as string };
      db.saveConfig(newConfig);
      setConfig(newConfig);
    };
    reader.readAsDataURL(file);
  };

  return (
    <Layout activeTab={activeTab} setActiveTab={(t) => { setSelectedClientId(null); setActiveTab(t); }}>
