              </div>
              <div className="flex gap-2">
                <button onClick={() => handlePrint(inv)} className="p-4 bg-indigo-600 text-white rounded-2xl"><Printer size={20}/></button>
                <button onClick={() => { if(confirm("Supprimer ?")) { db.deleteInvoice(inv.id); window.location.reload(); } }} className="p-4 text-red-400 hover:bg-red-50 rounded-2xl"><Trash2 size={20}/></button>
              </div>
            </div>
          ))}
        </div>
      )}
      {activeTab === 'config' && (
        <div className="max-w-2xl mx-auto bg-white p-10 rounded-[3rem] border border-slate-100 shadow-sm space-y-10">
           <div className="flex items-center gap-6">
              <div className="w-32 h-32 bg-slate-50 rounded-3xl border-2 border-dashed border-slate-200 flex items-center justify-center overflow-hidden relative group">
