    const appts = db.getAppointments().filter(a => a.clientId !== id);
    const invoices = db.getInvoices().filter(i => i.clientId !== id);
    localStorage.setItem(KEYS.CLIENTS, JSON.stringify(clients));
    localStorage.setItem(KEYS.APPOINTMENTS, JSON.stringify(appts));
    localStorage.setItem(KEYS.INVOICES, JSON.stringify(invoices));
    return true;
  },

  // --- SYSTÈME DE SAUVEGARDE IMAGE (JSON) ---
  // C'est l'approche la plus fiable car elle préserve les types et caractères spéciaux.

  exportFullBackup: () => {
    const backupData = {
      version: "2.0",
      timestamp: new Date().toISOString(),
      // On retire les photos pour que le fichier reste léger et fiable
      clients: db.getClients().map(({ photoProfile, ...rest }) => rest),
      appointments: db.getAppointments().map(({ photoBefore, photoAfter, ...rest }) => rest),
      invoices: db.getInvoices(),
      config: db.getConfig()
    };

    const blob = new Blob([JSON.stringify(backupData, null, 2)], { type: 'application/json' });
    const url = URL.createObjectURL(blob);
    const link = document.createElement('a');
    link.href = url;
    link.download = `backup_kanine_${new Date().toISOString().split('T')[0]}.kanine`;
    document.body.appendChild(link);
    link.click();
    document.body.removeChild(link);
    URL.revokeObjectURL(url);
  },

  importFullBackup: (file: File): Promise<boolean> => {
    return new Promise((resolve, reject) => {
      const reader = new FileReader();

      reader.onload = (e) => {
        try {
          const content = e.target?.result as string;
          const data = JSON.parse(content);

          // Validation minimale du format
          if (!data.clients || !Array.isArray(data.clients)) {
            throw new Error("Format de fichier invalide : données clients manquantes.");
          }

          // Nettoyage complet
          localStorage.clear();

          // Restauration
          localStorage.setItem(KEYS.CLIENTS, JSON.stringify(data.clients));
          localStorage.setItem(KEYS.APPOINTMENTS, JSON.stringify(data.appointments || []));
          localStorage.setItem(KEYS.INVOICES, JSON.stringify(data.invoices || []));
          localStorage.setItem(KEYS.CONFIG, JSON.stringify(data.config || INITIAL_CONFIG));

          resolve(true);
        } catch (err: any) {
          reject(err.message);
        }
      };

      reader.onerror = () => reject("Erreur lors de la lecture du fichier.");
      reader.readAsText(file);
    });
  },

  resetAll: () => {
    localStorage.clear();
    // Redirection vers l'origine pour forcer un nettoyage complet du state React
    window.location.href = window.location.origin;
  }
};

