  AlertCircle, CheckCircle2
} from 'lucide-react';
import { Invoice } from './types';
import { createRoot } from 'react-dom/client';

const App: React.FC = () => {
  const [activeTab, setActiveTab] = useState('dashboard');
  const [selectedClientId, setSelectedClientId] = useState<string | null>(null);
  const [config, setConfig] = useState(db.getConfig());
  const [isProcessing, setIsProcessing] = useState(false);
  const [status, setStatus] = useState<{ type: 'success' | 'error', msg: string } | null>(null);

  const fileInputRef = useRef<HTMLInputElement>(null);

  const handlePrint = (invoice: Invoice) => {
    const clients = db.getClients();
    const client = clients.find(c => c.id === invoice.clientId);
    const printWindow = window.open('', '_blank', 'width=900,height=1200');
    if (!printWindow) return;
    printWindow.document.write(`<html><head><script src="https://cdn.tailwindcss.com"></script></head><body><div id="root"></div></body></html>`);
    setTimeout(() => {
      const container = printWindow.document.getElementById('root');
      if (container) {
        const root = createRoot(container);
        root.render(<InvoicePDF invoice={invoice} client={client} />);
        setTimeout(() => printWindow.print(), 1000);
      }
    }, 200);
  };

  const handleBackupExport = () => {
    setIsProcessing(true);
    try {
      db.exportFullBackup();
      setStatus({ type: 'success', msg: 'Sauvegarde créée avec succès.' });
    } catch (e) {
      setStatus({ type: 'error', msg: 'Échec de la sauvegarde.' });
    } finally {
      setIsProcessing(false);
      setTimeout(() => setStatus(null), 3000);
    }
  };

  const handleBackupImport = async (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;

    if (!confirm("⚠️ ATTENTION : RESTAURATION SYSTÈME\n\nToutes vos données actuelles seront remplacées par celles du fichier sélectionné.\n\nContinuer ?")) {
      e.target.value = '';
      return;
    }

    setIsProcessing(true);
    try {
      const success = await db.importFullBackup(file);
      if (success) {
        alert("✅ Restauration terminée. L'application va redémarrer.");
        window.location.reload();
      }
    } catch (err: any) {
      alert("❌ ERREUR : " + err);
    } finally {
      setIsProcessing(false);
      if (fileInputRef.current) fileInputRef.current.value = '';
    }
  };

  const handleReset = () => {
    if (confirm("🚨 ZONE DE DANGER\n\nCela va supprimer TOUTES les données de l'application (Clients, RDV, Factures, Logo).\n\nÊtes-vous absolument sûr ?")) {
      db.resetAll();
    }
