    const file = e.target.files?.[0];
    if (!file) return;
    const reader = new FileReader();
    reader.onloadend = () => {
      const newConfig = { ...config, logo: reader.result as string };
      db.saveConfig(newConfig);
      setConfig(newConfig);
    };
    reader.readAsDataURL(file);
  };

  return (
