                  <Download size={32} />
                  <span className="font-black uppercase tracking-widest text-xs">Sauvegarder l'image (.kanine)</span>
                </button>
                <p className="text-[10px] text-center text-slate-400 font-bold uppercase tracking-widest px-4">Crée un fichier contenant vos clients, rdv et factures.</p>
              </div>

              <div className="space-y-4">
                <button 
                  onClick={() => fileInputRef.current?.click()}
                  className="w-full p-8 bg-white text-indigo-600 border-4 border-dashed border-indigo-100 rounded-[2.5rem] flex flex-col items-center gap-4 hover:bg-indigo-50 transition-all active:scale-95"
                >
                  <Upload size={32} />
                  <span className="font-black uppercase tracking-widest text-xs">Restaurer un fichier</span>
                </button>
                <p className="text-[10px] text-center text-slate-400 font-bold uppercase tracking-widest px-4">Sélectionnez un fichier .kanine pour restaurer vos données.</p>
              </div>
              <input type="file" ref={fileInputRef} onChange={handleBackupImport} accept=".kanine,.json" className="hidden" />
            </div>
          </div>

          <div className="bg-red-50 p-10 rounded-[3rem] border border-red-100 flex flex-col md:flex-row items-center justify-between gap-8 transition-all hover:bg-red-100/50">
             <div className="flex items-center gap-6 text-left">
