import React, { useState, useRef } from 'react';
import Layout from './components/Layout';
import Dashboard from './views/Dashboard';
import ClientList from './views/ClientList';
import Planning from './views/Planning';
import InvoicePDF from './components/InvoicePDF';
import { db } from './services/database';
import { 
  Trash2, Printer, Copy, Check, ShieldCheck, 
  RefreshCcw, FileText, AlertTriangle, 
  Terminal, Globe, ArrowRightLeft, Camera, ImageIcon
} from 'lucide-react';
import { Invoice } from './types';
import { createRoot } from 'react-dom/client';

const App: React.FC = () => {
  const [activeTab, setActiveTab] = useState('dashboard');
  const [selectedClientId, setSelectedClientId] = useState<string | null>(null);
  const [config, setConfig] = useState(db.getConfig());

  // Added ref to fix TypeScript error: Property 'click' does not exist on type 'Element'
  const logoInputRef = useRef<HTMLInputElement>(null);

  // States pour la synchronisation
  const [syncCode, setSyncCode] = useState('');
  const [importCode, setImportCode] = useState('');
  const [copyStatus, setCopyStatus] = useState(false);
  const [importStatus, setImportStatus] = useState<{type: 'none'|'success'|'error', msg: string}>({type: 'none', msg: ''});

  const handlePrint = (invoice: Invoice) => {
    const clients = db.getClients();
    const client = clients.find(c => c.id === invoice.clientId);
    const printWindow = window.open('', '_blank', 'width=900,height=1200');
    if (!printWindow) return;
    printWindow.document.write(`<html><head><script src="https://cdn.tailwindcss.com"></script></head><body><div id="root"></div></body></html>`);
    setTimeout(() => {
      const container = printWindow.document.getElementById('root');
      if (container) {
        const root = createRoot(container);
        root.render(<InvoicePDF invoice={invoice} client={client} />);
        setTimeout(() => printWindow.print(), 1000);
      }
    }, 200);
  };

  const handleGeneratePassport = () => {
    const code = db.generateSyncPassport();
    setSyncCode(code);
  };

  const handleCopyCode = () => {
    if (!syncCode) return;
    navigator.clipboard.writeText(syncCode);
    setCopyStatus(true);
    setTimeout(() => setCopyStatus(false), 2000);
  };

  const handleRunImport = () => {
    if (!importCode.trim()) return;
    const result = db.validateAndImportPassport(importCode.trim());
    if (result.success) {
      setImportStatus({ type: 'success', msg: result.message });
      setTimeout(() => window.location.reload(), 1500);
    } else {
      setImportStatus({ type: 'error', msg: result.message });
    }
  };

  const handleLogoUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;
    const reader = new FileReader();
    reader.onloadend = () => {
      const newConfig = { ...config, logo: reader.result as string };
      db.saveConfig(newConfig);
      setConfig(newConfig);
    };
    reader.readAsDataURL(file);
  };

  return (
    <Layout activeTab={activeTab} setActiveTab={(t) => { setSelectedClientId(null); setActiveTab(t); }}>
      {activeTab === 'dashboard' && <Dashboard onNavigateToClient={(id) => { setSelectedClientId(id); setActiveTab('clients'); }} />}
      {activeTab === 'clients' && <ClientList initialClientId={selectedClientId} />}
      {activeTab === 'planning' && <Planning onPrintInvoice={handlePrint} />}

      {activeTab === 'invoices' && (
        <div className="max-w-4xl mx-auto space-y-4">
          <h2 className="text-2xl font-black text-slate-800 uppercase italic">Factures Archivées</h2>
          {db.getInvoices().slice().reverse().map(inv => (
            <div key={inv.id} className="bg-white p-6 rounded-3xl border border-slate-100 flex items-center justify-between shadow-sm">
              <div>
                <p className="font-black text-slate-900">{inv.number} - {inv.petName}</p>
                <p className="text-xs text-slate-400 font-bold uppercase">Le {inv.date} • {inv.amount}€ ({inv.paymentMethod})</p>
              </div>
              <div className="flex gap-2">
                <button onClick={() => handlePrint(inv)} className="p-4 bg-indigo-600 text-white rounded-2xl"><Printer size={20}/></button>
                <button onClick={() => { if(confirm("Supprimer ?")) { db.deleteInvoice(inv.id); window.location.reload(); } }} className="p-4 text-red-400 hover:bg-red-50 rounded-2xl"><Trash2 size={20}/></button>
              </div>
            </div>
          ))}
        </div>
      )}

      {activeTab === 'config' && (
        <div className="max-w-2xl mx-auto space-y-8">
           <div className="bg-white p-10 rounded-[3rem] border border-slate-100 shadow-sm flex items-center gap-10">
              <div className="w-40 h-40 bg-slate-50 rounded-3xl border-2 border-dashed border-slate-200 flex items-center justify-center overflow-hidden relative group">
                {config.logo ? <img src={config.logo} className="w-full h-full object-contain" /> : <ImageIcon size={40} className="text-slate-300"/>}
                <label className="absolute inset-0 bg-black/40 opacity-0 group-hover:opacity-100 flex items-center justify-center cursor-pointer transition-opacity">
                   <Camera className="text-white"/>
                   <input ref={logoInputRef} type="file" onChange={handleLogoUpload} className="hidden" accept="image/*" />
                </label>
              </div>
              <div className="flex-1">
                <h3 className="text-xl font-black uppercase italic mb-2">Logo de l'entreprise</h3>
                <p className="text-sm text-slate-400 mb-4">Utilisé pour la génération de vos factures PDF.</p>
                {/* Fix: Use ref to call click() on HTMLInputElement, resolving TypeScript error */}
                <button onClick={() => logoInputRef.current?.click()} className="px-6 py-2 bg-indigo-600 text-white rounded-xl text-xs font-black uppercase tracking-widest">Modifier</button>
              </div>
           </div>
        </div>
      )}

      {activeTab === 'backup' && (
        <div className="max-w-5xl mx-auto space-y-12 pb-20">

          <div className="text-center space-y-3">
             <div className="inline-flex items-center gap-2 px-4 py-2 bg-indigo-50 text-indigo-600 rounded-full text-[10px] font-black uppercase tracking-widest border border-indigo-100">
                <Globe size={14}/> Cloud-Less Sync System
             </div>
             <h2 className="text-4xl font-black text-slate-900 uppercase italic tracking-tighter">Centre de Synchronisation</h2>
             <p className="text-slate-400 font-medium max-w-lg mx-auto italic">Transférez vos données entre vos appareils en un clin d'œil via votre <strong>Passport Ka'nine</strong>.</p>
          </div>

          <div className="grid grid-cols-1 lg:grid-cols-2 gap-10">

            {/* EXPORT SECTION */}
            <div className="bg-white p-10 rounded-[3.5rem] border border-slate-100 shadow-xl space-y-6 flex flex-col">
              <div className="flex items-center gap-4">
                 <div className="w-12 h-12 bg-indigo-50 text-indigo-600 rounded-2xl flex items-center justify-center">
                    <ShieldCheck size={24} />
                 </div>
                 <h3 className="text-xl font-black text-slate-800 uppercase tracking-tighter">Générer mon Passport</h3>
              </div>

              <div className="flex-1">
                <p className="text-sm text-slate-500 mb-6 font-medium leading-relaxed">Cliquez pour créer votre code de transfert unique. Il contient tous vos clients, rendez-vous et factures.</p>

                {syncCode ? (
                  <div className="space-y-4 animate-in fade-in slide-in-from-bottom-2">
                    <div className="p-6 bg-slate-900 rounded-3xl relative">
                       <p className="text-[10px] font-mono text-indigo-300 uppercase tracking-widest mb-3 flex items-center gap-2">
                          <Terminal size={12}/> Passport Ka'nine V3
                       </p>
                       <textarea 
                         readOnly 
                         className="w-full h-32 bg-transparent text-slate-100 font-mono text-[9px] break-all outline-none border-none resize-none no-scrollbar"
                         value={syncCode}
                       />
                    </div>
                    <button 
                      onClick={handleCopyCode}
                      className={`w-full py-5 rounded-2xl font-black uppercase text-xs tracking-widest flex items-center justify-center gap-3 transition-all ${copyStatus ? 'bg-emerald-500 text-white' : 'bg-slate-900 text-white hover:bg-slate-800'}`}
                    >
                      {copyStatus ? <Check size={18}/> : <Copy size={18}/>}
                      {copyStatus ? 'Code Copié !' : 'Copier mon Passport'}
                    </button>
                  </div>
                ) : (
                  <button 
                    onClick={handleGeneratePassport}
                    className="w-full p-10 border-4 border-dashed border-slate-100 rounded-[2.5rem] text-slate-300 hover:border-indigo-100 hover:text-indigo-400 transition-all font-black uppercase tracking-widest text-xs flex flex-col items-center gap-4"
                  >
                    <RefreshCcw size={32} />
                    Générer maintenant
                  </button>
                )}
              </div>
            </div>

            {/* IMPORT SECTION */}
            <div className="bg-white p-10 rounded-[3.5rem] border border-slate-100 shadow-xl space-y-6 flex flex-col">
              <div className="flex items-center gap-4">
                 <div className="w-12 h-12 bg-amber-50 text-amber-600 rounded-2xl flex items-center justify-center">
                    <ArrowRightLeft size={24} />
                 </div>
                 <h3 className="text-xl font-black text-slate-800 uppercase tracking-tighter">Appliquer un Passport</h3>
              </div>

              <div className="flex-1 space-y-6">
                <p className="text-sm text-slate-500 font-medium leading-relaxed">Collez ici le code Passport généré on un autre appareil pour restaurer vos données.</p>

                <div className={`p-6 rounded-3xl border-2 transition-all ${importStatus.type === 'error' ? 'bg-red-50 border-red-200' : 'bg-slate-50 border-slate-100 focus-within:border-indigo-200'}`}>
                   <textarea 
                     placeholder="Collez votre code ici..."
                     value={importCode}
                     onChange={(e) => { setImportCode(e.target.value); setImportStatus({type: 'none', msg: ''}); }}
                     className="w-full h-32 bg-transparent font-mono text-[9px] outline-none border-none resize-none placeholder:text-slate-300"
                   />
                </div>

                {importStatus.type !== 'none' && (
                  <div className={`p-4 rounded-2xl text-[10px] font-black uppercase tracking-widest flex items-center gap-3 ${importStatus.type === 'success' ? 'bg-emerald-50 text-emerald-600' : 'bg-red-50 text-red-600'}`}>
                    <AlertTriangle size={14} />
                    {importStatus.msg}
                  </div>
                )}

                <button 
                  onClick={handleRunImport}
                  disabled={!importCode}
                  className="w-full py-5 bg-indigo-600 text-white rounded-2xl font-black uppercase text-xs tracking-widest hover:bg-indigo-700 shadow-xl shadow-indigo-100 transition-all disabled:opacity-30 disabled:grayscale"
                >
                  Démarrer la Synchronisation
                </button>
              </div>
            </div>

          </div>

          <div className="bg-red-50 p-10 rounded-[3rem] border border-red-100 flex flex-col md:flex-row items-center justify-between gap-8">
             <div className="flex items-center gap-6">
                <div className="w-16 h-16 bg-white text-red-500 rounded-2xl flex items-center justify-center shrink-0 shadow-sm">
                  <RefreshCcw size={28} />
                </div>
                <div className="text-left">
                   <p className="font-black text-red-900 uppercase italic leading-none mb-1">Maintenance Usine</p>
                   <p className="text-xs text-red-400 font-bold uppercase tracking-widest">Vider toute la mémoire locale de cet appareil.</p>
                </div>
             </div>
             <button 
               onClick={() => db.resetAll()} 
               className="px-10 py-5 bg-red-600 text-white rounded-2xl font-black uppercase text-xs tracking-[0.2em] hover:bg-red-700 transition-all"
             >
                Effacer tout
             </button>
          </div>

        </div>
      )}
    </Layout>
  );
};

export default App;
